// NAME_TAG_SYSTEM_PATCH








function getModeOpponentName() {
  if (gameMode === "practice") return "Practice Dummy";
  if (gameMode === "cpu") return "CPU";
  if (gameMode === "online") {
    if (onlineRole === "p1") return sanitizePlayerName(onlinePlayerNames.p2, "Player 2");
    if (onlineRole === "p2") return sanitizePlayerName(onlinePlayerNames.p1, "Player 1");
  }
  return "Player 2";
}





function sanitizeAimPoint(aimPoint) {
  if (!aimPoint) return null;
  const x = Number(aimPoint.x);
  const y = Number(aimPoint.y);
  if (!Number.isFinite(x) || !Number.isFinite(y)) return null;
  return {
    x: Math.max(0, Math.min(STAGE_W, x)),
    y: Math.max(-900, Math.min(H + 180, y))
  };
}

function getMouseWorldPoint(event) {
  const rect = canvas.getBoundingClientRect();
  const screenX = (event.clientX - rect.left) * (canvas.width / Math.max(1, rect.width));
  const screenY = (event.clientY - rect.top) * (canvas.height / Math.max(1, rect.height));
  return sanitizeAimPoint({
    x: cameraX + screenX / cameraZoom,
    y: (screenY - getCameraYOffset()) / cameraZoom
  });
}

function getActiveMouseTechniqueFighter() {
  return gameMode === "online" && onlineRole === "p2" ? enemy : player;
}

function getTechniqueOrigin(f, move) {
  return {
    x: f.x + f.w / 2,
    y: f.y + (move === "slash" || move === "cleave" || move === "fuga" ? 48 : 56)
  };
}

function getTechniqueAimVector(f, move, aimPoint = null) {
  const origin = getTechniqueOrigin(f, move);
  const aim = sanitizeAimPoint(aimPoint) || sanitizeAimPoint(f.techniqueAim);
  let dx = aim ? aim.x - origin.x : f.dir;
  let dy = aim ? aim.y - origin.y : 0;
  const rawDistance = Math.hypot(dx, dy);
  const length = rawDistance;
  if (length < 8) {
    dx = f.dir;
    dy = 0;
  } else {
    dx /= length;
    dy /= length;
  }
  const dir = Math.abs(dx) > 0.08 ? Math.sign(dx) : f.dir;
  return { x: dx, y: dy, dir, angle: Math.atan2(dy, dx), origin, distance: aim ? rawDistance : Infinity, aim };
}

function setFighterTechniqueAim(f, aimPoint) {
  const aim = sanitizeAimPoint(aimPoint);
  if (!aim) return null;
  f.techniqueAim = aim;
  const move = getTechniqueMoveKey(f, f.chargingTechnique || 1);
  const aimVector = getTechniqueAimVector(f, move, aim);
  if (Math.abs(aimVector.x) > 0.08) f.dir = aimVector.dir;
  return aim;
}

function updateMouseAimFromEvent(event) {
  mouseAimWorld = getMouseWorldPoint(event) || mouseAimWorld;
  if (gameState === "playing") {
    const fighter = getActiveMouseTechniqueFighter();
    if (fighter && (fighter.chargingTechnique || fighter.ultimateAiming || mouseTechniqueHeld.ct1 || mouseTechniqueHeld.ct2)) {
      setFighterTechniqueAim(fighter, mouseAimWorld);
      if (fighter.ultimateAiming) fighter.ultimateAimPoint = mouseAimWorld;
    }
    if (fighter && mouseTechniqueHeld.teleport) {
      fighter.teleportAiming = true;
      fighter.techniqueAim = mouseAimWorld;
    }
    if (fighter && mouseTechniqueHeld.fuga) {
      fighter.fugaAiming = true;
      fighter.techniqueAim = mouseAimWorld;
    }
  }
  return mouseAimWorld;
}


// LIGHT_YAGAMI_PATCH
const LIGHT_INFO_MAX = 100;
const LIGHT_IDENTITY_MAX = 100;
const LIGHT_POTATO_COOLDOWN_TICKS = 5 * 60;
const LIGHT_POTATO_FOCUS_TICKS = 10 * 60;
const LIGHT_SUMMON_MISA_TICKS = 16 * 60;
const LIGHT_SUMMON_SOICHIRO_TICKS = 18 * 60;
const LIGHT_EYE_DEAL_FOCUS_TICKS = 5 * 60;

// LIGHT_BROWN_EFFECTS_PATCH
const LIGHT_BROWN = {
  deep: "#2b1708",
  dark: "#451a03",
  mid: "#7c3f12",
  main: "#a16207",
  bright: "#d97706",
  pale: "#fbbf24",
  cream: "#fef3c7"
};

function lightBrownRgba(which = "main", alpha = 1) {
  const colors = {
    deep: "43, 23, 8",
    dark: "69, 26, 3",
    mid: "124, 63, 18",
    main: "161, 98, 7",
    bright: "217, 119, 6",
    pale: "251, 191, 36",
    cream: "254, 243, 199"
  };
  return `rgba(${colors[which] || colors.main}, ${alpha})`;
}


function isLight(f) {
  return Boolean(f && f.technique === "deathnote");
}

function getLightFocusedCooldown(f, baseTicks) {
  if (!isLight(f)) return baseTicks;
  const infoRatio = Math.max(0, Math.min(1, (f.informationMeter || 0) / LIGHT_INFO_MAX));
  const infoScale = 1 - infoRatio * 0.28;
  const focusScale = (f.potatoFocusTicks || 0) > 0 ? 0.58 : 1;
  return Math.max(12, Math.ceil(baseTicks * infoScale * focusScale));
}

function gainLightInfo(f, amount) {
  if (!isLight(f)) return;
  const boosted = (f.potatoFocusTicks || 0) > 0 ? amount * 1.35 : amount;
  f.informationMeter = Math.max(0, Math.min(LIGHT_INFO_MAX, (f.informationMeter || 0) + boosted));
}

function gainLightIdentity(f, amount) {
  if (!isLight(f)) return;
  const infoBonus = 1 + Math.max(0, Math.min(100, f.informationMeter || 0)) / 220;
  const focusBonus = (f.potatoFocusTicks || 0) > 0 ? 1.3 : 1;
  f.identityProgress = Math.max(0, Math.min(LIGHT_IDENTITY_MAX, (f.identityProgress || 0) + amount * infoBonus * focusBonus));
  if (f.identityProgress >= LIGHT_IDENTITY_MAX) f.ultimateMeter = Math.max(f.ultimateMeter || 0, MAX_ULTIMATE);
}

function lightIdentityComplete(f) {
  return isLight(f) && (f.identityProgress || 0) >= LIGHT_IDENTITY_MAX;
}

function getLightInfoRatio(f) {
  return Math.max(0, Math.min(1, ((f && f.informationMeter) || 0) / LIGHT_INFO_MAX));
}

function setLightSummonAnchor(f, aimPoint = null) {
  if (!isLight(f)) return;
  const center = getFighterCenter(f);
  const side = f.dir || 1;
  const aim = sanitizeAimPoint(aimPoint);

  // LIGHT_INVESTIGATION_AIM_PATCH:
  // Investigation summons should appear where the player aimed, not follow Light.
  // SUMMON_GRAVITY_RANGE_PATCH: the aim point can no longer place a summon
  // across the whole stage - it is clamped to the summon range around Light.
  if (aim) {
    const rangedX = Math.max(center.x - LIGHT_SUMMON_MAX_RANGE, Math.min(center.x + LIGHT_SUMMON_MAX_RANGE, aim.x));
    f.lightSummonAnchorDir = aim.x >= center.x ? 1 : -1;
    f.lightSummonAnchorX = Math.max(36, Math.min(STAGE_W - 36, rangedX));
    f.lightSummonAnchorY = Math.max(84, Math.min(GROUND, aim.y));
    f.lightSummonFallVy = 0;
    return;
  }

  f.lightSummonAnchorDir = side;
  f.lightSummonAnchorX = center.x - side * 102;
  f.lightSummonAnchorY = f.y + f.h;
  f.lightSummonFallVy = 0;
}

// SUMMON_GRAVITY_RANGE_PATCH: nearest standable surface below a summon's
// feet - platform tops count, same casting rule as fighter shadows.
function getLightSummonSurfaceY(centerX, footY) {
  let best = GROUND;
  let bestDistance = GROUND - footY;
  for (const platform of getActivePlatforms()) {
    if (centerX < platform.x - 18 || centerX > platform.x + platform.w + 18) continue;
    const distance = platform.y - footY;
    if (distance < -8) continue;
    if (distance <= bestDistance) {
      best = platform.y;
      bestDistance = distance;
    }
  }
  return best;
}

function clearLightSummonAnchor(f) {
  if (!f) return;
  f.lightSummonAnchorX = null;
  f.lightSummonAnchorY = null;
  f.lightSummonAnchorDir = 0;
}

function getLightSummonRect(f) {
  if (!isLight(f) || !f.lightSummonType) return null;
  const isMisa = f.lightSummonType === "misa";
  const width = isMisa ? 56 : 62;
  const height = isMisa ? 118 : 124;

  if (!Number.isFinite(f.lightSummonAnchorX) || !Number.isFinite(f.lightSummonAnchorY)) {
    setLightSummonAnchor(f);
  }

  const centerX = Number.isFinite(f.lightSummonAnchorX) ? f.lightSummonAnchorX : getFighterCenter(f).x;
  const footY = Number.isFinite(f.lightSummonAnchorY) ? f.lightSummonAnchorY : (f.y + f.h);
  const dir = f.lightSummonAnchorDir || f.dir || 1;
  const x = centerX - width / 2;
  const y = footY - height;
  return { x, y, w: width, h: height, footY, dir, centerX };
}

function damageLightSummon(f, amount, sourceDir = 1, kind = "slash") {
  if (!isLight(f) || !f.lightSummonType || amount <= 0) return false;
  f.lightSummonHealth = Math.max(0, (f.lightSummonHealth || 0) - amount);
  f.lightSummonHitFlash = 10;
  const rect = getLightSummonRect(f);
  if (rect) spawnHitSpark(rect.x + rect.w / 2, rect.y + rect.h / 2, sourceDir, kind);
  if (f.lightSummonHealth <= 0) {
    const defeated = f.lightSummonType;
    f.lightSummonType = null;
    f.lightSummonTicks = 0;
    f.lightSummonHealth = 0;
    f.lightSummonMaxHealth = 0;
    clearLightSummonAnchor(f);
    if (defeated === "misa") {
      f.lightSummonStage = Math.max(f.lightSummonStage || 1, 2);
      showActionWarning("Misa has been removed");
    } else {
      f.lightSummonStage = Math.max(f.lightSummonStage || 2, 3);
      showActionWarning("Soichiro has been removed");
    }
    f.lightInvestigationCooldown = Math.max(f.lightInvestigationCooldown || 0, 2 * 60);
    f.lightInvestigationCooldownMax = Math.max(f.lightInvestigationCooldownMax || 0, f.lightInvestigationCooldown);
  }
  updateHud();
  return true;
}

function updateLightSummonUnderAttack(f, opponent) {
  if (!isLight(f) || !f.lightSummonType || !opponent || opponent.ko) return;
  const rect = getLightSummonRect(f);
  if (!rect) return;
  const attack = getAttackSpec(opponent);
  if (attack && opponent.attacking && !opponent.hasHit) {
    const activeStart = attack.windup;
    const activeEnd = attack.windup + attack.active;
    if (opponent.attackFrame >= activeStart && opponent.attackFrame <= activeEnd && rectsOverlap(getHitbox(opponent), rect)) {
      opponent.hasHit = true;
      const damage = Math.ceil((opponent.attacking === "heavy" ? 30 : 18) * getOutgoingDamageMultiplier(opponent));
      damageLightSummon(f, damage, opponent.dir || 1, opponent.attacking === "heavy" ? "heavy" : "light");
      gainUltimate(opponent, damage * ULT_DAMAGE_GAIN_SCALE * 0.45);
      hitStopTicks = Math.max(hitStopTicks, opponent.attacking === "heavy" ? HITSTOP_HEAVY : HITSTOP_LIGHT);
      shake = Math.max(shake, opponent.attacking === "heavy" ? 9 : 5);
    }
  }
}

function damageLightSummonByProjectile(projectile, f) {
  if (!projectile || projectile.visualOnly || !isLight(f) || !f.lightSummonType) return false;
  const rect = getLightSummonRect(f);
  if (!rect || !projectileOverlapsTarget(projectile, rect)) return false;
  const source = projectile.owner === "player" ? player : enemy;
  const damage = Math.max(8, Math.ceil((projectile.damage || 10) * 0.74));
  damageLightSummon(f, damage, projectile.dir || source?.dir || 1, projectile.move || "slash");
  if (source) gainUltimate(source, damage * ULT_DAMAGE_GAIN_SCALE * 0.4);
  projectile.hit = true;
  spawnProjectileDisperse(projectile);
  return true;
}

function startRyukStrike(f, aimPoint = null, cost = 0) {
  if (!isLight(f)) return false;
  const aim = sanitizeAimPoint(aimPoint) || mouseAimWorld;
  if (cost > 0) f.ce = Math.max(0, f.ce - cost);
  const infoRatio = getLightInfoRatio(f);
  const radius = 66 + Math.floor(infoRatio * 28);
  const startup = Math.max(8, Math.ceil(18 - infoRatio * 8 - ((f.potatoFocusTicks || 0) > 0 ? 4 : 0)));
  projectiles.push({
    owner: f === player ? "player" : "enemy",
    move: "ryukStrike",
    x: Math.max(40, Math.min(STAGE_W - 40, aim.x)),
    y: Math.max(70, Math.min(GROUND - 60, aim.y)),
    vx: 0,
    vy: 0,
    baseVx: 0,
    baseVy: 0,
    radius,
    damage: Math.ceil(34 * getOutgoingDamageMultiplier(f)),
    knockback: 34,
    dir: f.dir,
    aimX: 0,
    aimY: 1,
    angle: Math.PI / 2,
    maxTravel: null,
    traveled: 0,
    life: 34,
    startup,
    startupMax: startup,
    warningRadius: radius,
    maxLife: 34,
    hit: false
  });
  // LIGHT_INFO_NAME_FILL_RULES_PATCH:
  // Ryuk/Shinigami Strike gives no free Info or Name just for being cast.
  // Info is awarded only if it actually hits.
  updateHud();
  return true;
}

function startNameInvestigation(f, cost = 0, aimPoint = null) {
  if (!isLight(f)) return false;
  if (cost > 0) f.ce = Math.max(0, f.ce - cost);

  const fallbackPoint = aimPoint || (getOpponent(f) ? {
    x: getOpponent(f).x + getOpponent(f).w / 2,
    y: getOpponent(f).y + getOpponent(f).h
  } : null);
  setLightSummonAnchor(f, fallbackPoint);

  if (f.lightSummonStage <= 1 && f.lightSummonType !== "misa") {
    f.lightSummonType = "misa";
    f.lightSummonHealth = 50;
    f.lightSummonMaxHealth = 50;
    f.lightSummonTicks = LIGHT_SUMMON_MISA_TICKS;
    f.lightSummonStage = 1;
  } else if (f.lightSummonStage <= 2 && f.lightSummonType !== "soichiro") {
    f.lightSummonType = "soichiro";
    f.lightSummonHealth = 110;
    f.lightSummonMaxHealth = 110;
    f.lightSummonTicks = LIGHT_SUMMON_SOICHIRO_TICKS;
    f.lightSummonStage = 2;
  } else {
    return startEyeDeal(f);
  }

  gainLightInfo(f, 10);
  updateHud();
  return true;
}

function startEyeDeal(f) {
  if (!isLight(f) || f.eyeDealUsed || f.health <= 10) return false;
  f.eyeDealUsed = true;
  f.lightSummonStage = 3;
  f.lightSummonType = null;
  f.lightSummonTicks = 0;
  f.lightSummonHealth = 0;
  f.lightSummonMaxHealth = 0;
  clearLightSummonAnchor(f);
  f.health = Math.max(1, Math.ceil(f.health * 0.5));
  f.identityProgress = LIGHT_IDENTITY_MAX;
  f.informationMeter = LIGHT_INFO_MAX;
  f.ultimateMeter = MAX_ULTIMATE;
  f.potatoFocusTicks = Math.max(f.potatoFocusTicks || 0, LIGHT_EYE_DEAL_FOCUS_TICKS);
  f.eyeDealGlowTicks = 8 * 60;
  spawnHitSpark(f.x + f.w / 2, f.y + 34, f.dir, "brown");
  updateHud();
  return true;
}

function usePotatoChip(f) {
  // LIGHT_BALANCE_PATCH: can't eat through a combo - only usable while
  // actually safe, and it opens a brief real window where Light can't
  // block/attack/dodge, matching "no protection while being activated."
  if (!isLight(f) || f.ko || f.knockdown || f.stun > 0 || f.dodging > 0 || (f.potatoCooldown || 0) > 0 || gameState !== "playing" || paused || gameOver) return false;
  f.health = Math.min(f.maxHealth, f.health + 24);
  f.delayedHealth = Math.max(f.delayedHealth || 0, f.health);
  f.potatoCooldown = LIGHT_POTATO_COOLDOWN_TICKS;
  f.potatoFocusTicks = LIGHT_POTATO_FOCUS_TICKS;
  f.potatoVulnerableTicks = 14;
  // Potato gives healing/focus, not free Info or Name.
  spawnHitSpark(f.x + f.w / 2, f.y + 42, f.dir, "brown");
  updateHud();
  return true;
}

function updateLightSystems(f, opponent) {
  if (!isLight(f)) return;

  if (f.potatoCooldown > 0) f.potatoCooldown -= 1;
  if (f.potatoFocusTicks > 0) f.potatoFocusTicks -= 1;
  if (f.potatoVulnerableTicks > 0) f.potatoVulnerableTicks -= 1;
  if (f.deathNoteSlowTicks > 0) f.deathNoteSlowTicks -= 1;
  if (f.eyeDealGlowTicks > 0) f.eyeDealGlowTicks -= 1;
  if (f.lightSummonHitFlash > 0) f.lightSummonHitFlash -= 1;

  if (!f.ko && opponent && !opponent.ko) {
    // Name is only built by Name Investigation.
    // Info is built by landing hits or keeping investigation active, not by simply standing nearby.
  }

  if (f.lightSummonType && f.lightSummonTicks > 0) {
    if (!Number.isFinite(f.lightSummonAnchorX) || !Number.isFinite(f.lightSummonAnchorY)) setLightSummonAnchor(f);
    f.lightSummonTicks -= 1;

    // SUMMON_GRAVITY_RANGE_PATCH: a summon placed in the air falls like
    // anything else instead of hovering at the aim point - it drops until
    // its feet reach the ground or a platform top.
    const summonSurfaceY = getLightSummonSurfaceY(f.lightSummonAnchorX, f.lightSummonAnchorY);
    if (f.lightSummonAnchorY < summonSurfaceY) {
      f.lightSummonFallVy = (f.lightSummonFallVy || 0) + GRAVITY;
      f.lightSummonAnchorY = Math.min(summonSurfaceY, f.lightSummonAnchorY + f.lightSummonFallVy);
    } else {
      f.lightSummonFallVy = 0;
    }

    const nearby = opponent ? Math.abs((f.x + f.w / 2) - (opponent.x + opponent.w / 2)) < 360 : false;
    // Name is filled by Investigation only.
    // Misa is faster; Soichiro is slower but tougher.
    const rate = (f.lightSummonType === "misa" ? 0.24 : 0.13) * (nearby ? 1.15 : 0.82);
    gainLightIdentity(f, rate);
    gainLightInfo(f, rate * 0.45);
    updateLightSummonUnderAttack(f, opponent);

    if (f.lightSummonType === "soichiro" && opponent) {
      const rect = getLightSummonRect(f);
      if (rect && rectsOverlap(expandRect(rect, 58), opponent)) {
        f.shieldTicks = Math.min(SHIELD_MAX_TICKS, (f.shieldTicks || 0) + 0.18);
        if (Math.abs(opponent.vx || 0) > 0.1) opponent.vx *= 0.992;
      }
    }
  } else if (f.lightSummonTicks <= 0) {
    f.lightSummonType = null;
    f.lightSummonHealth = 0;
    f.lightSummonMaxHealth = 0;
    clearLightSummonAnchor(f);
  }
}

function startDeathNoteUltimate(f) {
  if (!isLight(f)) return false;
  if (!lightIdentityComplete(f)) {
    showActionWarning("Identity Not Complete");
    return false;
  }
  if (!canStartUltimate(f)) return false;

  const target = getOpponent(f);
  if (!target || target.ko) return false;

  triggerUltCutscene(f); // ULT_CUTSCENES_PATCH
  f.ultimateMeter = 0;
  f.ultimateAiming = false;
  f.ultimateMove = "deathNote";
  f.ultimateStartup = f.eyeDealUsed ? 28 : 50;
  f.ultimateRecovery = f.eyeDealUsed ? 30 : 42;
  f.vx *= 0.25;
  f.blocking = false;

  const eyeBonus = f.eyeDealUsed ? 1.18 : 1;
  const damage = Math.ceil((target.maxHealth * 0.42 + 86) * eyeBonus);
  const dealt = applyFighterDamage(target, damage);
  target.stun = Math.max(target.stun || 0, f.eyeDealUsed ? 84 : 62);
  target.hurt = Math.max(target.hurt || 0, 30);
  target.deathNoteSlowTicks = 6 * 60;
  target.deathNoteFearTicks = 6 * 60;
  target.vx *= 0.22;
  target.vy = Math.min(target.vy || 0, -5.5);
  target.grounded = false;
  gainUltimate(f, dealt * ULT_DAMAGE_GAIN_SCALE);
  spawnHitSpark(target.x + target.w / 2, target.y + 34, target.dir, "brown");
  spawnHitSpark(target.x + target.w / 2, target.y + 68, -target.dir, "brown");
  triggerUltimateScreenEffect("deathNote", 92);
  updateHud();

  if (!pacifistBot && target.health <= 0) startKnockout(f, target);
  return true;
}

function damageLightInformationOnHeavyHit(defender, amount) {
  if (!isLight(defender) || amount < 24) return;
  defender.informationMeter = Math.max(0, (defender.informationMeter || 0) - Math.ceil(amount * 0.22));
  defender.identityProgress = Math.max(0, (defender.identityProgress || 0) - Math.ceil(amount * 0.08));
}

function getLightExtraHudItems(f) {
  if (!isLight(f)) return [];

  // LIGHT_REAL_INFO_NAME_BARS_PATCH:
  // Info and Name use the main resource bars now, not extra cooldown rows.
  const items = [
    { name: "POTATO", current: f.potatoCooldown || 0, max: LIGHT_POTATO_COOLDOWN_TICKS, mode: "cooldown" }
  ];

  if ((f.potatoFocusTicks || 0) > 0) {
    items.push({ name: "FOCUS", current: f.potatoFocusTicks, max: LIGHT_POTATO_FOCUS_TICKS, mode: "active" });
  }

  if (f.lightSummonType) {
    items.push({ name: f.lightSummonType.toUpperCase(), current: f.lightSummonHealth || 0, max: f.lightSummonMaxHealth || 1, mode: "resource", style: "light-summon-meter" });
  }

  return items;
}


function getTechniqueCharacterName(technique) {
  if (technique === "shrine") return "Sukuna";
  if (technique === "deathnote") return "Light";
  if (technique === "brawler") return "Thragg";
  if (technique === "blackleg") return "Sanji"; // SANJI_PATCH
  if (technique === "hivemind") return "Vecna"; // VECNA_PATCH
  if (technique === "zealot") return "Zealot"; // ZEALOT_PATCH
  if (technique === "spider") return "Spider-Man"; // SPIDER_PATCH
  if (technique === "beast") return "Inosuke"; // INOSUKE_PATCH
  if (technique === "jiji") return "Jiji"; // JIJI_PATCH
  if (technique === "david") return "David"; // DAVID_PATCH
  if (technique === "akira") return "Akira"; // AKIRA_PATCH
  return "Gojo";
}

function shouldShowChargePreview(f) {
  if (!f || !f.chargingTechnique) return false;
  if (gameMode === "online") return onlineRole === "p2" ? f === enemy : f === player;
  if (gameMode === "cpu" && f === enemy && f.technique === "limitless") return true;
  return f === player;
}

