function getTechniqueMoveKey(f, slot) {
  if (f.technique === "limitless") return slot === 2 ? "red" : "blue";
  if (f.technique === "shrine") return slot === 2 ? "cleave" : "slash";
  if (f.technique === "deathnote") return slot === 2 ? "nameInvestigation" : "ryukStrike";
  // THRAGG_BRAWLER_PATCH: only one ranged tool, mapped to both mouse buttons.
  if (f.technique === "brawler") return "groundBreak";
  if (f.technique === "blackleg") return slot === 2 ? "muttonShot" : "diableJambe"; // SANJI_PATCH
  if (f.technique === "zealot") return slot === 2 ? "psiFlurry" : "charge"; // ZEALOT_PATCH
  if (f.technique === "spider") return slot === 2 ? "webBarrage" : "webShot"; // SPIDER_PATCH
  if (f.technique === "beast") return slot === 2 ? "beastDevour" : "beastPierce"; // INOSUKE_PATCH
  if (f.technique === "jiji") { // JIJI_PATCH: mouse moves depend on the form.
    if (f.jijiForm === "evileye") return slot === 2 ? "berserkerRush" : "evilBlast";
    return slot === 2 ? "soccerStrike" : "spiritBlast";
  }
  if (f.technique === "david") return slot === 2 ? "projectileLauncher" : "gorillaArms"; // DAVID_PATCH
  if (f.technique === "akira") return slot === 2 ? "voltPunch" : "joyRide"; // AKIRA_PATCH
  if (f.technique === "hivemind") return slot === 2 ? "demodogHunt" : "demobatSwarm"; // VECNA_PATCH
  return "blue";
}

