function sendOnlineFighterState() {
  if (!canSendOnlinePacket() || onlineRole !== "p2" || gameState !== "playing") return;
  const now = performance.now();
  if (now - lastOnlineFighterSent < ONLINE_FIGHTER_SEND_MS) return;
  lastOnlineFighterSent = now;
  onlineSocket.send(JSON.stringify({ type: "fighter", fighter: getFighterNetworkState(enemy) }));
}

function sendOnlineDamage(hit) {
  if (!canSendOnlinePacket() || onlineRole !== "p2") return;

  const holdLock = hit && (hit.barrageHold || hit.grabHold);
  const bigLock = hit && (hit.knockdown || hit.gojoPushPull || hit.gojoRedHeavy || hit.blueChase);

  // ONLINE_P2_HIT_MOVEMENT_FIX
  // P2 predicts their own hit locally first. Send the host the exact post-hit
  // position/velocity too, so the host state does not snap Player 1 back in place.
  const localDefenderState = player ? {
    defenderX: player.x,
    defenderY: player.y,
    defenderVx: player.vx,
    defenderVy: player.vy,
    defenderGrounded: player.grounded,
    defenderKnockdown: player.knockdown,
    defenderKnockdownTimer: player.knockdownTimer
  } : {};

  joinerLocalHitLockTicks = Math.max(joinerLocalHitLockTicks || 0, holdLock ? 75 : bigLock ? 70 : 48);

  onlineSocket.send(JSON.stringify({
    type: "damage",
    ...hit,
    ...localDefenderState
  }));
}

function sendOnlineReady() {
  if (!canSendOnlinePacket() || !isOnlinePlayerRole()) return;
  lastOnlineReadySent = performance.now();
  console.log("[ready send]", { role: onlineRole, phase: gameState, round: currentRound });
  onlineSocket.send(JSON.stringify({ type: "ready", role: onlineRole, phase: gameState, round: currentRound }));
}

function sendOnlineState() {
  if (!canSendOnlinePacket() || onlineRole !== "p1") return;
  const now = performance.now();
  if (now - lastOnlineStateSent < ONLINE_STATE_SEND_MS) return;
  lastOnlineStateSent = now;

  // Send compact fighter states instead of giant live objects.
  // This removes a lot of online lag from JSON stringify + websocket traffic.
  const playerState = getFighterNetworkState(player);
  const enemyState = getFighterNetworkState(enemy);
  const hostProjectiles = projectiles
    .filter((p) => p.owner === "player")
    .slice(-10)
    .map(compactProjectileForNetwork);

  onlineSocket.send(JSON.stringify({
    type: "state",
    player: playerState,
    enemy: enemyState,
    currentRound,
    playerRounds,
    enemyRounds,
    gameOver,
    roundEnding,
    roundResolved,
    paused,
    gameState,
    onlineReady,
    player1Ready,
    player2Ready,
    readyCountdownValue,
    lastRoundWinner,
    activeDomain,
    pendingDomain,
    domainClash,
    projectiles: hostProjectiles
  }));
}

function resetRoundActors() {
  platforms = makeStagePlatforms(currentStageId); // STAGE_SELECT_PATCH
  stageHazards = [];
  stageHazardTimer = 90;
  player = makeFighter({ x: 170, w: 50, h: 128, dir: 1, color: "#2563eb", accent: "#1d4ed8" });
  enemy = makeFighter({ x: STAGE_W - 230, w: 52, h: 128, dir: -1, color: "#dc2626", accent: "#991b1b" });
  projectiles = [];
  vecnaMinions = []; // VECNA_PATCH
  endUpsideDown(); // VECNA_PATCH
  zealotUnits = []; // ZEALOT_PATCH
  orbitalBeams = []; // ZEALOT_PATCH
  hitSparks = [];
  projectileDisperses = [];
  teleportEffects = [];
  fugaExplosions = [];
  shieldBreakEffects = [];
  worldSlashEffects = [];
  groundEraseEffects = [];
  ultimateChargeEffects = [];
  ultimateScreenEffect = { ticks: 0, maxTicks: 0, kind: "" };
  ultCutscene = null; // ULT_CUTSCENES_PATCH
  cinematicZoomTicks = 0;
  ultimateFocusOwner = null;
  pendingDomain = null;
  activeDomain = null;
  domainClash = null;
  mouseTechniqueHeld.ct1 = false;
  mouseTechniqueHeld.ct2 = false;
  mouseTechniqueHeld.teleport = false;
  mouseTechniqueHeld.fuga = false;
  if (gameMode === "cpu") {
    ensureCpuOpponentTechnique("reset round actors");
  }
  if (gameMode === "online" && onlineRole === "p2") {
    player.technique = onlineTechniqueChoices.p1 || "limitless";
    enemy.technique = onlineTechniqueChoices.p2 || selectedTechnique;
  } else if (gameMode === "online") {
    player.technique = onlineTechniqueChoices.p1 || selectedTechnique;
    enemy.technique = onlineTechniqueChoices.p2 || "limitless";
  } else {
    player.technique = selectedTechnique;
    enemy.technique = gameMode === "cpu" ? cpuOpponentTechnique : "limitless";
  }
  if (pacifistBot) enemy.technique = "dummy";
  // SKINS_PATCH: apply the player's chosen cosmetic skin for each character.
  player.skinId = getSelectedSkin(player.technique);
  enemy.skinId = getSelectedSkin(enemy.technique);
  applyTechniqueStats(player);
  applyTechniqueStats(enemy);
  applyCpuDifficultyStats();
  if (pacifistBot) {
    enemy.isPracticeDummy = true;
    enemy.practiceHomeX = STAGE_W / 2 - enemy.w / 2;
    enemy.practiceIdleTicks = PRACTICE_BOT_RETURN_TICKS;
    enemy.x = enemy.practiceHomeX;
    enemy.y = GROUND - enemy.h;
    enemy.vx = 0;
    enemy.vy = 0;
    enemy.grounded = true;
    enemy.onPlatform = false;
    enemy.dir = -1;
    enemy.attacking = null;
    enemy.aiGoal = "dummy";
    resetPracticeDamage();
  }
  koWinner = null;
  shake = 0;
  hitStopTicks = 0;
  updateControlsVisibility();
  updateCamera(true);
}

function startRound(nextState = "playing") {
  console.log("[round start]", { round: currentRound, nextState, gameMode, onlineRole });
  resetRoundActors();
  resetReadyPhase(`start round ${nextState}`);
  lastRoundWinner = null;
  frame = 0;
  fixedAccumulator = 0;
  lastFrameTime = performance.now();
  lastOnlineStateSent = 0;
  lastOnlineInputSent = 0;
  lastOnlineFighterSent = 0;
  setGameState(nextState, "startRound");
  gameOver = nextState !== "playing";
  roundEnding = false;
  roundResolved = nextState !== "playing";
  message.classList.add("hidden");
  updateReadyPromptVisibility();
  readyButton.disabled = false;
  clearInterval(readyCountdownId);
  setCountdownOverlay(0);
  if (nextState === "lobby") {
    updateReadyMessage();
  }
  updateBattleMusicState(nextState === "playing");
  updateHud();
}





function getPlayerLabelColor() {
  return "#ff4b4b";
}

function getEnemyLabelColor() {
  return gameMode === "cpu" ? "#cbd5e1" : "#60a5fa";
}

function getHealthColorClass(f) {
  const ratio = f.maxHealth > 0 ? f.health / f.maxHealth : 0;
  if (ratio > 0.55) return "green";
  if (ratio > 0.25) return "yellow";
  return "red";
}

function getSukunaPassiveLevel(f) {
  if (!f || f.technique !== "shrine" || f.health <= 0) return 0;
  const state = getLayeredHealthState(f.health, f.maxHealth, f.healthBars);
  if (state.activeBars <= 1) return 2;
  if (state.activeBars === 2) return 1;
  return 0;
}

function getSukunaPassiveDamageMultiplier(f) {
  const level = getSukunaPassiveLevel(f);
  if (level >= 2) return SUKUNA_PASSIVE_LAST_BAR_DAMAGE;
  if (level === 1) return SUKUNA_PASSIVE_ONE_BAR_DAMAGE;
  return 1;
}

function getOutgoingDamageMultiplier(f) {
  const simpleDomainBonus = hasSimpleDomain(f) ? SIMPLE_DOMAIN_CT_DAMAGE_MULTIPLIER : 1;
  return (f?.outgoingDamageMultiplier || 1) * getSukunaPassiveDamageMultiplier(f) * simpleDomainBonus * getJijiDamageMultiplier(f) * getDavidDamageMultiplier(f) * getAkiraDamageMultiplier(f);
}

// DAVID_PATCH: Cyberware Load adds up to +10% ability damage; Cyberpsychosis
// and the Cyber Skeleton ultimate stack their own damage boosts.
function getDavidDamageMultiplier(f) {
  if (!f || f.technique !== "david") return 1;
  let m = 1 + Math.min(1, (f.davidLoad || 0) / DAVID_LOAD_MAX) * DAVID_LOAD_DAMAGE_BONUS;
  if ((f.davidPsychosisTicks || 0) > 0) m *= DAVID_PSYCHOSIS_DAMAGE;
  if ((f.davidUltTicks || 0) > 0) m *= DAVID_ULT_DAMAGE;
  return m;
}

// JIJI_PATCH: Spiritual Acceptance grants Evil Eye +15% damage; Full
// Possession grants +20% while active.
function getJijiDamageMultiplier(f) {
  if (!f || f.technique !== "jiji") return 1;
  let m = 1;
  if (f.jijiForm === "evileye") {
    if ((f.jijiUltTicks || 0) > 0 && f.jijiUltForm === "evileye") m *= 1.2; // Full Possession
    if ((f.jijiUltTicks || 0) > 0 && f.jijiUltForm === "jiji") m *= 1.15; // Spiritual Acceptance boon
  }
  return m;
}

