function drawSukunaModelCleanup(f) {
  if (!f || f.technique !== "shrine") return;

  ctx.save();
  const facing = f.dir || 1;
  const centerX = f.x + f.w / 2;
  const baseY = f.y;
  ctx.translate(centerX, baseY);
  ctx.scale(facing, 1);

  const skin = "#e7b39e";
  const tattoo = "#1b0610";
  const pants = "#171019";
  const pantsLight = "rgba(245, 245, 245, 0.24)";

  // Cover any extra/old eye marks and redraw simpler face with no extra eyes.
  ctx.fillStyle = skin;
  ctx.beginPath();
  ctx.roundRect(-15, 4, 30, 29, 9);
  ctx.fill();

  // Main eyes only: smaller and meaner.
  ctx.strokeStyle = tattoo;
  ctx.lineWidth = 2;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.moveTo(-10, 16);
  ctx.lineTo(-3, 14);
  ctx.moveTo(10, 16);
  ctx.lineTo(3, 14);
  ctx.stroke();

  // Sukuna-like facial tattoos: forehead mark, cheek/eye lines, chin marks.
  ctx.lineWidth = 2.4;
  ctx.beginPath();
  ctx.moveTo(0, 7);
  ctx.lineTo(0, 13);
  ctx.moveTo(-6, 9);
  ctx.quadraticCurveTo(-11, 10, -13, 14);
  ctx.moveTo(6, 9);
  ctx.quadraticCurveTo(11, 10, 13, 14);
  ctx.moveTo(-13, 21);
  ctx.quadraticCurveTo(-8, 19, -4, 21);
  ctx.moveTo(13, 21);
  ctx.quadraticCurveTo(8, 19, 4, 21);
  ctx.moveTo(-4, 28);
  ctx.lineTo(-1, 32);
  ctx.moveTo(4, 28);
  ctx.lineTo(1, 32);
  ctx.stroke();

  // Torso/arm tattoo bands.
  ctx.lineWidth = 2.7;
  ctx.beginPath();
  ctx.moveTo(-16, 47);
  ctx.quadraticCurveTo(-7, 52, 0, 47);
  ctx.quadraticCurveTo(7, 52, 16, 47);
  ctx.moveTo(-18, 62);
  ctx.lineTo(-6, 68);
  ctx.moveTo(18, 62);
  ctx.lineTo(6, 68);
  ctx.stroke();

  // Remove shoe shapes by painting bare ankle/foot areas and then add foot outline.
  ctx.fillStyle = skin;
  ctx.beginPath();
  ctx.ellipse(-12, 92, 13, 6, 0.05, 0, Math.PI * 2);
  ctx.ellipse(13, 92, 13, 6, -0.05, 0, Math.PI * 2);
  ctx.fill();

  ctx.strokeStyle = tattoo;
  ctx.lineWidth = 1.4;
  ctx.beginPath();
  ctx.moveTo(-23, 92);
  ctx.quadraticCurveTo(-14, 96, -3, 92);
  ctx.moveTo(3, 92);
  ctx.quadraticCurveTo(14, 96, 24, 92);
  ctx.stroke();

  // Detailed loose pants: waistband, folds, knees, lower-leg folds.
  ctx.strokeStyle = pantsLight;
  ctx.lineWidth = 2;
  ctx.lineCap = "round";
  ctx.beginPath();
  ctx.moveTo(-21, 66);
  ctx.lineTo(21, 66);
  ctx.moveTo(-17, 73);
  ctx.quadraticCurveTo(-10, 78, -14, 89);
  ctx.moveTo(-5, 69);
  ctx.quadraticCurveTo(-2, 78, -6, 91);
  ctx.moveTo(17, 73);
  ctx.quadraticCurveTo(10, 78, 14, 89);
  ctx.moveTo(5, 69);
  ctx.quadraticCurveTo(2, 78, 6, 91);
  ctx.moveTo(-18, 82);
  ctx.lineTo(-5, 84);
  ctx.moveTo(18, 82);
  ctx.lineTo(5, 84);
  ctx.stroke();

  ctx.restore();
}

// VECNA_PATCH: demobats and demodogs - brawler art style, black outlines,
// no faces (the demodog's petal head stays closed).
function drawVecnaMinions() {
  for (const m of vecnaMinions) {
    const flash = m.hitCooldown > 12;
    ctx.save();
    if (m.kind === "bat") {
      const flap = Math.sin(frame * 0.55 + m.wob) * 7;
      const dir = Math.sign(m.vx) || 1;
      ctx.translate(m.x, m.y);
      ctx.scale(dir, 1);
      // wings
      ctx.fillStyle = flash ? "#7f5a5a" : "#241418";
      ctx.strokeStyle = "#020617";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-3, 0);
      ctx.quadraticCurveTo(-13, -6 - flap, -19, 2 - flap);
      ctx.quadraticCurveTo(-12, 3, -4, 4);
      ctx.closePath();
      ctx.moveTo(3, 0);
      ctx.quadraticCurveTo(13, -6 + flap, 19, 2 + flap);
      ctx.quadraticCurveTo(12, 3, 4, 4);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
      // body
      ctx.fillStyle = flash ? "#9c6b6b" : "#33191f";
      ctx.beginPath();
      ctx.ellipse(0, 0, 6.5, 4.6, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();
      ctx.fillStyle = "#7f1d1d";
      ctx.beginPath();
      ctx.ellipse(2, -1, 2, 1.4, 0, 0, Math.PI * 2);
      ctx.fill();
    } else {
      const dir = Math.sign(m.vx) || 1;
      const lope = m.state === "hunt" ? Math.sin(frame * 0.5) * 4 : 0;
      ctx.translate(m.x, m.y);
      ctx.scale(dir, 1);
      // legs
      ctx.strokeStyle = "#020617";
      ctx.lineWidth = 7;
      ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(-12, 4);
      ctx.lineTo(-15 - lope * 0.5, 15);
      ctx.moveTo(-4, 5);
      ctx.lineTo(-5 + lope * 0.5, 15);
      ctx.moveTo(5, 5);
      ctx.lineTo(4 - lope * 0.5, 15);
      ctx.moveTo(12, 4);
      ctx.lineTo(15 + lope * 0.5, 15);
      ctx.stroke();
      ctx.strokeStyle = flash ? "#9c6b6b" : "#3b2026";
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(-12, 4);
      ctx.lineTo(-15 - lope * 0.5, 14);
      ctx.moveTo(-4, 5);
      ctx.lineTo(-5 + lope * 0.5, 14);
      ctx.moveTo(5, 5);
      ctx.lineTo(4 - lope * 0.5, 14);
      ctx.moveTo(12, 4);
      ctx.lineTo(15 + lope * 0.5, 14);
      ctx.stroke();
      // body
      ctx.fillStyle = flash ? "#9c6b6b" : "#3b2026";
      ctx.strokeStyle = "#020617";
      ctx.lineWidth = 2.4;
      ctx.beginPath();
      ctx.ellipse(0, 0, 19, 9, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.stroke();
      // closed petal head - jagged bud, no face
      ctx.fillStyle = flash ? "#b98484" : "#4d262d";
      ctx.beginPath();
      ctx.moveTo(14, -5);
      ctx.lineTo(24, -8);
      ctx.lineTo(27, -2);
      ctx.lineTo(28, 4);
      ctx.lineTo(22, 7);
      ctx.lineTo(15, 5);
      ctx.closePath();
      ctx.fill();
      ctx.stroke();
      ctx.strokeStyle = "rgba(127, 29, 29, 0.85)";
      ctx.lineWidth = 1.6;
      ctx.beginPath();
      ctx.moveTo(24, -7);
      ctx.lineTo(23, 6);
      ctx.moveTo(20, -6);
      ctx.lineTo(19, 6);
      ctx.stroke();
    }
    ctx.restore();
  }
}

// VECNA_PATCH: giant spider leg slams during The Upside Down. Drawn over
// the fighters; the warning shadow telegraphs the strike point.
function drawUpsideDownSpider() {
  if (!upsideDown) return;
  if (upsideDown.warnTicks > 0 && upsideDown.warnX !== null) {
    const t = 1 - upsideDown.warnTicks / VECNA_SPIDER_WARN_TICKS;
    ctx.save();
    ctx.globalAlpha = 0.35 + t * 0.4;
    ctx.fillStyle = "rgba(60, 10, 16, 0.6)";
    ctx.beginPath();
    ctx.ellipse(upsideDown.warnX, GROUND - 3, VECNA_SPIDER_SLAM_RADIUS * (0.5 + t * 0.5), 8, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = "rgba(220, 80, 80, 0.85)";
    ctx.lineWidth = 2.5;
    ctx.stroke();
    // the leg descending during the telegraph
    const legDrop = t * t;
    const kneeX = upsideDown.warnX + 130;
    const kneeY = -80 + legDrop * 150;
    const tipY = -40 + legDrop * (GROUND + 36);
    ctx.globalAlpha = 0.9;
    ctx.strokeStyle = "#020617";
    ctx.lineWidth = 20;
    ctx.lineCap = "round";
    ctx.beginPath();
    ctx.moveTo(kneeX + 130, -60);
    ctx.lineTo(kneeX, kneeY);
    ctx.lineTo(upsideDown.warnX, Math.min(tipY, GROUND - 4));
    ctx.stroke();
    ctx.strokeStyle = "#1d0e14";
    ctx.lineWidth = 13;
    ctx.beginPath();
    ctx.moveTo(kneeX + 130, -60);
    ctx.lineTo(kneeX, kneeY);
    ctx.lineTo(upsideDown.warnX, Math.min(tipY, GROUND - 4));
    ctx.stroke();
    ctx.restore();
  } else if (upsideDown.slamFlash > 0 && Number.isFinite(upsideDown.slamX)) {
    // impact frame: leg planted in the ground + dust
    ctx.save();
    const kneeX = upsideDown.slamX + 130;
    ctx.strokeStyle = "#020617";
    ctx.lineWidth = 20;
    ctx.lineCap = "round";
    ctx.beginPath();
    ctx.moveTo(kneeX + 130, -60);
    ctx.lineTo(kneeX, 70);
    ctx.lineTo(upsideDown.slamX, GROUND - 2);
    ctx.stroke();
    ctx.strokeStyle = "#1d0e14";
    ctx.lineWidth = 13;
    ctx.beginPath();
    ctx.moveTo(kneeX + 130, -60);
    ctx.lineTo(kneeX, 70);
    ctx.lineTo(upsideDown.slamX, GROUND - 2);
    ctx.stroke();
    ctx.globalAlpha = upsideDown.slamFlash / 10;
    ctx.fillStyle = "rgba(120, 60, 60, 0.5)";
    ctx.beginPath();
    ctx.ellipse(upsideDown.slamX, GROUND - 4, 54, 14, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
}

// VECNA_PATCH: the arena tint + drifting spores while The Upside Down is
// active - drawn right after the city so it sits behind the fighters.
function drawUpsideDownBackdrop() {
  if (!upsideDown) return;
  const fade = Math.min(1, (VECNA_ULT_TICKS - upsideDown.ticks) / 30, upsideDown.ticks / 40);
  ctx.save();
  ctx.globalAlpha = 0.5 * fade;
  ctx.fillStyle = "#12040c";
  ctx.fillRect(0, 0, STAGE_W, H);
  ctx.globalAlpha = 0.85 * fade;
  // drifting spores
  for (let i = 0; i < 26; i += 1) {
    const seed = i * 137.5;
    const sx = (seed * 7 + frame * (0.2 + (i % 5) * 0.08)) % STAGE_W;
    const sy = (seed * 3.7 + frame * 0.12 + Math.sin(frame * 0.02 + i) * 20) % H;
    ctx.fillStyle = i % 3 === 0 ? "rgba(190, 120, 120, 0.5)" : "rgba(140, 140, 150, 0.35)";
    ctx.beginPath();
    ctx.arc(sx, sy, i % 4 === 0 ? 2.2 : 1.3, 0, Math.PI * 2);
    ctx.fill();
  }
  // vines creeping along the ground line
  ctx.strokeStyle = "rgba(70, 20, 26, 0.9)";
  ctx.lineWidth = 4;
  ctx.lineCap = "round";
  ctx.beginPath();
  for (let x = 0; x < STAGE_W; x += 90) {
    const sway = Math.sin(frame * 0.05 + x) * 6;
    ctx.moveTo(x, GROUND + 2);
    ctx.quadraticCurveTo(x + 24, GROUND - 26 + sway, x + 12 + sway, GROUND - 44);
  }
  ctx.stroke();
  ctx.restore();
}

// ZEALOT_PATCH: warped-in Protoss units - gold/cyan, no faces.
function drawZealotUnits() {
  for (const u of zealotUnits) {
    ctx.save();
    ctx.translate(u.x, u.y);
    const dir = u.owner === "player" ? 1 : -1;
    // warp-in shimmer
    if (u.warpFlash > 0) {
      ctx.globalAlpha = 0.4 + 0.6 * (1 - u.warpFlash / 18);
      ctx.globalCompositeOperation = "lighter";
      ctx.fillStyle = "rgba(45, 212, 191, 0.5)";
      ctx.beginPath();
      ctx.ellipse(0, -12, 20, 30 * (u.warpFlash / 18 + 0.2), 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalCompositeOperation = "source-over";
      ctx.globalAlpha = 1 - u.warpFlash / 22;
    }
    ctx.scale(dir, 1);
    if (u.kind === "zealot") {
      // small gold zealot with cyan blades
      ctx.fillStyle = "#c8a13a"; ctx.strokeStyle = "#020617"; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.roundRect(-11, -26, 22, 26, 5); ctx.fill(); ctx.stroke();
      ctx.strokeStyle = "#0b1420"; ctx.lineWidth = 5; ctx.lineCap = "round";
      ctx.beginPath(); ctx.moveTo(-8, 0); ctx.lineTo(-9, 12); ctx.moveTo(8, 0); ctx.lineTo(9, 12); ctx.stroke();
      // head + nerve cords
      ctx.fillStyle = "#8a6f3a"; ctx.beginPath(); ctx.arc(0, -32, 8, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
      ctx.strokeStyle = "#0b1420"; ctx.lineWidth = 3;
      ctx.beginPath(); ctx.moveTo(-4, -28); ctx.lineTo(-8, -18); ctx.moveTo(4, -28); ctx.lineTo(8, -18); ctx.stroke();
      // psi blades
      ctx.globalCompositeOperation = "lighter";
      ctx.strokeStyle = "rgba(45, 212, 191, 0.9)"; ctx.lineWidth = 3;
      ctx.beginPath(); ctx.moveTo(11, -8); ctx.lineTo(28, -14); ctx.stroke();
      ctx.globalCompositeOperation = "source-over";
    } else if (u.kind === "stalker") {
      // four-legged strider on cyan-jointed legs
      ctx.strokeStyle = "#0b1420"; ctx.lineWidth = 4; ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(-8, -14); ctx.lineTo(-16, 0); ctx.lineTo(-14, 14);
      ctx.moveTo(-2, -14); ctx.lineTo(-6, 2); ctx.lineTo(-4, 14);
      ctx.moveTo(6, -14); ctx.lineTo(10, 2); ctx.lineTo(8, 14);
      ctx.moveTo(10, -14); ctx.lineTo(18, 0); ctx.lineTo(16, 14);
      ctx.stroke();
      ctx.fillStyle = "#5a4a86"; ctx.strokeStyle = "#020617"; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.ellipse(0, -18, 13, 9, 0, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
      ctx.fillStyle = "#2dd4bf"; ctx.beginPath(); ctx.arc(6, -18, 2.4, 0, Math.PI * 2); ctx.fill();
    } else {
      // sentry: floating orb + barrier shimmer
      ctx.fillStyle = "#b98b2e"; ctx.strokeStyle = "#020617"; ctx.lineWidth = 2;
      ctx.beginPath(); ctx.arc(0, -16, 11, 0, Math.PI * 2); ctx.fill(); ctx.stroke();
      ctx.fillStyle = "#2dd4bf"; ctx.beginPath(); ctx.arc(0, -16, 4, 0, Math.PI * 2); ctx.fill();
      ctx.globalCompositeOperation = "lighter";
      ctx.strokeStyle = `rgba(45, 212, 191, ${0.3 + Math.sin(frame * 0.2) * 0.15})`;
      ctx.lineWidth = 3;
      ctx.beginPath(); ctx.arc(0, -14, 22, 0, Math.PI * 2); ctx.stroke();
      ctx.globalCompositeOperation = "source-over";
    }
    ctx.restore();
  }
}

// ZEALOT_PATCH: orbital-strike beams - warning ring, then a blue pillar.
function drawOrbitalBeams() {
  for (const b of orbitalBeams) {
    ctx.save();
    if (!b.struck) {
      const t = 1 - b.warnTicks / 40;
      ctx.globalAlpha = 0.4 + t * 0.4;
      ctx.strokeStyle = "rgba(45, 212, 191, 0.85)";
      ctx.lineWidth = 2.5;
      ctx.beginPath();
      ctx.ellipse(b.x, GROUND - 3, ZEALOT_ORBITAL_RADIUS * (0.5 + t * 0.5), 9, 0, 0, Math.PI * 2);
      ctx.stroke();
      ctx.globalAlpha = 0.3;
      ctx.fillStyle = "rgba(45, 212, 191, 0.5)";
      ctx.fillRect(b.x - 3, 0, 6, GROUND);
    } else if (b.flash > 0) {
      ctx.globalAlpha = b.flash / 14;
      ctx.globalCompositeOperation = "lighter";
      const grad = ctx.createLinearGradient(b.x, 0, b.x, GROUND);
      grad.addColorStop(0, "rgba(224, 255, 255, 0.95)");
      grad.addColorStop(0.5, "rgba(45, 212, 191, 0.9)");
      grad.addColorStop(1, "rgba(13, 148, 136, 0.7)");
      ctx.fillStyle = grad;
      ctx.fillRect(b.x - ZEALOT_ORBITAL_RADIUS * 0.4, 0, ZEALOT_ORBITAL_RADIUS * 0.8, GROUND);
      ctx.fillStyle = "rgba(224, 255, 255, 0.9)";
      ctx.fillRect(b.x - 6, 0, 12, GROUND);
    }
    ctx.restore();
  }
}

// SPIDER_PATCH: floating web mark over a tagged target + cocoon wrap.
function drawSpiderMarks() {
  for (const fighter of [player, enemy]) {
    if (!fighter || fighter.ko) continue;
    if ((fighter.cocoonTicks || 0) > 0) {
      // wrapped in webbing - pale overlay with cross-hatched strands
      const c = getFighterCenter(fighter);
      ctx.save();
      ctx.globalAlpha = 0.5;
      ctx.strokeStyle = "rgba(226, 232, 240, 0.9)";
      ctx.lineWidth = 2;
      for (let i = -2; i <= 2; i += 1) {
        ctx.beginPath();
        ctx.moveTo(fighter.x + 4, fighter.y + 30 + i * 14);
        ctx.lineTo(fighter.x + fighter.w - 4, fighter.y + 40 + i * 14);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(fighter.x + fighter.w - 4, fighter.y + 30 + i * 14);
        ctx.lineTo(fighter.x + 4, fighter.y + 40 + i * 14);
        ctx.stroke();
      }
      ctx.restore();
    }
    if ((fighter.spiderMarkTicks || 0) > 0) {
      const c = getFighterCenter(fighter);
      const y = fighter.y - 14 + Math.sin(frame * 0.15) * 2;
      ctx.save();
      ctx.translate(c.x, y);
      ctx.strokeStyle = "rgba(214, 35, 51, 0.9)";
      ctx.lineWidth = 1.6;
      ctx.beginPath();
      ctx.arc(0, 0, 6, 0, Math.PI * 2);
      ctx.stroke();
      // little spider legs
      ctx.lineWidth = 1.2;
      ctx.beginPath();
      for (let i = 0; i < 4; i += 1) {
        const a = 0.5 + i * 0.4;
        ctx.moveTo(Math.cos(Math.PI - a) * 6, -2);
        ctx.lineTo(Math.cos(Math.PI - a) * 11, -5);
        ctx.moveTo(Math.cos(a) * 6, -2);
        ctx.lineTo(Math.cos(a) * 11, -5);
      }
      ctx.stroke();
      ctx.fillStyle = "rgba(214, 35, 51, 0.9)";
      ctx.beginPath();
      ctx.arc(0, 0, 2.6, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
    }
  }
}

function drawEffects() {
  drawVecnaMinions(); // VECNA_PATCH
  drawZealotUnits(); // ZEALOT_PATCH
  drawOrbitalBeams(); // ZEALOT_PATCH
  drawSpiderMarks(); // SPIDER_PATCH
  drawGroundEraseEffects();
  drawWorldSlashEffects();
  drawUltimateChargeEffects();
  if (player.attacking && !player.hasHit) drawHitboxHint(player);
  if (enemy.attacking && !enemy.hasHit) drawHitboxHint(enemy);
  drawProjectileShadows();
  drawProjectiles();
  drawProjectileDisperses();
  drawFugaExplosions();
  drawTeleportEffects();
  drawHitSparks();
}

function drawGroundEraseEffects() {
  for (const effect of groundEraseEffects) {
    const t = effect.life / effect.maxLife;
    const age = 1 - t;
    ctx.save();
    ctx.globalAlpha = Math.max(0, t);
    ctx.fillStyle = `rgba(2, 6, 23, ${0.76 * t})`;
    ctx.beginPath();
    ctx.ellipse(effect.x, effect.y, effect.radius * (0.45 + age * 0.7), 8 + age * 14, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.strokeStyle = `rgba(168, 85, 247, ${0.62 * t})`;
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(effect.x - effect.radius * (0.55 + age), effect.y - 2);
    ctx.lineTo(effect.x - effect.radius * 0.18, effect.y + 6);
    ctx.lineTo(effect.x + effect.radius * 0.22, effect.y - 5);
    ctx.lineTo(effect.x + effect.radius * (0.6 + age), effect.y + 4);
    ctx.stroke();
    ctx.restore();
  }
}

function drawUltimateChargeEffects() {
  for (const effect of ultimateChargeEffects) {
    const fighter = effect.owner === "player" ? player : enemy;
    if (!fighter) continue;
    const center = getFighterCenter(fighter);
    const t = Math.max(0, effect.life / effect.maxLife);
    const age = 1 - t;
    const pulse = 1 + Math.sin(frame * 0.28) * 0.08;
    ctx.save();
    ctx.translate(center.x, center.y - 8);
    ctx.globalCompositeOperation = "lighter";
    ctx.globalAlpha = 0.7 + 0.25 * t;
    if (effect.kind === "hollowPurple") {
      ctx.strokeStyle = `rgba(125, 211, 252, ${0.68 * t})`;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(-34 + age * 22, -10, 20 * pulse, 0, Math.PI * 2);
      ctx.stroke();
      ctx.strokeStyle = `rgba(248, 113, 113, ${0.68 * t})`;
      ctx.beginPath();
      ctx.arc(34 - age * 22, -10, 20 * pulse, 0, Math.PI * 2);
      ctx.stroke();
      const purpleGlow = ctx.createRadialGradient(0, -10, 1, 0, -10, 56 * pulse);
      purpleGlow.addColorStop(0, `rgba(255, 255, 255, ${0.84 * age})`);
      purpleGlow.addColorStop(0.22, `rgba(216, 180, 254, ${0.74 * age})`);
      purpleGlow.addColorStop(0.62, `rgba(124, 58, 237, ${0.46 * age})`);
      purpleGlow.addColorStop(1, "rgba(76, 29, 149, 0)");
      ctx.fillStyle = purpleGlow;
      ctx.beginPath();
      ctx.arc(0, -10, 56 * pulse, 0, Math.PI * 2);
      ctx.fill();
    } else {
      ctx.strokeStyle = `rgba(2, 6, 23, ${0.92 * t})`;
      ctx.lineWidth = 8;
      for (let i = 0; i < 5; i += 1) {
        const y = -38 + i * 17 + Math.sin(frame * 0.13 + i) * 4;
        ctx.beginPath();
        ctx.moveTo(-78 - age * 16, y);
        ctx.lineTo(78 + age * 20, y - 14);
        ctx.stroke();
      }
      ctx.strokeStyle = `rgba(220, 38, 38, ${0.7 * t})`;
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(-86, -6);
      ctx.lineTo(86, -24);
      ctx.stroke();
    }
    ctx.restore();
  }
}

function drawWorldSlashEffects() {
  for (const effect of worldSlashEffects) {
    const t = effect.life / effect.maxLife;
    const age = 1 - t;
    const crackReady = effect.life < effect.maxLife - effect.splitDelay;
    ctx.save();
    ctx.globalCompositeOperation = "lighter";
    ctx.globalAlpha = Math.max(0, t);
    ctx.lineCap = "round";
    ctx.strokeStyle = `rgba(2, 6, 23, ${0.96 * t})`;
    ctx.lineWidth = crackReady ? 10 : 5;
    ctx.beginPath();
    ctx.moveTo(effect.x1, effect.y1);
    ctx.lineTo(effect.x2, effect.y2);
    ctx.stroke();
    ctx.strokeStyle = `rgba(248, 113, 113, ${0.86 * t})`;
    ctx.lineWidth = crackReady ? 4 : 2;
    ctx.beginPath();
    ctx.moveTo(effect.x1, effect.y1);
    ctx.lineTo(effect.x2, effect.y2);
    ctx.stroke();

    if (crackReady) {
      const dx = effect.x2 - effect.x1;
      const dy = effect.y2 - effect.y1;
      const length = Math.hypot(dx, dy) || 1;
      const nx = -dy / length;
      const ny = dx / length;
      ctx.strokeStyle = `rgba(2, 6, 23, ${0.82 * t})`;
      ctx.lineWidth = 4;
      for (const branch of effect.branches || []) {
        const bx = effect.x1 + dx * branch.t;
        const by = effect.y1 + dy * branch.t;
        const side = Math.sign(branch.offset) || 1;
        ctx.beginPath();
        ctx.moveTo(bx, by);
        ctx.lineTo(bx + nx * branch.length * side, by + ny * branch.length * side + branch.offset * 0.25);
        ctx.stroke();
      }
      ctx.fillStyle = `rgba(127, 29, 29, ${0.13 * t})`;
      ctx.beginPath();
      ctx.rect(Math.min(effect.x1, effect.x2), effect.y1 - 24 - age * 18, Math.abs(effect.x2 - effect.x1), 48 + age * 28);
      ctx.fill();
    }
    ctx.restore();
  }
}

function drawFugaExplosions() {
  for (const effect of fugaExplosions) {
    const t = effect.life / effect.maxLife;
    const age = 1 - t;
    const radius = effect.radius;
    ctx.save();
    ctx.translate(effect.x, effect.y);
    ctx.globalAlpha = Math.max(0, t);
    ctx.globalCompositeOperation = "lighter";

    const glow = ctx.createRadialGradient(0, 0, radius * 0.05, 0, 0, radius * (0.35 + age * 0.72));
    glow.addColorStop(0, `rgba(255, 255, 255, ${0.95 * t})`);
    glow.addColorStop(0.16, `rgba(254, 240, 138, ${0.9 * t})`);
    glow.addColorStop(0.46, `rgba(249, 115, 22, ${0.72 * t})`);
    glow.addColorStop(0.78, `rgba(127, 29, 29, ${0.46 * t})`);
    glow.addColorStop(1, "rgba(2, 6, 23, 0)");
    ctx.fillStyle = glow;
    ctx.beginPath();
    ctx.arc(0, 0, radius * (0.36 + age * 0.7), 0, Math.PI * 2);
    ctx.fill();

    ctx.strokeStyle = `rgba(254, 240, 138, ${0.78 * t})`;
    ctx.lineWidth = 8 * t + 2;
    ctx.beginPath();
    ctx.arc(0, 0, radius * (0.18 + age * 0.62), 0, Math.PI * 2);
    ctx.stroke();

    ctx.strokeStyle = `rgba(2, 6, 23, ${0.78 * t})`;
    ctx.lineWidth = 5 * t + 1;
    for (let i = 0; i < 8; i += 1) {
      const angle = effect.spin + i * Math.PI / 4;
      const wobble = Math.sin(frame * 0.08 + i) * 0.16;
      const inner = radius * (0.16 + age * 0.25);
      const outer = radius * (0.34 + age * 0.68);
      ctx.beginPath();
      ctx.moveTo(Math.cos(angle) * inner, Math.sin(angle) * inner);
      ctx.lineTo(Math.cos(angle + wobble) * outer, Math.sin(angle + wobble) * outer);
      ctx.stroke();
    }

    ctx.globalCompositeOperation = "source-over";
    ctx.fillStyle = `rgba(15, 23, 42, ${0.16 * t})`;
    ctx.beginPath();
    ctx.ellipse(-radius * 0.05, radius * 0.12, radius * (0.24 + age * 0.35), radius * (0.16 + age * 0.28), 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
}

function drawShieldBreakEffects() {
  for (const effect of shieldBreakEffects) {
    const t = effect.life / effect.maxLife;
    const age = 1 - t;
    ctx.save();
    ctx.translate(effect.x, effect.y);
    ctx.globalAlpha = Math.max(0, t);
    ctx.globalCompositeOperation = "lighter";
    ctx.strokeStyle = effect.color;
    ctx.lineWidth = 4 * t + 1;
    ctx.setLineDash([8 + age * 14, 10]);
    ctx.lineDashOffset = -frame * 0.9;
    ctx.beginPath();
    ctx.ellipse(0, 0, 48 + age * 38, 76 + age * 46, 0, 0, Math.PI * 2);
    ctx.stroke();
    ctx.setLineDash([]);

    ctx.strokeStyle = effect.darkColor;
    ctx.lineWidth = 3 * t + 1;
    ctx.lineCap = "round";
    for (let i = 0; i < 10; i += 1) {
      const angle = effect.spin + i * Math.PI * 0.2;
      const innerX = Math.cos(angle) * (26 + age * 24);
      const innerY = Math.sin(angle) * (42 + age * 30);
      const outerX = Math.cos(angle) * (54 + age * 50);
      const outerY = Math.sin(angle) * (82 + age * 54);
      ctx.beginPath();
      ctx.moveTo(innerX, innerY);
      ctx.lineTo(outerX, outerY);
      ctx.stroke();
    }
    ctx.restore();
  }
}

function drawProjectileDisperses() {
  for (const effect of projectileDisperses) {
    const t = effect.life / effect.maxLife;
    const age = 1 - t;
    const radius = effect.radius;
    ctx.save();
    ctx.translate(effect.x, effect.y);
    ctx.globalAlpha = t;
    ctx.lineCap = "round";

    if (effect.move === "purple") {
      const spin = frame * 0.22 + effect.spin;
      ctx.globalCompositeOperation = "lighter";
      ctx.strokeStyle = `rgba(216, 180, 254, ${0.9 * t})`;
      ctx.lineWidth = 7;
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.9 + age * 1.85), spin, spin + Math.PI * (1.2 + age));
      ctx.stroke();
      ctx.strokeStyle = `rgba(56, 189, 248, ${0.62 * t})`;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.55 + age * 1.35), -spin, -spin + Math.PI * 1.4);
      ctx.stroke();
      ctx.strokeStyle = `rgba(248, 113, 113, ${0.58 * t})`;
      for (let i = 0; i < 9; i += 1) {
        const a = spin + i * Math.PI / 4.5;
        ctx.beginPath();
        ctx.moveTo(Math.cos(a) * radius * 0.28, Math.sin(a) * radius * 0.28);
        ctx.lineTo(Math.cos(a) * radius * (1.8 + age), Math.sin(a) * radius * (1.8 + age));
        ctx.stroke();
      }
      ctx.globalCompositeOperation = "source-over";
    } else if (effect.move === "blue") {
      const spin = frame * 0.18 + effect.spin;
      ctx.strokeStyle = `rgba(56, 189, 248, ${0.7 * t})`;
      ctx.lineWidth = 3;
      for (let i = 0; i < 3; i += 1) {
        const r = radius * (0.55 + age * 1.4 + i * 0.32);
        ctx.beginPath();
        ctx.arc(0, 0, r, spin + i * 1.4, spin + i * 1.4 + Math.PI * (0.7 + age));
        ctx.stroke();
      }
      ctx.fillStyle = `rgba(224, 242, 254, ${0.75 * t})`;
      for (let i = 0; i < 5; i += 1) {
        const a = spin + i * Math.PI * 0.42;
        const r = radius * (1.05 + age * 1.2);
        ctx.beginPath();
        ctx.arc(Math.cos(a) * r, Math.sin(a) * r, 2.2 + age * 2, 0, Math.PI * 2);
        ctx.fill();
      }
    } else if (effect.move === "red") {
      ctx.strokeStyle = `rgba(248, 113, 113, ${0.85 * t})`;
      ctx.lineWidth = 5;
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.8 + age * 1.5), 0, Math.PI * 2);
      ctx.stroke();
      ctx.strokeStyle = `rgba(127, 29, 29, ${0.8 * t})`;
      ctx.lineWidth = 3;
      for (let i = 0; i < 8; i += 1) {
        const a = effect.spin + i * Math.PI / 4;
        const inner = radius * (0.3 + age * 0.75);
        const outer = radius * (0.9 + age * 1.65);
        ctx.beginPath();
        ctx.moveTo(Math.cos(a) * inner, Math.sin(a) * inner);
        ctx.lineTo(Math.cos(a) * outer, Math.sin(a) * outer);
        ctx.stroke();
      }
    } else if (effect.move === "ryukStrike") {
      const spin = frame * 0.08 + effect.spin;
      ctx.fillStyle = `rgba(0,0,0,${0.18 * t})`;
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.7 + age * 0.9), 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = `rgba(0,0,0,${0.72 * t})`;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.75 + age * 0.65), spin, spin + Math.PI * 1.45);
      ctx.stroke();
      ctx.fillStyle = `rgba(0,0,0,${0.45 * t})`;
      for (let i = 0; i < 9; i += 1) {
        const a = spin + i * Math.PI * 0.42;
        const r = radius * (0.4 + age * 0.9);
        ctx.beginPath();
        ctx.arc(Math.cos(a) * r, Math.sin(a) * r * 0.6, 4 + (i % 3) * 2, 0, Math.PI * 2);
        ctx.fill();
      }
    } else {
      const effectAngle = Number(effect.angle);
      if (Number.isFinite(effectAngle)) ctx.rotate(effectAngle);
      else ctx.scale(effect.dir, 1);
      ctx.rotate(-0.14);
      ctx.strokeStyle = `rgba(220, 38, 38, ${0.78 * t})`;
      ctx.lineWidth = 4;
      for (let i = 0; i < 5; i += 1) {
        const y = (i - 2) * 7;
        const spread = age * radius * 1.2;
        ctx.beginPath();
        ctx.moveTo(-radius * 1.1 - spread * 0.4, y);
        ctx.lineTo(radius * 1.1 + spread, y - 8 + i * 2);
        ctx.stroke();
      }
      ctx.strokeStyle = `rgba(2, 6, 23, ${0.7 * t})`;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-radius * 1.2 - age * 10, radius * 0.42);
      ctx.lineTo(radius * 1.35 + age * 16, -radius * 0.7);
      ctx.stroke();
    }

    ctx.restore();
  }
}

function drawHitSparks() {
  for (const spark of hitSparks) {
    const t = spark.life / spark.maxLife;
    ctx.save();
    ctx.translate(spark.x, spark.y);
    ctx.globalAlpha = t;
    ctx.strokeStyle = spark.color;
    ctx.lineWidth = spark.kind === "block" ? 3 : 4;
    ctx.lineCap = "round";
    const shrineSpark = spark.kind === "slash" || spark.kind === "cleave";
    const fugaSpark = spark.kind === "fuga";
    const ryukSpark = spark.kind === "ryukStrike";
    if (ryukSpark) {
      ctx.fillStyle = lightBrownRgba("deep", 0.34 * t);
      ctx.beginPath();
      ctx.arc(0, 0, 34 * t + 10, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = lightBrownRgba("dark", 0.92 * t);
      ctx.lineWidth = 5;
      ctx.beginPath();
      ctx.arc(0, 0, 24 * t + 8, 0, Math.PI * 2);
      ctx.stroke();
    } else if (spark.kind === "brown") {
      ctx.globalCompositeOperation = "lighter";
      ctx.fillStyle = lightBrownRgba("dark", 0.36 * t);
      ctx.beginPath();
      ctx.arc(0, 0, 34 * t + 8, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = lightBrownRgba("bright", 0.86 * t);
      ctx.lineWidth = 8;
      ctx.beginPath();
      ctx.moveTo(-spark.dir * 34 * t, 0);
      ctx.lineTo(spark.dir * 40 * t, 0);
      ctx.moveTo(0, -24 * t);
      ctx.lineTo(0, 24 * t);
      ctx.stroke();
      ctx.strokeStyle = lightBrownRgba("cream", 0.9 * t);
      ctx.lineWidth = 3;
    } else if (shrineSpark) {
      ctx.strokeStyle = `rgba(2, 6, 23, ${0.85 * t})`;
      ctx.lineWidth = spark.kind === "cleave" ? 8 : 5;
      ctx.beginPath();
      ctx.moveTo(-spark.dir * 24 * t, -12 * t);
      ctx.lineTo(spark.dir * 24 * t, 12 * t);
      ctx.moveTo(-spark.dir * 18 * t, 14 * t);
      ctx.lineTo(spark.dir * 18 * t, -14 * t);
      ctx.stroke();
      ctx.strokeStyle = `rgba(220, 38, 38, ${0.95 * t})`;
      ctx.lineWidth = spark.kind === "cleave" ? 4 : 3;
    } else if (spark.kind === "blue") {
      ctx.strokeStyle = `rgba(14, 165, 233, ${0.8 * t})`;
      ctx.lineWidth = 3;
      for (let ring = 0; ring < 2; ring += 1) {
        ctx.beginPath();
        ctx.arc(0, 0, (8 + ring * 9) * t, frame * 0.16 + ring, frame * 0.16 + ring + Math.PI * 1.45);
        ctx.stroke();
      }
      ctx.strokeStyle = `rgba(224, 242, 254, ${0.75 * t})`;
      ctx.lineWidth = 2;
    } else if (spark.kind === "red") {
      ctx.globalCompositeOperation = "lighter";
      ctx.fillStyle = `rgba(127, 29, 29, ${0.36 * t})`;
      ctx.beginPath();
      ctx.arc(0, 0, 34 * t + 8, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = `rgba(190, 18, 60, ${0.85 * t})`;
      ctx.lineWidth = 9;
      ctx.beginPath();
      ctx.moveTo(-spark.dir * 38 * t, 0);
      ctx.lineTo(spark.dir * 44 * t, 0);
      ctx.moveTo(0, -28 * t);
      ctx.lineTo(0, 28 * t);
      ctx.stroke();
      ctx.strokeStyle = `rgba(254, 226, 226, ${0.95 * t})`;
      ctx.lineWidth = 3.5;
    } else if (spark.kind === "purple") {
      ctx.globalCompositeOperation = "lighter";
      ctx.fillStyle = `rgba(88, 28, 135, ${0.45 * t})`;
      ctx.beginPath();
      ctx.arc(0, 0, 46 * t + 12, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = `rgba(216, 180, 254, ${0.95 * t})`;
      ctx.lineWidth = 9;
      ctx.beginPath();
      ctx.moveTo(-spark.dir * 48 * t, -14 * t);
      ctx.lineTo(spark.dir * 54 * t, 14 * t);
      ctx.moveTo(-spark.dir * 36 * t, 18 * t);
      ctx.lineTo(spark.dir * 40 * t, -18 * t);
      ctx.stroke();
      ctx.strokeStyle = `rgba(255, 255, 255, ${0.86 * t})`;
      ctx.lineWidth = 3.5;
    } else if (fugaSpark) {
      ctx.strokeStyle = `rgba(249, 115, 22, ${0.92 * t})`;
      ctx.lineWidth = 8;
      ctx.beginPath();
      ctx.moveTo(-spark.dir * 30 * t, 0);
      ctx.lineTo(spark.dir * 34 * t, 0);
      ctx.moveTo(0, -24 * t);
      ctx.lineTo(0, 24 * t);
      ctx.stroke();
      ctx.strokeStyle = `rgba(254, 240, 138, ${0.9 * t})`;
      ctx.lineWidth = 3;
    }
    for (let i = 0; i < (ryukSpark ? 0 : spark.kind === "brown" || shrineSpark || fugaSpark ? 10 : 7); i += 1) {
      const angle = (Math.PI * 2 / 7) * i + spark.dir * 0.2;
      const inner = 4 + (1 - t) * 5;
      const outer = (spark.kind === "brown" ? 34 : spark.kind === "fuga" ? 36 : spark.kind === "cleave" ? 32 : spark.kind === "heavy" || spark.kind === "slash" ? 23 : 16) * t + 5;
      ctx.beginPath();
      ctx.moveTo(Math.cos(angle) * inner, Math.sin(angle) * inner);
      ctx.lineTo(Math.cos(angle) * outer, Math.sin(angle) * outer);
      ctx.stroke();
    }
    ctx.fillStyle = ryukSpark ? lightBrownRgba("deep", 0.86 * t) : spark.kind === "brown" ? lightBrownRgba("cream", 0.92 * t) : shrineSpark ? `rgba(127, 29, 29, ${0.8 * t})` : fugaSpark ? `rgba(254, 240, 138, ${0.9 * t})` : "rgba(255, 255, 255, 0.85)";
    ctx.beginPath();
    ctx.arc(0, 0, 3 + 4 * t, 0, Math.PI * 2);
    ctx.fill();
    ctx.restore();
  }
}

function drawLimitlessOrb(move, radius, dir = 1) {
  ctx.save();
  if (move === "red") {
    ctx.scale(dir, 1);
    const pulse = 1 + Math.sin(frame * 0.34) * 0.08;
    const redGlow = ctx.createRadialGradient(0, 0, radius * 0.15, 0, 0, radius * 1.75 * pulse);
    redGlow.addColorStop(0, "rgba(255, 255, 255, 0.95)");
    redGlow.addColorStop(0.18, "rgba(254, 202, 202, 0.95)");
    redGlow.addColorStop(0.48, "rgba(239, 68, 68, 0.82)");
    redGlow.addColorStop(1, "rgba(127, 29, 29, 0)");
    ctx.fillStyle = redGlow;
    ctx.beginPath();
    ctx.ellipse(0, 0, radius * 1.75 * pulse, radius * 1.35 * pulse, 0, 0, Math.PI * 2);
    ctx.fill();

    ctx.fillStyle = "rgba(248, 113, 113, 0.92)";
    ctx.beginPath();
    ctx.ellipse(0, 0, radius * 0.88, radius * 0.72, 0, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = "rgba(255, 255, 255, 0.88)";
    ctx.beginPath();
    ctx.ellipse(radius * 0.18, -radius * 0.12, radius * 0.34, radius * 0.24, 0, 0, Math.PI * 2);
    ctx.fill();

    ctx.strokeStyle = "rgba(127, 29, 29, 0.72)";
    ctx.lineWidth = 5;
    ctx.lineCap = "round";
    ctx.beginPath();
    ctx.moveTo(-radius * 1.55, -radius * 0.42);
    ctx.lineTo(-radius * 0.35, -radius * 0.16);
    ctx.moveTo(-radius * 1.35, radius * 0.48);
    ctx.lineTo(-radius * 0.24, radius * 0.22);
    ctx.stroke();

    ctx.strokeStyle = "rgba(254, 226, 226, 0.95)";
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.arc(0, 0, radius * 1.02, frame * 0.18, frame * 0.18 + Math.PI * 1.15);
    ctx.stroke();
  } else if (move === "blue") {
    const spin = frame * 0.16;
    const pulse = 1 + Math.sin(frame * 0.22) * 0.06;
    const blueGlow = ctx.createRadialGradient(0, 0, 1, 0, 0, radius * 1.8 * pulse);
    blueGlow.addColorStop(0, "rgba(2, 6, 23, 0.95)");
    blueGlow.addColorStop(0.28, "rgba(29, 78, 216, 0.92)");
    blueGlow.addColorStop(0.6, "rgba(56, 189, 248, 0.72)");
    blueGlow.addColorStop(1, "rgba(56, 189, 248, 0)");
    ctx.fillStyle = blueGlow;
    ctx.beginPath();
    ctx.arc(0, 0, radius * 1.8 * pulse, 0, Math.PI * 2);
    ctx.fill();

    ctx.fillStyle = "rgba(15, 23, 42, 0.92)";
    ctx.beginPath();
    ctx.arc(0, 0, radius * 0.52, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = "rgba(224, 242, 254, 0.9)";
    ctx.beginPath();
    ctx.arc(-radius * 0.15, -radius * 0.12, radius * 0.2, 0, Math.PI * 2);
    ctx.fill();

    ctx.strokeStyle = "rgba(186, 230, 253, 0.9)";
    ctx.lineWidth = 3;
    ctx.lineCap = "round";
    for (let i = 0; i < 3; i += 1) {
      ctx.beginPath();
      ctx.arc(0, 0, radius * (0.82 + i * 0.28), spin + i * 1.8, spin + i * 1.8 + Math.PI * 1.25);
      ctx.stroke();
    }
    ctx.strokeStyle = "rgba(14, 165, 233, 0.65)";
    ctx.lineWidth = 2;
    for (let i = 0; i < 6; i += 1) {
      const a = spin + i * Math.PI / 3;
      ctx.beginPath();
      ctx.moveTo(Math.cos(a) * radius * 1.05, Math.sin(a) * radius * 1.05);
      ctx.lineTo(Math.cos(a + 0.42) * radius * 1.55, Math.sin(a + 0.42) * radius * 1.55);
      ctx.stroke();
    }
    ctx.strokeStyle = "rgba(224, 242, 254, 0.78)";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.arc(0, 0, radius + 6, spin, spin + Math.PI * 1.5);
    ctx.stroke();
  }
  ctx.restore();
}

function drawShrineTechniqueShape(move, radius) {
  ctx.save();
  ctx.rotate(move === "cleave" ? -0.18 : -0.1);
  if (move === "slash") {
    ctx.fillStyle = "rgba(2, 6, 23, 0.95)";
    ctx.beginPath();
    ctx.moveTo(-radius * 1.4, -radius * 0.32);
    ctx.lineTo(radius * 1.65, -radius * 0.95);
    ctx.lineTo(radius * 1.35, -radius * 0.25);
    ctx.lineTo(radius * 1.8, radius * 0.12);
    ctx.lineTo(-radius * 1.2, radius * 0.68);
    ctx.lineTo(-radius * 0.75, radius * 0.08);
    ctx.closePath();
    ctx.fill();
    ctx.fillStyle = "rgba(220, 38, 38, 0.95)";
    ctx.beginPath();
    ctx.moveTo(-radius * 1.1, -radius * 0.2);
    ctx.lineTo(radius * 1.25, -radius * 0.62);
    ctx.lineTo(radius * 0.95, -radius * 0.15);
    ctx.lineTo(radius * 1.38, radius * 0.1);
    ctx.lineTo(-radius * 0.95, radius * 0.48);
    ctx.lineTo(-radius * 0.55, radius * 0.05);
    ctx.closePath();
    ctx.fill();
    ctx.strokeStyle = "rgba(15, 23, 42, 0.95)";
    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(-radius * 1.2, radius * 0.45);
    ctx.lineTo(radius * 1.45, -radius * 0.72);
    ctx.stroke();
  } else {
    ctx.fillStyle = "rgba(2, 6, 23, 0.92)";
    ctx.beginPath();
    ctx.moveTo(-radius * 0.7, -radius * 0.85);
    ctx.lineTo(radius * 1.35, -radius * 1.25);
    ctx.lineTo(radius * 0.72, -radius * 0.12);
    ctx.lineTo(radius * 1.45, radius * 0.62);
    ctx.lineTo(-radius * 0.75, radius * 1.1);
    ctx.lineTo(-radius * 0.2, radius * 0.08);
    ctx.closePath();
    ctx.fill();
    ctx.fillStyle = "rgba(220, 38, 38, 0.9)";
    ctx.beginPath();
    ctx.moveTo(-radius * 0.35, -radius * 0.55);
    ctx.lineTo(radius * 0.9, -radius * 0.82);
    ctx.lineTo(radius * 0.42, -radius * 0.05);
    ctx.lineTo(radius * 0.95, radius * 0.42);
    ctx.lineTo(-radius * 0.35, radius * 0.7);
    ctx.lineTo(0, radius * 0.02);
    ctx.closePath();
    ctx.fill();
    ctx.strokeStyle = "rgba(127, 29, 29, 0.95)";
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.moveTo(-radius * 0.8, radius * 0.95);
    ctx.lineTo(radius * 1.25, -radius * 1.1);
    ctx.moveTo(-radius * 0.6, -radius * 0.75);
    ctx.lineTo(radius * 1.28, radius * 0.58);
    ctx.stroke();
  }
  ctx.restore();
}

function getAimPreviewDistance(move, spec, chargeRatio, aimVector, attacker = null, radius = spec.radius) {
  const aimLimit = Number.isFinite(aimVector?.distance) ? Math.max(8, aimVector.distance) : Infinity;
  const usesExactMouseEnd = move === "cleave" || move === "fuga";
  const domainSlashBoost = attacker && isDomainOwner(attacker, "malevolentShrine");

  const maxDistance = move === "cleave"
    ? domainSlashBoost ? 178 : 118
    : Math.max(120, spec.speed * (spec.life + (move === "blue" || move === "red" ? Math.round(chargeRatio * 10) : 0) + (domainSlashBoost && move === "slash" ? 34 : 0)));

  const target = attacker === player ? enemy : attacker === enemy ? player : null;

  if (usesExactMouseEnd) {
    const distances = [Math.min(maxDistance, aimLimit)];
    if (target && !target.ko) {
      const targetRadius = move === "cleave" ? Math.max(20, spec.radius * 0.55) : radius;
      distances.push(getRayRectHitDistance(aimVector, maxDistance, targetRadius, target));
    }
    return Math.max(8, Math.min(...distances.filter((distance) => Number.isFinite(distance) && distance > 0)));
  }

  // Blue, Red, Dismantle, Hollow Purple, World Slash, and other ranged moves aim toward the mouse
  // but do NOT stop at the mouse. They keep traveling until their own range/lifetime ends.
  const chargedLife = spec.life + (move === "blue" || move === "red" ? Math.round(chargeRatio * 10) : 0) + (domainSlashBoost && move === "slash" ? 34 : 0);
  const fullTravel = Math.max(120, spec.speed * chargedLife);
  const distances = [fullTravel];

  distances.push(
    aimVector.x > 0.001 ? (STAGE_W - radius - aimVector.origin.x) / aimVector.x : Infinity,
    aimVector.x < -0.001 ? (radius - aimVector.origin.x) / aimVector.x : Infinity,
    aimVector.y > 0.001 ? (GROUND - radius - aimVector.origin.y) / aimVector.y : Infinity,
    aimVector.y < -0.001 ? (radius - aimVector.origin.y) / aimVector.y : Infinity
  );

  return Math.max(8, Math.min(...distances.filter((distance) => Number.isFinite(distance) && distance > 0)));
}

function drawTechniqueAimPreview(f) {
  const move = getTechniqueMoveKey(f, f.chargingTechnique);
  const spec = techniqueMoves[move];
  if (!spec) return;
  const chargeRatio = getTechniqueChargeRatio(f);
  const showOnlyChargeOrb = f !== getActiveMouseTechniqueFighter();
  const aimVector = getTechniqueAimVector(f, move, f.techniqueAim);
  const radiusScale = f.technique === "limitless" ? 1 + chargeRatio * (move === "red" ? 0.95 : 0.85) : 1;
  const radius = spec.radius * radiusScale;

  if (move === "blue" || move === "red") {
    const chargeDistance = 38 + chargeRatio * 12;
    ctx.save();
    ctx.translate(
      aimVector.origin.x + aimVector.x * chargeDistance,
      aimVector.origin.y + aimVector.y * chargeDistance
    );
    drawLimitlessOrb(move, radius, aimVector.dir);
    ctx.restore();
  }

  if (showOnlyChargeOrb) return;

  const previewDistance = getAimPreviewDistance(move, spec, chargeRatio, aimVector, f, radius);
  let ghostX = aimVector.origin.x + aimVector.x * previewDistance;
  let ghostY = aimVector.origin.y + aimVector.y * previewDistance;
  if (move === "ryukStrike") {
    const targetPoint = sanitizeAimPoint(f.techniqueAim) || sanitizeAimPoint(mouseAimWorld);
    if (targetPoint) {
      ghostX = Math.max(40, Math.min(STAGE_W - 40, targetPoint.x));
      ghostY = Math.max(70, Math.min(GROUND - 60, targetPoint.y));
    }
  }

  if (move === "ryukStrike") {
    ctx.save();
    ctx.globalAlpha = 0.58;
    ctx.fillStyle = "rgba(0, 0, 0, 0.28)";
    ctx.strokeStyle = "rgba(0, 0, 0, 0.88)";
    ctx.lineWidth = 4;
    ctx.setLineDash([10, 8]);
    ctx.beginPath();
    ctx.arc(ghostX, ghostY, radius, 0, Math.PI * 2);
    ctx.fill();
    ctx.stroke();
    ctx.setLineDash([]);
    ctx.fillStyle = "rgba(245, 245, 244, 0.78)";
    ctx.font = "900 12px system-ui, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("RYUK", ghostX, ghostY + 4);
    ctx.restore();
    return;
  }

  ctx.save();
  ctx.globalAlpha = 0.5;
  ctx.strokeStyle = move === "blue" ? "#7dd3fc" : move === "red" ? "#fecaca" : "#fca5a5";
  ctx.lineWidth = move === "cleave" ? 5 : 3;
  ctx.lineCap = "round";
  if (move === "blue" || move === "red") ctx.setLineDash([12, 9]);
  ctx.beginPath();
  ctx.moveTo(aimVector.origin.x, aimVector.origin.y);
  ctx.lineTo(ghostX, ghostY);
  ctx.stroke();
  ctx.setLineDash([]);

  ctx.translate(ghostX, ghostY);
  if (move === "blue" || move === "red") {
    drawLimitlessOrb(move, radius, aimVector.dir);
  } else {
    ctx.rotate(aimVector.angle);
    drawShrineTechniqueShape(move, radius);
  }
  ctx.restore();
}

function drawProjectiles() {
  for (const p of projectiles) {
    ctx.save();
    ctx.translate(p.x, p.y);
    const projectileAngle = Number(p.angle);
    const hasProjectileAngle = Number.isFinite(projectileAngle);
    if (p.move === "purple") {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);
      const pulse = 1 + Math.sin(frame * 0.22) * 0.05;
      ctx.globalCompositeOperation = "lighter";
      const glow = ctx.createRadialGradient(0, 0, p.radius * 0.12, 0, 0, p.radius * 2.35 * pulse);
      glow.addColorStop(0, "rgba(255, 255, 255, 0.98)");
      glow.addColorStop(0.18, "rgba(216, 180, 254, 0.95)");
      glow.addColorStop(0.46, "rgba(124, 58, 237, 0.84)");
      glow.addColorStop(0.82, "rgba(37, 99, 235, 0.38)");
      glow.addColorStop(1, "rgba(2, 6, 23, 0)");
      ctx.fillStyle = glow;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 2.18 * pulse, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = "rgba(255, 255, 255, 0.92)";
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 0.52, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(109, 40, 217, 0.96)";
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 0.84, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(224, 242, 254, 0.9)";
      ctx.beginPath();
      ctx.arc(p.radius * 0.18, -p.radius * 0.18, p.radius * 0.22, 0, Math.PI * 2);
      ctx.fill();

      ctx.strokeStyle = "rgba(248, 113, 113, 0.88)";
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 1.06, frame * 0.19, frame * 0.19 + Math.PI * 1.35);
      ctx.stroke();
      ctx.strokeStyle = "rgba(56, 189, 248, 0.88)";
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 1.34, -frame * 0.14, -frame * 0.14 + Math.PI * 1.25);
      ctx.stroke();
      ctx.strokeStyle = "rgba(216, 180, 254, 0.62)";
      ctx.lineWidth = 9;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 3.4, 0);
      ctx.lineTo(-p.radius * 1.1, 0);
      ctx.stroke();
      ctx.globalCompositeOperation = "source-over";
    } else if (p.move === "worldSlash") {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);

      // PURPLE_WCS_BUFF_PATCH
      // World Cutting Slash: a wide white space wound with a black void core
      // and red cursed-energy fractures.
      const pulse = 1 + Math.sin(frame * 0.32) * 0.055;
      const slashLength = p.radius * 4.8;
      const slashHeight = p.radius * 0.82 * pulse;
      ctx.lineCap = "round";
      ctx.lineJoin = "round";

      ctx.globalCompositeOperation = "lighter";
      ctx.globalAlpha = 0.9;

      // red cursed glow behind the cut
      ctx.strokeStyle = "rgba(239, 68, 68, 0.36)";
      ctx.lineWidth = p.radius * 0.82;
      ctx.beginPath();
      ctx.moveTo(-slashLength * 0.72, slashHeight * 0.28);
      ctx.bezierCurveTo(-slashLength * 0.25, -slashHeight * 0.8, slashLength * 0.25, slashHeight * 0.72, slashLength * 0.82, -slashHeight * 0.2);
      ctx.stroke();

      // bright white outer tear
      ctx.strokeStyle = "rgba(255,255,255,0.98)";
      ctx.lineWidth = p.radius * 0.38;
      ctx.beginPath();
      ctx.moveTo(-slashLength * 0.85, slashHeight * 0.18);
      ctx.bezierCurveTo(-slashLength * 0.28, -slashHeight * 0.52, slashLength * 0.25, slashHeight * 0.5, slashLength * 0.92, -slashHeight * 0.12);
      ctx.stroke();

      // black void core
      ctx.globalCompositeOperation = "source-over";
      ctx.strokeStyle = "rgba(0,0,0,0.96)";
      ctx.lineWidth = p.radius * 0.24;
      ctx.beginPath();
      ctx.moveTo(-slashLength * 0.8, slashHeight * 0.17);
      ctx.bezierCurveTo(-slashLength * 0.25, -slashHeight * 0.42, slashLength * 0.22, slashHeight * 0.38, slashLength * 0.84, -slashHeight * 0.1);
      ctx.stroke();

      // razor center line
      ctx.globalCompositeOperation = "lighter";
      ctx.strokeStyle = "rgba(255,255,255,0.92)";
      ctx.lineWidth = 2.8;
      ctx.beginPath();
      ctx.moveTo(-slashLength * 0.95, slashHeight * 0.06);
      ctx.lineTo(slashLength * 0.95, -slashHeight * 0.04);
      ctx.stroke();

      // parallel fracture lines
      ctx.strokeStyle = "rgba(255,255,255,0.55)";
      ctx.lineWidth = 2;
      for (let i = 0; i < 4; i += 1) {
        const off = (i - 1.5) * p.radius * 0.22;
        ctx.beginPath();
        ctx.moveTo(-slashLength * (0.55 + i * 0.05), off + slashHeight * 0.34);
        ctx.lineTo(slashLength * (0.45 + i * 0.08), off - slashHeight * 0.28);
        ctx.stroke();
      }

      // dark trailing tears
      ctx.globalCompositeOperation = "source-over";
      ctx.strokeStyle = "rgba(0,0,0,0.75)";
      ctx.lineWidth = 5;
      ctx.beginPath();
      ctx.moveTo(-slashLength * 1.05, slashHeight * 0.34);
      ctx.lineTo(-slashLength * 0.5, slashHeight * 0.22);
      ctx.moveTo(-slashLength * 0.9, -slashHeight * 0.24);
      ctx.lineTo(-slashLength * 0.38, -slashHeight * 0.16);
      ctx.stroke();

      ctx.globalCompositeOperation = "source-over";
      ctx.globalAlpha = 1;
    } else if (p.move === "ryukStrike") {
      const age = p.visualSpawnAge || 0;
      const maxLife = p.maxLife || 34;
      const startupTotal = Math.max(1, p.startupMax || ((p.startup || 0) + age));
      const impactAge = Math.max(0, age - startupTotal);
      const vanishRatio = Math.max(0, Math.min(1, (maxLife - age) / Math.max(1, maxLife * 0.35)));
      const summonRatio = Math.max(0, Math.min(1, age / Math.max(1, startupTotal)));
      const impactRatio = Math.max(0, Math.min(1, impactAge / 9));
      const pulse = 1 + Math.sin(frame * 0.32) * 0.035;
      if ((p.startup || 0) > 0) {
        const charge = summonRatio;
        ctx.globalCompositeOperation = "lighter";
        ctx.fillStyle = `rgba(0,0,0,${0.16 + charge * 0.18})`;
        ctx.strokeStyle = `rgba(0,0,0,${0.58 + charge * 0.28})`;
        ctx.lineWidth = 4;
        ctx.setLineDash([12, 10]);
        ctx.beginPath();
        ctx.arc(0, 0, p.radius, 0, Math.PI * 2);
        ctx.fill();
        ctx.stroke();
        ctx.setLineDash([]);

        ctx.globalCompositeOperation = "source-over";
        drawDeathNoteCharacterModel("ryuk", 0, -p.radius * (0.48 - charge * 0.17), Math.max(0.82, p.radius / 76), {
          alpha: 0.18 + charge * 0.62
        });

        ctx.globalAlpha = 0.32 + charge * 0.38;
        ctx.fillStyle = "rgba(0,0,0,0.75)";
        for (let i = 0; i < 8; i += 1) {
          const a = frame * 0.045 + i * 0.82;
          ctx.beginPath();
          ctx.arc(Math.cos(a) * p.radius * (0.55 + charge * 0.2), Math.sin(a) * p.radius * 0.32 - p.radius * 0.12, 5 + (i % 3) * 2, 0, Math.PI * 2);
          ctx.fill();
        }
        ctx.restore();
        continue;
      }

      ctx.globalAlpha = vanishRatio;
      ctx.globalCompositeOperation = "source-over";
      const smokeHalo = ctx.createRadialGradient(0, 0, p.radius * 0.1, 0, 0, p.radius * 1.45);
      smokeHalo.addColorStop(0, lightBrownRgba("cream", 0.18));
      smokeHalo.addColorStop(0.3, lightBrownRgba("dark", 0.34));
      smokeHalo.addColorStop(1, "rgba(0,0,0,0)");
      ctx.fillStyle = smokeHalo;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 1.35, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(0,0,0,0.24)";
      ctx.beginPath();
      ctx.arc(0, 0, p.radius, 0, Math.PI * 2);
      ctx.fill();
      ctx.strokeStyle = "rgba(0,0,0,0.9)";
      ctx.lineWidth = 5;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * pulse, 0, Math.PI * 2);
      ctx.stroke();

      const ryukY = -p.radius * (1.72 - impactRatio * 0.22);
      drawDeathNoteCharacterModel("ryuk", 0, ryukY + p.radius * 1.04, Math.max(0.96, p.radius / 68), {
        alpha: 1,
        pose: "punch",
        punch: impactRatio
      });

      // Rounded black arrow: blunt head, thick shaft, and no slash/cleave styling.
      const arrowDrop = 1 - Math.pow(1 - impactRatio, 3);
      const startY = ryukY + p.radius * 0.46 + arrowDrop * p.radius * 0.58;
      const endY = -p.radius * 0.12 + arrowDrop * p.radius * 0.36;
      ctx.strokeStyle = lightBrownRgba("deep", 0.96);
      ctx.lineWidth = Math.max(12, p.radius * 0.18);
      ctx.lineCap = "round";
      ctx.lineJoin = "round";
      ctx.beginPath();
      ctx.moveTo(0, startY);
      ctx.lineTo(0, endY);
      ctx.stroke();
      ctx.fillStyle = lightBrownRgba("dark", 0.98);
      ctx.beginPath();
      ctx.roundRect(-p.radius * 0.22, endY - p.radius * 0.08, p.radius * 0.44, p.radius * 0.28, p.radius * 0.12);
      ctx.fill();

      ctx.fillStyle = `rgba(0,0,0,${0.38 * vanishRatio})`;
      for (let i = 0; i < 10; i += 1) {
        const a = frame * 0.05 + i * 0.72;
        ctx.beginPath();
        ctx.arc(Math.cos(a) * p.radius * 0.78, Math.sin(a) * p.radius * 0.42, 4 + (i % 3) * 2, 0, Math.PI * 2);
        ctx.fill();
      }
    } else if (p.move === "red") {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);
      const visualGrow = Math.min(1, ((p.visualSpawnAge || 1) / 10));
      const visualScale = 0.12 + (1 - Math.pow(1 - visualGrow, 3)) * 0.88; // VISUAL_RED_GROW_PATCH
      ctx.scale(visualScale, visualScale);
      const pulse = 1 + Math.sin(frame * 0.34) * 0.08;
      const redGlow = ctx.createRadialGradient(0, 0, p.radius * 0.15, 0, 0, p.radius * 1.75 * pulse);
      redGlow.addColorStop(0, "rgba(255, 255, 255, 0.95)");
      redGlow.addColorStop(0.18, "rgba(254, 202, 202, 0.95)");
      redGlow.addColorStop(0.48, "rgba(239, 68, 68, 0.82)");
      redGlow.addColorStop(1, "rgba(127, 29, 29, 0)");
      ctx.fillStyle = redGlow;
      ctx.beginPath();
      ctx.ellipse(0, 0, p.radius * 1.75 * pulse, p.radius * 1.35 * pulse, 0, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = "rgba(248, 113, 113, 0.92)";
      ctx.beginPath();
      ctx.ellipse(0, 0, p.radius * 0.88, p.radius * 0.72, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(255, 255, 255, 0.88)";
      ctx.beginPath();
      ctx.ellipse(p.radius * 0.18, -p.radius * 0.12, p.radius * 0.34, p.radius * 0.24, 0, 0, Math.PI * 2);
      ctx.fill();

      ctx.strokeStyle = "rgba(127, 29, 29, 0.72)";
      ctx.lineWidth = 5;
      ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.55, -p.radius * 0.42);
      ctx.lineTo(-p.radius * 0.35, -p.radius * 0.16);
      ctx.moveTo(-p.radius * 1.35, p.radius * 0.48);
      ctx.lineTo(-p.radius * 0.24, p.radius * 0.22);
      ctx.stroke();

      ctx.strokeStyle = "rgba(254, 226, 226, 0.95)";
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 1.02, frame * 0.18, frame * 0.18 + Math.PI * 1.15);
      ctx.stroke();
    } else if (p.move === "blue") {
      const visualGrow = Math.min(1, ((p.visualSpawnAge || 1) / 10));
      const visualScale = 0.12 + (1 - Math.pow(1 - visualGrow, 3)) * 0.88; // VISUAL_BLUE_GROW_PATCH
      ctx.scale(visualScale, visualScale);
      const spin = frame * 0.16;
      const pulse = 1 + Math.sin(frame * 0.22) * 0.06;
      const blueGlow = ctx.createRadialGradient(0, 0, 1, 0, 0, p.radius * 1.8 * pulse);
      blueGlow.addColorStop(0, "rgba(2, 6, 23, 0.95)");
      blueGlow.addColorStop(0.28, "rgba(29, 78, 216, 0.92)");
      blueGlow.addColorStop(0.6, "rgba(56, 189, 248, 0.72)");
      blueGlow.addColorStop(1, "rgba(56, 189, 248, 0)");
      ctx.fillStyle = blueGlow;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 1.8 * pulse, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = "rgba(15, 23, 42, 0.92)";
      ctx.beginPath();
      ctx.arc(0, 0, p.radius * 0.52, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(224, 242, 254, 0.9)";
      ctx.beginPath();
      ctx.arc(-p.radius * 0.15, -p.radius * 0.12, p.radius * 0.2, 0, Math.PI * 2);
      ctx.fill();

      ctx.strokeStyle = "rgba(186, 230, 253, 0.9)";
      ctx.lineWidth = 3;
      ctx.lineCap = "round";
      for (let i = 0; i < 3; i += 1) {
        ctx.beginPath();
        ctx.arc(0, 0, p.radius * (0.82 + i * 0.28), spin + i * 1.8, spin + i * 1.8 + Math.PI * 1.25);
        ctx.stroke();
      }
      ctx.strokeStyle = "rgba(14, 165, 233, 0.65)";
      ctx.lineWidth = 2;
      for (let i = 0; i < 6; i += 1) {
        const a = spin + i * Math.PI / 3;
        ctx.beginPath();
        ctx.moveTo(Math.cos(a) * p.radius * 1.05, Math.sin(a) * p.radius * 1.05);
        ctx.lineTo(Math.cos(a + 0.42) * p.radius * 1.55, Math.sin(a + 0.42) * p.radius * 1.55);
        ctx.stroke();
      }
      ctx.strokeStyle = "rgba(224, 242, 254, 0.78)";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.arc(0, 0, p.radius + 6, spin, spin + Math.PI * 1.5);
      ctx.stroke();
    } else if (p.move === "fuga") {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);
      const pulse = 1 + Math.sin(frame * 0.36) * 0.08;
      const flameGlow = ctx.createRadialGradient(-p.radius * 0.5, 0, 1, -p.radius * 0.2, 0, p.radius * 2.9 * pulse);
      flameGlow.addColorStop(0, "rgba(255, 255, 255, 0.95)");
      flameGlow.addColorStop(0.2, "rgba(254, 240, 138, 0.92)");
      flameGlow.addColorStop(0.48, "rgba(249, 115, 22, 0.82)");
      flameGlow.addColorStop(1, "rgba(127, 29, 29, 0)");
      ctx.fillStyle = flameGlow;
      ctx.beginPath();
      ctx.ellipse(-p.radius * 0.25, 0, p.radius * 2.75 * pulse, p.radius * 0.95 * pulse, 0, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = "rgba(2, 6, 23, 0.92)";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.85, -p.radius * 0.18);
      ctx.lineTo(p.radius * 1.06, -p.radius * 0.18);
      ctx.lineTo(p.radius * 1.86, 0);
      ctx.lineTo(p.radius * 1.06, p.radius * 0.18);
      ctx.lineTo(-p.radius * 1.85, p.radius * 0.18);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = "rgba(185, 28, 28, 0.96)";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.25, -p.radius * 0.09);
      ctx.lineTo(p.radius * 1.02, -p.radius * 0.09);
      ctx.lineTo(p.radius * 1.55, 0);
      ctx.lineTo(p.radius * 1.02, p.radius * 0.09);
      ctx.lineTo(-p.radius * 1.25, p.radius * 0.09);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = "rgba(2, 6, 23, 0.96)";
      ctx.beginPath();
      ctx.moveTo(p.radius * 0.72, -p.radius * 0.58);
      ctx.lineTo(p.radius * 2.12, 0);
      ctx.lineTo(p.radius * 0.72, p.radius * 0.58);
      ctx.lineTo(p.radius * 1.02, 0);
      ctx.closePath();
      ctx.fill();

      ctx.fillStyle = "rgba(254, 240, 138, 0.95)";
      ctx.beginPath();
      ctx.moveTo(p.radius * 0.88, -p.radius * 0.28);
      ctx.lineTo(p.radius * 1.72, 0);
      ctx.lineTo(p.radius * 0.88, p.radius * 0.28);
      ctx.lineTo(p.radius * 1.08, 0);
      ctx.closePath();
      ctx.fill();

      ctx.strokeStyle = "rgba(254, 240, 138, 0.92)";
      ctx.lineWidth = 3;
      ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.62, 0);
      ctx.lineTo(p.radius * 1.2, 0);
      ctx.stroke();

      ctx.strokeStyle = "rgba(2, 6, 23, 0.82)";
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.65, -p.radius * 0.52);
      ctx.lineTo(-p.radius * 0.92, 0);
      ctx.lineTo(-p.radius * 1.65, p.radius * 0.52);
      ctx.moveTo(-p.radius * 1.28, -p.radius * 0.44);
      ctx.lineTo(-p.radius * 0.62, 0);
      ctx.lineTo(-p.radius * 1.28, p.radius * 0.44);
      ctx.stroke();

      ctx.fillStyle = "rgba(254, 240, 138, 0.9)";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 2.0, -p.radius * 0.48);
      ctx.quadraticCurveTo(-p.radius * 2.75, 0, -p.radius * 2.0, p.radius * 0.5);
      ctx.quadraticCurveTo(-p.radius * 1.48, 0, -p.radius * 2.0, -p.radius * 0.48);
      ctx.fill();

      ctx.strokeStyle = "rgba(127, 29, 29, 0.92)";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.2, -p.radius * 0.28);
      ctx.lineTo(p.radius * 1.25, -p.radius * 0.08);
      ctx.moveTo(-p.radius * 1.2, p.radius * 0.28);
      ctx.lineTo(p.radius * 1.25, p.radius * 0.08);
      ctx.stroke();
    } else if (p.move === "slash") {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);
      ctx.rotate(-0.1);
      ctx.fillStyle = "rgba(2, 6, 23, 0.95)";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.4, -p.radius * 0.32);
      ctx.lineTo(p.radius * 1.65, -p.radius * 0.95);
      ctx.lineTo(p.radius * 1.35, -p.radius * 0.25);
      ctx.lineTo(p.radius * 1.8, p.radius * 0.12);
      ctx.lineTo(-p.radius * 1.2, p.radius * 0.68);
      ctx.lineTo(-p.radius * 0.75, p.radius * 0.08);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = "rgba(220, 38, 38, 0.95)";
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.1, -p.radius * 0.2);
      ctx.lineTo(p.radius * 1.25, -p.radius * 0.62);
      ctx.lineTo(p.radius * 0.95, -p.radius * 0.15);
      ctx.lineTo(p.radius * 1.38, p.radius * 0.1);
      ctx.lineTo(-p.radius * 0.95, p.radius * 0.48);
      ctx.lineTo(-p.radius * 0.55, p.radius * 0.05);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = "rgba(15, 23, 42, 0.95)";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.2, p.radius * 0.45);
      ctx.lineTo(p.radius * 1.45, -p.radius * 0.72);
      ctx.stroke();
    } else if (p.move === "groundBreak") {
      // THRAGG_THEME_PATCH: Ground Break had no draw case and fell into
      // the generic fallback, which renders the red Sukuna-style slash -
      // that's why it kept reading as "Dismantle". It's now a white
      // Viltrumite shockwave: dust ring + jagged white spikes.
      ctx.scale(p.dir, 1);
      const gt = Math.max(0.3, p.life / Math.max(1, p.maxLife || 46));
      ctx.fillStyle = `rgba(148, 163, 184, ${0.3 * gt})`;
      ctx.beginPath();
      ctx.ellipse(0, p.radius * 0.35, p.radius * 1.5, p.radius * 0.5, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = `rgba(248, 250, 252, ${0.95 * gt})`;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 1.2, p.radius * 0.5);
      ctx.lineTo(-p.radius * 0.7, -p.radius * 0.6);
      ctx.lineTo(-p.radius * 0.35, p.radius * 0.05);
      ctx.lineTo(0, -p.radius * 1.05);
      ctx.lineTo(p.radius * 0.35, 0);
      ctx.lineTo(p.radius * 0.75, -p.radius * 0.7);
      ctx.lineTo(p.radius * 1.25, p.radius * 0.5);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = "rgba(2, 6, 23, 0.9)";
      ctx.lineWidth = 2.5;
      ctx.stroke();
      ctx.fillStyle = `rgba(220, 38, 38, ${0.5 * gt})`;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 0.3, p.radius * 0.3);
      ctx.lineTo(0, -p.radius * 0.55);
      ctx.lineTo(p.radius * 0.3, p.radius * 0.3);
      ctx.closePath();
      ctx.fill();
    } else if (p.move === "web") {
      // SPIDER_PATCH: a white web ball with trailing strands.
      ctx.scale(p.dir, 1);
      ctx.strokeStyle = "rgba(226, 232, 240, 0.7)";
      ctx.lineWidth = 1.5;
      ctx.beginPath();
      ctx.moveTo(-14, -4); ctx.lineTo(-4, 0); ctx.moveTo(-14, 4); ctx.lineTo(-4, 0);
      ctx.moveTo(-10, 0); ctx.lineTo(-4, 0);
      ctx.stroke();
      ctx.fillStyle = "#e8eef7";
      ctx.strokeStyle = "#94a3b8";
      ctx.lineWidth = 1.4;
      ctx.beginPath();
      ctx.arc(0, 0, 8, 0, Math.PI * 2);
      ctx.fill(); ctx.stroke();
      ctx.strokeStyle = "rgba(100, 116, 139, 0.8)";
      ctx.lineWidth = 0.9;
      ctx.beginPath();
      ctx.moveTo(-8, 0); ctx.lineTo(8, 0); ctx.moveTo(0, -8); ctx.lineTo(0, 8);
      ctx.moveTo(-5.6, -5.6); ctx.lineTo(5.6, 5.6); ctx.moveTo(-5.6, 5.6); ctx.lineTo(5.6, -5.6);
      ctx.stroke();
    } else if (p.move === "webPellet") {
      // SPIDER_PATCH: the barrage cone's little web bits.
      ctx.fillStyle = `rgba(226, 232, 240, ${Math.max(0.2, p.life / Math.max(1, p.maxLife))})`;
      ctx.beginPath();
      ctx.arc(0, 0, 4, 0, Math.PI * 2);
      ctx.fill();
    } else if (p.move === "stalkerShot") {
      // ZEALOT_PATCH: the Stalker's particle-disruptor bolt - a cyan dart.
      ctx.scale(p.dir, 1);
      ctx.globalCompositeOperation = "lighter";
      ctx.fillStyle = "rgba(45, 212, 191, 0.4)";
      ctx.beginPath();
      ctx.ellipse(0, 0, 16, 6, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = "rgba(224, 255, 255, 0.95)";
      ctx.beginPath();
      ctx.moveTo(-10, 0); ctx.lineTo(4, -3.5); ctx.lineTo(12, 0); ctx.lineTo(4, 3.5); ctx.closePath();
      ctx.fill();
      ctx.globalCompositeOperation = "source-over";
    } else if (p.move === "utensil") {
      // SANJI_UTENSIL_PATCH: a spinning thrown utensil. Each kind draws
      // its own silhouette in steel, with an orange/blue heat glint when
      // it's an empowered or Ifrit throw.
      p.spin = (p.spin || 0) + 0.55 * (p.dir || 1);
      ctx.rotate(p.spin);
      const steel = "#d4d9e2";
      const dark = "#020617";
      const kind = p.utensilKind || "chopsticks";
      ctx.strokeStyle = dark;
      ctx.lineCap = "round";
      ctx.lineJoin = "round";
      if (p.utensilBurn) {
        ctx.save();
        ctx.globalCompositeOperation = "lighter";
        ctx.fillStyle = "rgba(249, 180, 90, 0.5)";
        ctx.beginPath();
        ctx.arc(0, 0, 15, 0, Math.PI * 2);
        ctx.fill();
        ctx.restore();
      }
      if (kind === "chopsticks") {
        ctx.strokeStyle = dark;
        ctx.lineWidth = 5;
        ctx.beginPath();
        ctx.moveTo(-13, -3); ctx.lineTo(13, -3);
        ctx.moveTo(-13, 3); ctx.lineTo(13, 3);
        ctx.stroke();
        ctx.strokeStyle = "#c98a52";
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.moveTo(-13, -3); ctx.lineTo(13, -3);
        ctx.moveTo(-13, 3); ctx.lineTo(13, 3);
        ctx.stroke();
      } else if (kind === "fork") {
        ctx.strokeStyle = dark;
        ctx.lineWidth = 6;
        ctx.beginPath();
        ctx.moveTo(-12, 0); ctx.lineTo(9, 0);
        ctx.stroke();
        ctx.strokeStyle = steel;
        ctx.lineWidth = 3.4;
        ctx.beginPath();
        ctx.moveTo(-12, 0); ctx.lineTo(8, 0);
        ctx.stroke();
        // tines
        ctx.strokeStyle = dark;
        ctx.lineWidth = 4.5;
        ctx.beginPath();
        ctx.moveTo(8, -5); ctx.lineTo(15, -5);
        ctx.moveTo(8, 0); ctx.lineTo(16, 0);
        ctx.moveTo(8, 5); ctx.lineTo(15, 5);
        ctx.stroke();
        ctx.strokeStyle = steel;
        ctx.lineWidth = 2.2;
        ctx.beginPath();
        ctx.moveTo(8, -5); ctx.lineTo(15, -5);
        ctx.moveTo(8, 0); ctx.lineTo(16, 0);
        ctx.moveTo(8, 5); ctx.lineTo(15, 5);
        ctx.stroke();
      } else if (kind === "spoon") {
        ctx.strokeStyle = dark;
        ctx.lineWidth = 6;
        ctx.beginPath();
        ctx.moveTo(-14, 0); ctx.lineTo(4, 0);
        ctx.stroke();
        ctx.strokeStyle = steel;
        ctx.lineWidth = 3.4;
        ctx.beginPath();
        ctx.moveTo(-14, 0); ctx.lineTo(4, 0);
        ctx.stroke();
        ctx.fillStyle = dark;
        ctx.beginPath();
        ctx.ellipse(10, 0, 8, 6, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = steel;
        ctx.beginPath();
        ctx.ellipse(10, 0, 6, 4.2, 0, 0, Math.PI * 2);
        ctx.fill();
      } else {
        // knife
        ctx.fillStyle = dark;
        ctx.beginPath();
        ctx.moveTo(-15, -2);
        ctx.lineTo(2, -4);
        ctx.lineTo(17, 0);
        ctx.lineTo(2, 4);
        ctx.lineTo(-15, 2);
        ctx.closePath();
        ctx.fill();
        ctx.fillStyle = "#8a6a3a";
        ctx.fillRect(-15, -3, 8, 6);
        ctx.fillStyle = steel;
        ctx.beginPath();
        ctx.moveTo(-6, -2.4);
        ctx.lineTo(2, -2.6);
        ctx.lineTo(15, 0);
        ctx.lineTo(2, 2.6);
        ctx.lineTo(-6, 2.4);
        ctx.closePath();
        ctx.fill();
      }
    } else if (p.move === "davidRocket") {
      // DAVID_PATCH: a stubby arm-launched rocket with a fiery trail.
      if (hasProjectileAngle) ctx.rotate(projectileAngle); else ctx.scale(p.dir, 1);
      const rad = p.radius || 16;
      // exhaust flame
      ctx.save();
      ctx.globalCompositeOperation = "lighter";
      const fl = ctx.createRadialGradient(-rad * 0.9, 0, 1, -rad * 0.9, 0, rad * 1.4);
      fl.addColorStop(0, "rgba(255, 240, 180, 0.95)");
      fl.addColorStop(0.5, "rgba(255, 140, 40, 0.7)");
      fl.addColorStop(1, "rgba(255, 60, 20, 0)");
      ctx.fillStyle = fl;
      ctx.beginPath();
      ctx.ellipse(-rad * 0.9, 0, rad * 1.3 + Math.random() * 3, rad * 0.7, 0, 0, Math.PI * 2);
      ctx.fill();
      ctx.restore();
      // rocket body
      ctx.fillStyle = "#b8bcc4";
      ctx.strokeStyle = "#20242c";
      ctx.lineWidth = 1.4;
      ctx.beginPath();
      ctx.moveTo(rad * 0.9, 0);
      ctx.lineTo(rad * 0.2, -rad * 0.5);
      ctx.lineTo(-rad * 0.7, -rad * 0.5);
      ctx.lineTo(-rad * 0.7, rad * 0.5);
      ctx.lineTo(rad * 0.2, rad * 0.5);
      ctx.closePath();
      ctx.fill(); ctx.stroke();
      // yellow warning stripe + fins
      ctx.fillStyle = "#f5c518";
      ctx.fillRect(-rad * 0.2, -rad * 0.5, rad * 0.25, rad);
      ctx.fillStyle = "#20242c";
      ctx.beginPath();
      ctx.moveTo(-rad * 0.7, -rad * 0.5); ctx.lineTo(-rad * 1.0, -rad * 0.8); ctx.lineTo(-rad * 0.7, -rad * 0.2); ctx.closePath();
      ctx.moveTo(-rad * 0.7, rad * 0.5); ctx.lineTo(-rad * 1.0, rad * 0.8); ctx.lineTo(-rad * 0.7, rad * 0.2); ctx.closePath();
      ctx.fill();
    } else if (p.move === "jijiSpirit" || p.move === "jijiEvil" || p.move === "jijiSoccer") {
      // JIJI_PATCH: spirit energy - lavender/white for Jiji, dark maroon for
      // the Evil Eye, and a bouncing translucent orb for Soccer Strike.
      const evil = p.move === "jijiEvil";
      const soccer = p.move === "jijiSoccer";
      const rad = p.radius || 12;
      const pulse = 1 + Math.sin(frame * 0.3) * 0.08;
      ctx.globalCompositeOperation = "lighter";
      const glow = ctx.createRadialGradient(0, 0, rad * 0.15, 0, 0, rad * 2.1 * pulse);
      if (evil) {
        glow.addColorStop(0, "rgba(245, 230, 255, 0.95)");
        glow.addColorStop(0.35, "rgba(168, 85, 247, 0.9)");
        glow.addColorStop(0.7, "rgba(91, 33, 182, 0.55)");
        glow.addColorStop(1, "rgba(20, 6, 40, 0)");
      } else if (soccer) {
        glow.addColorStop(0, "rgba(255, 255, 255, 0.95)");
        glow.addColorStop(0.4, "rgba(129, 140, 248, 0.82)");
        glow.addColorStop(0.75, "rgba(79, 70, 229, 0.4)");
        glow.addColorStop(1, "rgba(15, 10, 40, 0)");
      } else {
        glow.addColorStop(0, "rgba(255, 255, 255, 0.95)");
        glow.addColorStop(0.4, "rgba(196, 181, 253, 0.85)");
        glow.addColorStop(0.75, "rgba(124, 92, 220, 0.42)");
        glow.addColorStop(1, "rgba(20, 12, 40, 0)");
      }
      ctx.fillStyle = glow;
      ctx.beginPath();
      ctx.arc(0, 0, rad * 2 * pulse, 0, Math.PI * 2);
      ctx.fill();
      ctx.globalCompositeOperation = "source-over";
      ctx.fillStyle = evil ? "rgba(245, 230, 255, 0.95)" : "rgba(255, 255, 255, 0.95)";
      ctx.beginPath();
      ctx.arc(0, 0, rad * 0.55, 0, Math.PI * 2);
      ctx.fill();
      // trailing wisps
      ctx.strokeStyle = evil ? "rgba(168, 85, 247, 0.7)" : soccer ? "rgba(129, 140, 248, 0.7)" : "rgba(196, 181, 253, 0.7)";
      ctx.lineWidth = 3;
      ctx.lineCap = "round";
      ctx.beginPath();
      ctx.moveTo(-(p.dir || 1) * rad * 2.4, 0);
      ctx.lineTo(-(p.dir || 1) * rad * 0.8, 0);
      ctx.stroke();
      if (evil) {
        // a glowing slit "eye" in the core
        ctx.fillStyle = "rgba(245, 208, 32, 0.95)";
        ctx.beginPath();
        ctx.ellipse(0, 0, rad * 0.4, rad * 0.18, 0, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = "rgba(26, 5, 48, 0.95)";
        ctx.beginPath();
        ctx.ellipse(0, 0, rad * 0.12, rad * 0.16, 0, 0, Math.PI * 2);
        ctx.fill();
      }
    } else {
      if (hasProjectileAngle) ctx.rotate(projectileAngle);
      else ctx.scale(p.dir, 1);
      ctx.rotate(-0.18);
      const t = p.life / Math.max(1, techniqueMoves.cleave.life);
      ctx.fillStyle = `rgba(2, 6, 23, ${0.92 * t})`;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 0.7, -p.radius * 0.85);
      ctx.lineTo(p.radius * 1.35, -p.radius * 1.25);
      ctx.lineTo(p.radius * 0.72, -p.radius * 0.12);
      ctx.lineTo(p.radius * 1.45, p.radius * 0.62);
      ctx.lineTo(-p.radius * 0.75, p.radius * 1.1);
      ctx.lineTo(-p.radius * 0.2, p.radius * 0.08);
      ctx.closePath();
      ctx.fill();
      ctx.fillStyle = `rgba(220, 38, 38, ${0.9 * t})`;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 0.35, -p.radius * 0.55);
      ctx.lineTo(p.radius * 0.9, -p.radius * 0.82);
      ctx.lineTo(p.radius * 0.42, -p.radius * 0.05);
      ctx.lineTo(p.radius * 0.95, p.radius * 0.42);
      ctx.lineTo(-p.radius * 0.35, p.radius * 0.7);
      ctx.lineTo(0, p.radius * 0.02);
      ctx.closePath();
      ctx.fill();
      ctx.strokeStyle = `rgba(127, 29, 29, ${0.95 * t})`;
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.moveTo(-p.radius * 0.8, p.radius * 0.95);
      ctx.lineTo(p.radius * 1.25, -p.radius * 1.1);
      ctx.moveTo(-p.radius * 0.6, -p.radius * 0.75);
      ctx.lineTo(p.radius * 1.28, p.radius * 0.58);
      ctx.stroke();
    }
    ctx.restore();
  }
}

function drawHitboxHint(f) {
  const attack = getAttackSpec(f);
  if (f.attackFrame < attack.windup || f.attackFrame > attack.windup + attack.active) return;
  let box = getHitbox(f);

  // LIGHT_BIG_SAME_HITBOX_VISUAL_PATCH:
  // Same hitbox visual as normal, only slightly bigger for Light because Ryuk is doing the hit.
  if (isLight(f) && (f.attacking === "light" || f.attacking === "heavy")) {
    const growX = f.attacking === "heavy" ? 16 : 12;
    const growY = f.attacking === "heavy" ? 10 : 8;
    box = {
      x: box.x - growX * 0.25,
      y: box.y - growY * 0.5,
      w: box.w + growX,
      h: box.h + growY
    };
  }

  ctx.strokeStyle = "rgba(255, 246, 183, 0.5)";
  ctx.lineWidth = 2;
  ctx.strokeRect(box.x, box.y, box.w, box.h);
}

function draw() {
  updateCamera();
  drawViewportBackdrop();

  ctx.save();
  if (shake > 0) {
    ctx.translate((Math.random() - 0.5) * shake, (Math.random() - 0.5) * shake);
    shake *= 0.78;
    if (shake < 0.4) shake = 0;
  }

  // DOMAIN_CINEMATIC_CAMERA_PATCH
  // Give domain startup a short cinematic rotation/zoom.
  let domainCinematicRotation = 0;
  let domainCinematicZoom = 1;
  if (pendingDomain && !domainClash) {
    const progress = 1 - Math.max(0, Math.min(1, pendingDomain.ticks / Math.max(1, pendingDomain.maxTicks || DOMAIN_STARTUP_TICKS)));
    const sign = pendingDomain.type === "malevolentShrine" ? -1 : 1;
    domainCinematicRotation = sign * (0.02 + progress * 0.045) + Math.sin(frame * 0.12) * 0.005;
    domainCinematicZoom = 1 + progress * 0.08;
  }
  if (domainCinematicRotation !== 0 || domainCinematicZoom !== 1) {
    ctx.translate(W / 2, H / 2);
    ctx.rotate(domainCinematicRotation);
    ctx.scale(domainCinematicZoom, domainCinematicZoom);
    ctx.translate(-W / 2, -H / 2);
  }

  ctx.translate(0, getCameraYOffset());
  ctx.scale(cameraZoom, cameraZoom);
  ctx.translate(-cameraX, 0);
  getStage().draw(); // STAGE_SELECT_PATCH
  drawUpsideDownBackdrop(); // VECNA_PATCH
  drawActiveDomainBackdrop();

  // DOMAIN_PLATFORM_VISIBILITY_PATCH
  // Domains replace the arena background, but the actual platforms should still
  // be visible and readable because they still affect gameplay.
  if (activeDomain || pendingDomain || domainClash) {
    drawPlatforms();
  }

  drawEffects();
  if (stageHazardsEnabled) drawStageHazards(); // STAGE_SELECT_PATCH (behind fighters)
  drawFighter(player, getPlayerLabel(), getPlayerLabelColor());
  drawFighter(enemy, getEnemyLabel(), getEnemyLabelColor());
  drawUpsideDownSpider(); // VECNA_PATCH
  drawTechniqueAimSizePreview();
  drawShieldBreakEffects();
  ctx.restore();
  drawUltimateScreenEffects();
  drawUltCutscene(); // ULT_CUTSCENES_PATCH
  drawDavidGlitchOverlay(); // DAVID_PATCH
  drawAkiraNotebook(); // AKIRA_PATCH
  drawBindingVowQuote();
  drawActionWarning();
}

// AKIRA_PATCH: the Bucket List notebook overlay (toggle with T). Lists the
// three active goals with progress bars; completed goals cross off.
function drawAkiraNotebook() {
  const me = (gameMode === "online" && onlineRole === "p2") ? enemy : player;
  if (!akiraNotebookOpen || !isAkira(me) || !Array.isArray(me.akiraGoals)) return;
  const pw = 300, ph = 176;
  const px = (W - pw) / 2, py = 84;
  ctx.save();
  // paper
  ctx.fillStyle = "rgba(250, 246, 232, 0.97)";
  ctx.strokeStyle = "#1f2937";
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.roundRect(px, py, pw, ph, 10);
  ctx.fill();
  ctx.stroke();
  // red margin + spiral holes
  ctx.strokeStyle = "rgba(220, 80, 80, 0.6)";
  ctx.lineWidth = 1.5;
  ctx.beginPath();
  ctx.moveTo(px + 30, py + 8); ctx.lineTo(px + 30, py + ph - 8);
  ctx.stroke();
  ctx.fillStyle = "#9aa3b0";
  for (let i = 0; i < 6; i++) { ctx.beginPath(); ctx.arc(px + 15, py + 24 + i * 26, 3, 0, Math.PI * 2); ctx.fill(); }
  // title
  ctx.fillStyle = "#b91c1c";
  ctx.font = "800 16px Arial";
  ctx.textAlign = "left";
  ctx.fillText("BUCKET LIST", px + 40, py + 26);
  ctx.fillStyle = "#374151";
  ctx.font = "600 11px Arial";
  ctx.fillText(`Goals done: ${me.akiraGoalsCompleted || 0}`, px + 180, py + 26);
  // goals
  me.akiraGoals.forEach((g, i) => {
    const gy = py + 52 + i * 38;
    const ratio = Math.max(0, Math.min(1, g.progress / g.target));
    ctx.fillStyle = "#111827";
    ctx.font = "700 13px Arial";
    ctx.fillText(`${i + 1}. ${g.label}`, px + 42, gy);
    // progress bar
    ctx.fillStyle = "#d8dbe0";
    ctx.fillRect(px + 42, gy + 6, 220, 8);
    ctx.fillStyle = "#22a06b";
    ctx.fillRect(px + 42, gy + 6, 220 * ratio, 8);
    ctx.strokeStyle = "#1f2937";
    ctx.lineWidth = 1;
    ctx.strokeRect(px + 42, gy + 6, 220, 8);
    // strike-through if flashing done (brief)
    if (g.done) {
      ctx.strokeStyle = "#b91c1c";
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(px + 40, gy - 4); ctx.lineTo(px + 262, gy - 4);
      ctx.stroke();
    }
  });
  ctx.fillStyle = "#6b7280";
  ctx.font = "600 10px Arial";
  ctx.textAlign = "center";
  ctx.fillText("press T to close", px + pw / 2, py + ph - 8);
  ctx.restore();
}

// DAVID_PATCH: a cyber glitch overlay while any David is in Cyberpsychosis -
// red/cyan channel-split scanlines and jitter bars.
function drawDavidGlitchOverlay() {
  const g = Math.max(player?.technique === "david" ? (player.davidGlitch || 0) : 0, enemy?.technique === "david" ? (enemy.davidGlitch || 0) : 0);
  if (g <= 0.02) return;
  ctx.save();
  ctx.globalAlpha = Math.min(0.35, g * 0.3);
  // red/cyan edge tint
  ctx.globalCompositeOperation = "lighter";
  ctx.fillStyle = "rgba(255, 40, 60, 0.5)";
  ctx.fillRect(0, 0, 5, H);
  ctx.fillStyle = "rgba(40, 220, 240, 0.5)";
  ctx.fillRect(W - 5, 0, 5, H);
  // random jitter bars
  ctx.globalCompositeOperation = "source-over";
  for (let i = 0; i < 4; i++) {
    if (Math.random() > 0.5) continue;
    const y = Math.random() * H;
    const h = 2 + Math.random() * 8;
    ctx.fillStyle = Math.random() > 0.5 ? "rgba(255, 40, 60, 0.18)" : "rgba(40, 220, 240, 0.18)";
    ctx.fillRect(0, y, W, h);
  }
  // scanlines
  ctx.globalAlpha = Math.min(0.15, g * 0.12);
  ctx.fillStyle = "#000";
  for (let y = 0; y < H; y += 4) ctx.fillRect(0, y, W, 1);
  ctx.restore();
}


function drawTechniqueAimSizePreview() {
  if (homeOpen || paused || gameState !== "playing") return;

  const active = getActiveMouseTechniqueFighter();
  if (!active || active.ko) return;

  let move = null;
  if (active.technique === "shrine") {
    if (mouseTechniqueHeld.ct2) move = "cleave";
    else if (mouseTechniqueHeld.fuga) move = "fuga";
    else if (mouseTechniqueHeld.ct1) move = "slash";
  } else if (active.technique === "limitless") {
    if (mouseTechniqueHeld.ct1) move = "blue";
    else if (mouseTechniqueHeld.ct2) move = "red";
  }

  if (!move || !techniqueMoves[move]) return;

  const spec = techniqueMoves[move];

  // CLEAVE_PREVIEW_CE_FIX
  // Do not show the Cleave/Dismantle aim art if the move cannot actually be used,
  // especially when the player does not have enough CE.
  const moveCost = getTechniqueCost(active, move);
  if (active.ce < moveCost) return;
  if ((active.techniqueCooldown || 0) > 0 && (move === "cleave" || move === "slash")) return;

  const aimPoint = sanitizeAimPoint(active.techniqueAim || mouseAimWorld);
  const origin = getTechniqueOrigin(active, move);
  const aimVector = getTechniqueAimVector(active, move, aimPoint);
  const vowBoost = move === "cleave" && hasBindingVow(active, "cleave");
  const finalRadius =
    spec.radius *
    getDomainProjectileSizeMultiplier(active, move) *
    (vowBoost ? 1.45 : 1);
  const previewDistance = getAimPreviewDistance(move, spec, 0, aimVector, active, finalRadius);
  const endX = origin.x + aimVector.x * previewDistance;
  const endY = origin.y + aimVector.y * previewDistance;

  ctx.save();

  // Draw the aim line.
  ctx.globalAlpha = 0.65;
  ctx.lineWidth = move === "cleave" ? 3 : 2.5;
  ctx.setLineDash(move === "cleave" ? [12, 9] : [10, 8]);
  ctx.strokeStyle = active.technique === "shrine" ? "rgba(255, 233, 233, 0.85)" : "rgba(173, 216, 255, 0.85)";
  ctx.beginPath();
  ctx.moveTo(origin.x, origin.y);
  ctx.lineTo(endX, endY);
  ctx.stroke();
  ctx.setLineDash([]);

  // CLEAVE_AIM_ART_PREVIEW_FIX:
  // For Cleave, show the actual Cleave art ghost, not a circle.
  if (move === "cleave") {
    ctx.translate(endX, endY);
    ctx.rotate(aimVector.angle);
    ctx.globalAlpha = vowBoost ? 0.68 : 0.48;
    ctx.globalCompositeOperation = "lighter";
    drawShrineTechniqueShape("cleave", finalRadius);

    // Thin outline matching the art hitbox, so the player sees the real size.
    ctx.globalCompositeOperation = "source-over";
    ctx.globalAlpha = vowBoost ? 0.75 : 0.5;
    ctx.strokeStyle = vowBoost ? "rgba(255, 230, 230, 0.92)" : "rgba(248, 113, 113, 0.75)";
    ctx.lineWidth = 2;
    ctx.setLineDash([8, 7]);
    ctx.rotate(-0.18);
    ctx.strokeRect(-finalRadius * 0.75, -finalRadius * 1.25, finalRadius * 2.2, finalRadius * 2.35);
    ctx.setLineDash([]);
    ctx.restore();
    return;
  }

  // Other moves keep a simple ghost preview.
  ctx.globalAlpha = 0.5;
  ctx.translate(endX, endY);
  if (move === "blue" || move === "red") {
    drawLimitlessOrb(move, finalRadius, aimVector.dir);
  } else if (move === "slash") {
    ctx.rotate(aimVector.angle);
    drawShrineTechniqueShape("slash", finalRadius);
  } else {
    ctx.fillStyle = "rgba(255,255,255,0.75)";
    ctx.beginPath();
    ctx.arc(0, 0, 4.5, 0, Math.PI * 2);
    ctx.fill();
  }

  ctx.restore();
}


function drawBindingVowQuote() {
  const speakers = [player, enemy].filter((f) => f && (f.bindingVowQuoteTicks || 0) > 0 && f.bindingVowQuote);
  if (!speakers.length) return;
  const f = speakers[speakers.length - 1];
  const t = Math.max(0, Math.min(1, (f.bindingVowQuoteTicks || 0) / BINDING_VOW_QUOTE_TICKS));
  const center = getFighterCenter(f);

  ctx.save();
  ctx.globalAlpha = Math.max(0, Math.min(1, t));
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = "900 42px system-ui, sans-serif";
  ctx.shadowColor = "rgba(185, 28, 28, 0.95)";
  ctx.shadowBlur = 18;
  ctx.fillStyle = "#fff7ed";
  ctx.strokeStyle = "rgba(0,0,0,0.85)";
  ctx.lineWidth = 7;
  const x = Math.max(170, Math.min(W - 170, (center.x - cameraX) * cameraZoom));
  const y = 122;
  ctx.strokeText(f.bindingVowQuote, x, y);
  ctx.fillText(f.bindingVowQuote, x, y);
  ctx.restore();
}

function drawActionWarning() {
  if (!actionWarning || actionWarning.ticks <= 0 || !actionWarning.text) return;
  const t = actionWarning.noFade ? 1 : actionWarning.ticks / Math.max(1, actionWarning.maxTicks || 1);
  ctx.save();
  ctx.globalAlpha = Math.max(0, Math.min(1, t));
  ctx.textAlign = "center";
  ctx.textBaseline = "middle";
  ctx.font = "900 28px system-ui, sans-serif";

  const x = W / 2;
  const y = 96;
  const paddingX = 28;
  const boxW = Math.min(W - 80, ctx.measureText(actionWarning.text).width + paddingX * 2);
  const boxH = 48;

  ctx.fillStyle = "rgba(2, 6, 23, 0.78)";
  ctx.strokeStyle = "rgba(248, 250, 252, 0.62)";
  ctx.lineWidth = 2;
  ctx.beginPath();
  ctx.roundRect(x - boxW / 2, y - boxH / 2, boxW, boxH, 14);
  ctx.fill();
  ctx.stroke();

  ctx.shadowColor = "rgba(239, 68, 68, 0.8)";
  ctx.shadowBlur = 12;
  ctx.fillStyle = "#fff7ed";
  ctx.fillText(actionWarning.text, x, y);
  ctx.restore();
}

function drawUltimateScreenEffects() {
  if (!ultimateScreenEffect || ultimateScreenEffect.ticks <= 0) return;
  const t = ultimateScreenEffect.ticks / Math.max(1, ultimateScreenEffect.maxTicks);
  const age = 1 - t;
  ctx.save();
  if (ultimateScreenEffect.kind === "domainVoid") {
    ctx.fillStyle = `rgba(2, 6, 23, ${0.64 * t})`;
    ctx.fillRect(0, 0, W, H);
    ctx.strokeStyle = `rgba(125, 211, 252, ${0.8 * t})`;
    ctx.lineWidth = 4;
    for (let i = 0; i < 9; i += 1) {
      ctx.beginPath();
      ctx.arc(W / 2, H / 2, 45 + i * 42 + age * 120, 0, Math.PI * 2);
      ctx.stroke();
    }
    ctx.fillStyle = `rgba(255,255,255,${0.9 * t})`;
    ctx.font = "bold 46px system-ui, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("DOMAIN EXPANSION", W / 2, H * 0.42);
    ctx.font = "bold 34px system-ui, sans-serif";
    ctx.fillText("UNLIMITED VOID", W / 2, H * 0.52);
  } else if (ultimateScreenEffect.kind === "domainShrine") {
    ctx.fillStyle = `rgba(69, 10, 10, ${0.66 * t})`;
    ctx.fillRect(0, 0, W, H);
    ctx.strokeStyle = `rgba(248, 250, 252, ${0.85 * t})`;
    ctx.lineWidth = 5;
    for (let i = 0; i < 10; i += 1) {
      const y = H * (0.12 + i * 0.08);
      ctx.beginPath();
      ctx.moveTo(W * -0.05, y + age * 45);
      ctx.lineTo(W * 1.05, y - 80 + i * 11);
      ctx.stroke();
    }
    ctx.fillStyle = `rgba(255,255,255,${0.9 * t})`;
    ctx.font = "bold 46px system-ui, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("DOMAIN EXPANSION", W / 2, H * 0.42);
    ctx.font = "bold 34px system-ui, sans-serif";
    ctx.fillText("MALEVOLENT SHRINE", W / 2, H * 0.52);
  } else if (ultimateScreenEffect.kind === "domainClash") {
    ctx.fillStyle = `rgba(2, 6, 23, ${0.68 * t})`;
    ctx.fillRect(0, 0, W, H);
    ctx.fillStyle = `rgba(56, 189, 248, ${0.22 * t})`;
    ctx.fillRect(0, 0, W / 2, H);
    ctx.fillStyle = `rgba(185, 28, 28, ${0.26 * t})`;
    ctx.fillRect(W / 2, 0, W / 2, H);
    ctx.fillStyle = `rgba(255,255,255,${0.95 * t})`;
    ctx.font = "bold 44px system-ui, sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("DOMAIN CLASH", W / 2, H * 0.48);
    ctx.font = "bold 22px system-ui, sans-serif";
    ctx.fillText("Mash X", W / 2, H * 0.56);
  } else if (ultimateScreenEffect.kind === "hollowPurple") {
    ctx.fillStyle = `rgba(2, 6, 23, ${0.44 * Math.sin(Math.PI * t) + 0.08 * t})`;
    ctx.fillRect(0, 0, W, H);
    const glow = ctx.createRadialGradient(W / 2, H / 2, 20, W / 2, H / 2, W * 0.6);
    glow.addColorStop(0, `rgba(168, 85, 247, ${0.12 * t})`);
    glow.addColorStop(0.55, `rgba(37, 99, 235, ${0.08 * t})`);
    glow.addColorStop(1, "rgba(2, 6, 23, 0)");
    ctx.fillStyle = glow;
    ctx.fillRect(0, 0, W, H);
  } else if (ultimateScreenEffect.kind === "deathNote") {
    const flicker = 0.65 + Math.sin(frame * 0.75) * 0.18 + Math.sin(frame * 0.21) * 0.12;
    ctx.fillStyle = `rgba(2, 6, 23, ${0.74 * t})`;
    ctx.fillRect(0, 0, W, H);
    ctx.fillStyle = `rgba(127, 29, 29, ${0.18 * t * flicker})`;
    ctx.fillRect(0, 0, W, H);

    ctx.save();
    ctx.translate(W * 0.5, H * 0.5);
    ctx.rotate(-0.08 + Math.sin(frame * 0.03) * 0.015);
    ctx.fillStyle = `rgba(250, 250, 245, ${0.92 * t})`;
    ctx.strokeStyle = `rgba(15, 23, 42, ${0.9 * t})`;
    ctx.lineWidth = 4;
    ctx.beginPath();
    ctx.roundRect(-132, -72, 264, 144, 6);
    ctx.fill();
    ctx.stroke();
    ctx.fillStyle = `rgba(15, 23, 42, ${0.86 * t})`;
    ctx.font = "900 26px Georgia, serif";
    ctx.textAlign = "center";
    ctx.fillText("DEATH NOTE", 0, -24);
    ctx.strokeStyle = `rgba(127, 29, 29, ${0.72 * t})`;
    ctx.lineWidth = 2;
    for (let i = 0; i < 5; i += 1) {
      const y = 4 + i * 15;
      ctx.beginPath();
      ctx.moveTo(-96, y);
      ctx.lineTo(96 - age * 34 + i * 4, y + Math.sin(frame * 0.08 + i) * 2);
      ctx.stroke();
    }
    ctx.restore();

    ctx.fillStyle = `rgba(0,0,0,${0.62 * t})`;
    ctx.beginPath();
    ctx.ellipse(W * 0.73, H * 0.48, 58 + age * 18, 112, 0.08, 0, Math.PI * 2);
    ctx.fill();
    ctx.fillStyle = `rgba(239,68,68,${0.78 * t})`;
    ctx.beginPath();
    ctx.arc(W * 0.71, H * 0.42, 5 + Math.sin(frame * 0.4) * 1.5, 0, Math.PI * 2);
    ctx.arc(W * 0.75, H * 0.42, 5 + Math.cos(frame * 0.37) * 1.5, 0, Math.PI * 2);
    ctx.fill();

    ctx.strokeStyle = `rgba(248, 113, 113, ${0.68 * t})`;
    ctx.lineWidth = 3;
    for (let i = 0; i < 8; i += 1) {
      const x = W * (0.12 + i * 0.11);
      const y = H * (0.2 + ((i * 37) % 55) / 100);
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + Math.sin(frame * 0.09 + i) * 26, y + 38 + age * 46);
      ctx.stroke();
    }
  } else {
    ctx.fillStyle = `rgba(2, 6, 23, ${0.28 * t})`;
    ctx.fillRect(0, 0, W, H);
    ctx.strokeStyle = `rgba(127, 29, 29, ${0.44 * t})`;
    ctx.lineWidth = 3;
    for (let i = 0; i < 7; i += 1) {
      const y = H * (0.16 + i * 0.12) + Math.sin(frame * 0.09 + i) * 12;
      ctx.beginPath();
      ctx.moveTo(W * 0.08, y);
      ctx.lineTo(W * (0.92 - age * 0.05), y - 34 + i * 5);
      ctx.stroke();
    }
    if (ultimateScreenEffect.kind === "worldSlashRelease") {
      ctx.strokeStyle = `rgba(248, 250, 252, ${0.82 * t})`;
      ctx.lineWidth = 5;
      ctx.beginPath();
      ctx.moveTo(W * 0.08, H * 0.52);
      ctx.lineTo(W * 0.92, H * 0.45);
      ctx.stroke();
    }
  }
  ctx.restore();
}

function fixedUpdate() {
  frame += 1;
  walkingSfxActiveThisFrame = false;
  if (actionWarning && actionWarning.ticks > 0) actionWarning.ticks -= 1;

  // DOMAIN_RUNTIME_FIX
  // The domain system was defined but never ticked. That meant pending domains
  // never activated, active domain effects never ran, and the caster could stay
  // stuck in domainStartup forever.
  updateDomainSystem();

  // CT_LOCK_TIMER_FIX
  // Post-domain CT lock always ticks down here. This prevents it from getting
  // stuck after online sync, hitstop, or special animation states.
  [player, enemy].forEach((fighter) => {
    if (fighter && Number.isFinite(Number(fighter.ctLockTimer)) && fighter.ctLockTimer > 0) {
      fighter.ctLockTimer = Math.max(0, fighter.ctLockTimer - 1);
    }
  });

  if (joinerLocalHitLockTicks > 0) joinerLocalHitLockTicks -= 1;
  if (hitStopTicks > 0) {
    hitStopTicks -= 1;
    updateHitSparks();
    finalizeWalkingSfx();
    updateHud();
    return;
  }
  if (gameState !== "playing") {
    if (gameMode === "online" && onlineRole === "p2" && (gameState === "lobby" || gameState === "roundOver") && player2Ready && readyCountdownValue <= 0 && performance.now() - lastOnlineReadySent > 500) {
      sendOnlineReady();
    }
    finalizeWalkingSfx();
    updateHud();
    return;
  }

  if (gameMode === "online" && onlineRole === "p2" && roundResolved && player2Ready && readyCountdownValue <= 0 && performance.now() - lastOnlineReadySent > 500) {
    sendOnlineReady();
  }

  if (!gameOver && !paused && gameMode === "online" && onlineRole === "p2") {
    updateOnlineRivalSelf();
    updateFighter(enemy, player);
    keepFightersApart();
    updateSukunaBarrage(enemy, player);
    updateSukunaGrabThrow(enemy, player);
    applyHit(enemy, player);
    updateProjectiles();
    updateVecnaMinions(); // VECNA_PATCH
    updateUpsideDown(); // VECNA_PATCH
    updateZealotUnits(); // ZEALOT_PATCH
    updateOrbitalBeams(); // ZEALOT_PATCH
    updateHitSparks();
  } else if (!gameOver && !paused && !(gameMode === "online" && onlineRole !== "p1")) {
    updatePlayer();
    if (gameMode === "online") {
      updateRemoteRivalPlayer();
    } else if (gameMode === "pvp") {
      updateRivalPlayer();
    } else {
      updateEnemyAi();
    }
    updateFighter(player, enemy);
    updateFighter(enemy, player);
    keepFightersApart();
    updateSukunaBarrage(player, enemy);
    updateSukunaGrabThrow(player, enemy);
    if (gameMode !== "online") updateSukunaBarrage(enemy, player);
    if (gameMode !== "online") updateSukunaGrabThrow(enemy, player);
    applyHit(player, enemy);
    if (!(gameMode === "online" && onlineRole === "p1")) applyHit(enemy, player);
    updateProjectiles();
    updateVecnaMinions(); // VECNA_PATCH
    updateUpsideDown(); // VECNA_PATCH
    updateZealotUnits(); // ZEALOT_PATCH
    updateOrbitalBeams(); // ZEALOT_PATCH
    updateHitSparks();
  } else if (roundEnding && !paused) {
    updateFighter(player, enemy);
    updateFighter(enemy, player);
    updateHitSparks();
    if ((player.lying || enemy.lying) && Math.max(player.koTimer, enemy.koTimer) > 50) {
      finishRound(koWinner);
    }
  }
  updateStage(); // STAGE_SELECT_PATCH
  applyPracticeSettingsTick();
  finalizeWalkingSfx();
  updateHud();
}

function loop(now) {
  const elapsed = Math.min(100, now - lastFrameTime);
  lastFrameTime = now;

  if (paused) {
    fixedAccumulator = 0;
  } else {
    fixedAccumulator += elapsed;
    let steps = 0;
    while (fixedAccumulator >= FIXED_STEP && steps < MAX_CATCH_UP_STEPS) {
      fixedUpdate();
      fixedAccumulator -= FIXED_STEP;
      steps += 1;
    }
    if (steps === MAX_CATCH_UP_STEPS) fixedAccumulator = 0;
  }

  draw();
  if (!techniqueScreen.classList.contains("hidden")) renderTechniquePreviews();
  sendOnlineInputTick();
  sendOnlineFighterState();
  sendOnlineState();
  requestAnimationFrame(loop);
}

window.addEventListener("keydown", (event) => {
  if (event.target && ["INPUT", "TEXTAREA"].includes(event.target.tagName)) return;
  const key = event.key.toLowerCase();
  const code = event.code.toLowerCase();
  const handledKeys = ["a", "d", "w", "e", "q", "r", "f", "s", "c", "x", "z", "t", "u", "i", "o", "p", " ", "shift", "tab", "arrowleft", "arrowright", "arrowup", "arrowdown", "n", "m", "/", "escape"];
  const handledCodes = ["keya", "keyd", "keyw", "keye", "keyq", "keyr", "keyf", "keys", "keyc", "keyx", "keyz", "keyt", "keyu", "keyi", "keyo", "keyp", "space", "shiftleft", "shiftright", "tab", "arrowleft", "arrowright", "arrowup", "arrowdown", "keyn", "keym", "slash", "escape"];
  if (handledKeys.includes(key) || handledCodes.includes(code)) event.preventDefault();
  if (key === "escape" && !homeOpen) {
    setPaused(!paused);
    return;
  }
  if (homeOpen) return;
  if (paused) return;
  if (isEventForAction("jump", key, code) && !event.repeat && canUseKeyboardReady()) {
    playButtonClickSound();
    handleReadyClick();
    return;
  }
  if (gameState !== "playing") return;
  keys.add(key);
  keys.add(code);
  keys.add(event.key);
  keys.add(event.code);

  const activeKeyFighter = gameMode === "online" && onlineRole === "p2" ? enemy : player;
  if (!event.repeat && activeKeyFighter?.technique === "shrine" && (activeKeyFighter.bindingVowChoiceTicks || 0) > 0) {
    const vowType = bindingVowKeyToType(key);
    if (vowType) {
      activateBindingVow(activeKeyFighter, vowType);
      if (gameMode === "online" && onlineRole === "p2") sendOnlineInput("bindingVowSelect", null, { vowType });
      return;
    }
  }

  if (gameMode === "online" && onlineRole === "p2") {
    if (!event.repeat && isEventForAction("light", key, code)) noteAttackButtonPress(enemy, "light");
    if (!event.repeat && isEventForAction("heavy", key, code)) noteAttackButtonPress(enemy, "heavy");
    if (isEventForAction("throw", key, code) && !event.repeat && handleThrowInput(enemy, false)) {
      sendOnlineInput("backThrow");
      return;
    }
    // SANJI_UTENSIL_PATCH + SANJI_COOK_PATCH: R switches, F cooks.
    if ((key === "r" || code === "keyr") && !event.repeat && enemy?.technique === "blackleg") {
      if (switchSanjiUtensil(enemy)) sendOnlineInput("sanji-utensil-switch");
      return;
    }
    if ((key === "f" || code === "keyf") && !event.repeat && enemy?.technique === "blackleg") {
      if (startSanjiCook(enemy)) sendOnlineInput("sanji-cook");
      return;
    }
    // INOSUKE_PATCH: R = Spatial Awareness, F = Whirling Fangs.
    if ((key === "r" || code === "keyr") && !event.repeat && enemy?.technique === "beast") {
      if (startBeastSpatial(enemy)) sendOnlineInput("beast-spatial");
      return;
    }
    if ((key === "f" || code === "keyf") && !event.repeat && enemy?.technique === "beast") {
      if (startBeastWhirl(enemy)) sendOnlineInput("beast-whirl");
      return;
    }
    const action = getOnlineAction(key, code, event.repeat);
    if (action === "light") startAttack(enemy, "light");
    if (action === "heavy") startAttack(enemy, "heavy");
    if (action === "dodge") startDodge(enemy, getVectorFromInput(getOnlineInput()));
    if (action === "jump") jumpFighterWithMove(enemy, (getOnlineInput().right ? 1 : 0) - (getOnlineInput().left ? 1 : 0));
    if (action === "infinity") toggleInfinity(enemy);
    if (action === "domain") startDomainExpansion(enemy);
    if (action === "simpleDomain") startSimpleDomain(enemy);
    if (action === "potato-chip") usePotatoChip(enemy);
    if (action === "bindingVowOpen") openBindingVowChoice(enemy);
    if (action === "ultimate") startUltimate(enemy);
    if (action === "ultimate-start") beginUltimateAim(enemy, enemy.techniqueAim || mouseAimWorld);
    sendOnlineInput(action);
    return;
  }
  if (!event.repeat && isEventForAction("light", key, code)) noteAttackButtonPress(player, "light");
  if (!event.repeat && isEventForAction("heavy", key, code)) noteAttackButtonPress(player, "heavy");
  if (isEventForAction("throw", key, code) && !event.repeat && handleThrowInput(player, false)) return;
  if (!event.repeat && isEventForAction("light", key, code)) startAttack(player, "light");
  if (!event.repeat && isEventForAction("heavy", key, code)) startAttack(player, "heavy");
  if ((key === "f" || code === "keyf") && !event.repeat) {
    if (player.technique === "limitless") toggleInfinity(player);
    // SANJI_COOK_PATCH: F cooks a healing meal.
    else if (player.technique === "blackleg") {
      if (startSanjiCook(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("sanji-cook");
      return;
    }
    // INOSUKE_PATCH: F is Tenth Fang Whirling Fangs.
    else if (player.technique === "beast") {
      if (startBeastWhirl(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("beast-whirl");
      return;
    }
    // AKIRA_PATCH: F is the Shark Suit.
    else if (player.technique === "akira") {
      if (startSharkSuit(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("akira-shark");
      return;
    }
  }
  if ((key === "r" || code === "keyr") && !event.repeat && player.technique === "akira") {
    // AKIRA_PATCH: R drinks a Cold Beer.
    if (drinkBeer(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("akira-beer");
    return;
  }
  if ((key === "t" || code === "keyt") && !event.repeat && player.technique === "akira") {
    // AKIRA_PATCH: T opens/closes the Bucket List notebook.
    akiraNotebookOpen = !akiraNotebookOpen;
    return;
  }
  if ((key === "r" || code === "keyr") && !event.repeat && player.technique === "blackleg") {
    // SANJI_UTENSIL_PATCH: R cycles the loaded utensil.
    if (switchSanjiUtensil(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("sanji-utensil-switch");
    return;
  }
  if ((key === "r" || code === "keyr") && !event.repeat && player.technique === "beast") {
    // INOSUKE_PATCH: R is Seventh Form Spatial Awareness.
    if (startBeastSpatial(player) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("beast-spatial");
    return;
  }
  if ((key === "t" || code === "keyt") && !event.repeat && player.technique === "shrine") {
    openBindingVowChoice(player);
    return;
  }
  if ((key === "x" || code === "keyx") && !event.repeat) {
    startDomainExpansion(player);
    return;
  }
  if ((key === "z" || code === "keyz") && !event.repeat) {
    startSimpleDomain(player);
    return;
  }
  if (isEventForAction("specialAim", key, code) && !event.repeat && !homeOpen && !paused && gameState === "playing") {
    const fighter = gameMode === "online" && onlineRole === "p2" ? enemy : player;
    if (fighter?.technique === "shrine") {
      if (prepareFuga(fighter, mouseAimWorld) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("fuga-start", mouseAimWorld);
    } else if (fighter?.technique === "limitless") {
      if (prepareTeleport(fighter, mouseAimWorld) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("teleport-start", mouseAimWorld);
    } else if (fighter?.technique === "deathnote") {
      usePotatoChip(fighter);
      if (gameMode === "online" && onlineRole === "p2") sendOnlineInput("potato-chip");
    } else if (fighter?.technique === "brawler") {
      // THRAGG_BRAWLER_PATCH: flying dash is instant, no aim/charge needed.
      if (startFlyingDash(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("flying-dash");
    } else if (fighter?.technique === "blackleg") {
      // SANJI_PATCH: S kicks the air - Sky Walk.
      if (startSkyWalk(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("sky-walk");
    } else if (fighter?.technique === "hivemind") {
      // VECNA_PATCH: S melts into the ground / erupts back out.
      if (startUpsideDownSlip(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("upside-slip");
    } else if (fighter?.technique === "zealot") {
      // ZEALOT_PATCH: S spins up Whirlwind.
      if (startZealotWhirlwind(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("zealot-whirl");
    } else if (fighter?.technique === "spider") {
      // SPIDER_PATCH: S is Web Swing.
      if (startWebSwing(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("spider-swing");
    } else if (fighter?.technique === "beast") {
      // INOSUKE_PATCH: S is Fifth Fang Crazy Cutting.
      if (startBeastCrazy(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("beast-crazy");
    } else if (fighter?.technique === "jiji") {
      // JIJI_PATCH: S / CT3 transforms between Jiji and Evil Eye.
      if (startJijiTransform(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("jiji-transform");
    } else if (fighter?.technique === "david") {
      // DAVID_PATCH: S is the Sandevistan.
      if (startSandevistan(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("david-sande");
    } else if (fighter?.technique === "akira") {
      // AKIRA_PATCH: S is Overtime.
      if (startOvertime(fighter) && gameMode === "online" && onlineRole === "p2") sendOnlineInput("akira-overtime");
    }
  }
  if (isEventForAction("ultimate", key, code) && !event.repeat) beginUltimateAim(player, mouseAimWorld);
  if (key === "shift" || code === "shiftleft" || code === "shiftright") startDodge(player, getPlayerDodgeVector());
  if (isEventForAction("jump", key, code) && !event.repeat) jumpPlayer();
  if (gameMode === "pvp") {
    if (!event.repeat && (key === "n" || code === "keyn")) noteAttackButtonPress(enemy, "light");
    if (!event.repeat && (key === "m" || code === "keym")) noteAttackButtonPress(enemy, "heavy");
    if ((key === "n" || code === "keyn" || key === "m" || code === "keym") && handleThrowInput(enemy)) return;
    if (!event.repeat && (key === "n" || code === "keyn")) startAttack(enemy, "light");
    if (!event.repeat && (key === "m" || code === "keym")) startAttack(enemy, "heavy");
    if (key === "/" || code === "slash") startDodge(enemy, getRivalDodgeVector());
    if ((key === "arrowup" || code === "arrowup") && !event.repeat) jumpRivalPlayer();
  }
});

window.addEventListener("keyup", (event) => {
  if (event.target && ["INPUT", "TEXTAREA"].includes(event.target.tagName)) return;
  const key = event.key.toLowerCase();
  const code = event.code.toLowerCase();
  const releaseAction = getTechniqueReleaseAction(key, code);
  keys.delete(event.key.toLowerCase());
  keys.delete(event.code.toLowerCase());
  if (isEventForAction("rct", event.key, event.code)) {
    cancelRct(player, true); // RCT_RELEASE_STOP_PATCH_EXACT
  }
  keys.delete(event.key);
  keys.delete(event.code);
  if (isEventForAction("specialAim", key, code) && !homeOpen && !paused && gameState === "playing") {
    const active = gameMode === "online" && onlineRole === "p2" ? enemy : player;
    if (active?.fugaAiming) {
      if (isOnlineJoinerControlledFighter(active)) {
        active.techniqueAim = sanitizeAimPoint(active?.techniqueAim || mouseAimWorld) || active.techniqueAim;
        active.fugaChargeTicks = Math.max(active.fugaChargeTicks || 0, getFugaRequiredChargeTicks(active));
      }
      startFuga(active, active?.techniqueAim || mouseAimWorld);
      clearSpecialHoldState(active);
      if (gameMode === "online" && onlineRole === "p2") sendOnlineInput("fuga", active?.techniqueAim || mouseAimWorld);
      return;
    }
    if (active?.teleportAiming) {
      if (isOnlineJoinerControlledFighter(active)) {
        active.techniqueAim = sanitizeAimPoint(active?.techniqueAim || mouseAimWorld) || active.techniqueAim;
        active.teleportAiming = true;
      }
      performTeleport(active, active?.techniqueAim || mouseAimWorld);
      clearSpecialHoldState(active);
      if (gameMode === "online" && onlineRole === "p2") sendOnlineInput("teleport", active?.techniqueAim || mouseAimWorld);
      return;
    }
    clearSpecialHoldState(active);
  }
  if (isEventForAction("ultimate", key, code) && !homeOpen && !paused && gameState === "playing") {
    const active = gameMode === "online" && onlineRole === "p2" ? enemy : player;
    const didRelease = releaseUltimateAim(active, active?.ultimateAimPoint || mouseAimWorld);
    if (gameMode === "online" && onlineRole === "p2") sendOnlineInput("ultimate-release", active?.ultimateAimPoint || mouseAimWorld);
    return;
  }
  if (gameMode === "online" && onlineRole === "p2" && releaseAction) {
    if (releaseAction === "ct1-release") releaseTechniqueInput(enemy, 1);
    if (releaseAction === "ct2-release") releaseTechniqueInput(enemy, 2);
    sendOnlineInput(releaseAction);
    return;
  }
  if (!homeOpen && !paused && gameState === "playing") {
    if (releaseAction === "ct1-release") releaseTechniqueInput(player, 1);
    if (releaseAction === "ct2-release") releaseTechniqueInput(player, 2);
  }
});

