// VISUAL_UPGRADE_PATCH_INFINITY_WCS_ONLY
function drawInfinityField(f) {
  if (!isInfinityActive(f)) return;
  const center = getFighterCenter(f);
  const fieldY = center.y - 8;
  const pulse = 1 + Math.sin((f.infinityPulse || frame) * 0.16) * 0.045;
  const radius = INFINITY_RADIUS * pulse;
  const ceRatio = Math.max(0, Math.min(1, f.ce / f.maxCe));
  const spin = frame * 0.035;

  ctx.save();
  ctx.globalCompositeOperation = "lighter";

  const glow = ctx.createRadialGradient(center.x, fieldY, radius * 0.12, center.x, fieldY, radius * 1.18);
  glow.addColorStop(0, `rgba(224, 242, 254, ${0.10 + ceRatio * 0.05})`);
  glow.addColorStop(0.42, `rgba(56, 189, 248, ${0.12 + ceRatio * 0.06})`);
  glow.addColorStop(0.78, "rgba(37, 99, 235, 0.08)");
  glow.addColorStop(1, "rgba(14, 165, 233, 0)");
  ctx.fillStyle = glow;
  ctx.beginPath();
  ctx.arc(center.x, fieldY, radius * 1.2, 0, Math.PI * 2);
  ctx.fill();

  for (let i = 0; i < 3; i += 1) {
    const r = radius * (0.72 + i * 0.16);
    ctx.strokeStyle = `rgba(191, 219, 254, ${0.42 - i * 0.08})`;
    ctx.lineWidth = 2 + i * 0.9;
    ctx.setLineDash(i === 1 ? [13, 9] : [7, 13]);
    ctx.lineDashOffset = -(frame * (0.65 + i * 0.25));
    ctx.beginPath();
    ctx.ellipse(center.x, fieldY, r * (1 + i * 0.02), r * (0.88 + i * 0.03), spin * (i + 1), 0, Math.PI * 2);
    ctx.stroke();
  }
  ctx.setLineDash([]);

  ctx.strokeStyle = "rgba(125, 211, 252, 0.7)";
  ctx.lineWidth = 1.5;
  for (let i = 0; i < 7; i += 1) {
    const a = frame * 0.035 + i * Math.PI * 2 / 7;
    const x = center.x + Math.cos(a) * radius * 0.85;
    const y = fieldY + Math.sin(a) * radius * 0.72;
    ctx.beginPath();
    ctx.arc(x, y, 2.2 + Math.sin(frame * 0.1 + i) * 0.9, 0, Math.PI * 2);
    ctx.stroke();
  }

  ctx.globalCompositeOperation = "source-over";
  ctx.restore();
}

function drawWorldSlashEffects() {
  for (const effect of worldSlashEffects) {
    const t = effect.life / effect.maxLife;
    const crackReady = effect.life < effect.maxLife - effect.splitDelay;
    const dx = effect.x2 - effect.x1;
    const dy = effect.y2 - effect.y1;
    const length = Math.hypot(dx, dy) || 1;
    const nx = -dy / length;
    const ny = dx / length;

    ctx.save();
    ctx.globalCompositeOperation = "lighter";
    ctx.globalAlpha = Math.max(0, t);
    ctx.lineCap = "round";

    ctx.strokeStyle = `rgba(255, 255, 255, ${0.95 * t})`;
    ctx.lineWidth = crackReady ? 13 : 7;
    ctx.beginPath();
    ctx.moveTo(effect.x1, effect.y1);
    ctx.lineTo(effect.x2, effect.y2);
    ctx.stroke();

    ctx.strokeStyle = `rgba(2, 6, 23, ${0.98 * t})`;
    ctx.lineWidth = crackReady ? 9 : 4;
    ctx.beginPath();
    ctx.moveTo(effect.x1 + nx * 1.5, effect.y1 + ny * 1.5);
    ctx.lineTo(effect.x2 + nx * 1.5, effect.y2 + ny * 1.5);
    ctx.stroke();

    ctx.strokeStyle = `rgba(248, 250, 252, ${0.55 * t})`;
    ctx.lineWidth = 2;
    ctx.setLineDash([18, 12]);
    ctx.lineDashOffset = -frame * 1.2;
    ctx.beginPath();
    ctx.moveTo(effect.x1 - nx * 4, effect.y1 - ny * 4);
    ctx.lineTo(effect.x2 - nx * 4, effect.y2 - ny * 4);
    ctx.stroke();
    ctx.setLineDash([]);

    if (crackReady) {
      ctx.strokeStyle = `rgba(255, 255, 255, ${0.72 * t})`;
      ctx.lineWidth = 3;
      for (const branch of effect.branches || []) {
        const bx = effect.x1 + dx * branch.t;
        const by = effect.y1 + dy * branch.t;
        ctx.beginPath();
        ctx.moveTo(bx, by);
        ctx.lineTo(bx + nx * branch.offset, by + ny * branch.offset);
        ctx.stroke();
      }
    }

    ctx.restore();
  }
}

(function () {
  const PRACTICE_SETTINGS_STORAGE_KEY = "jujutsuBrawlPracticeSettingsV1";

  function isPracticeActive() {
    return (
      gameMode === "practice" ||
      pacifistBot === true ||
      !practiceSettingsButton?.classList.contains("hidden")
    );
  }

  function getBarContainer(el) {
    return el?.closest?.(".ce-frame, .ultimate-frame, .extra-cooldowns") || el;
  }

  function setHudVisible(el, visible) {
    const container = getBarContainer(el);
    if (!container) return;
    container.classList.toggle("hidden", !visible);
    container.style.display = visible ? "" : "none";
  }

  function applyDummyHud() {
    const hideDummyHud = isPracticeActive();

    // Hide dummy resource bars, keep dummy HP visible.
    setHudVisible(enemyCeEl, !hideDummyHud);
    setHudVisible(enemyUltimateEl, !hideDummyHud);
    setHudVisible(enemyExtraCooldownsEl, !hideDummyHud);

    if (enemyStarsEl) {
      enemyStarsEl.classList.toggle("hidden", hideDummyHud);
      enemyStarsEl.style.display = hideDummyHud ? "none" : "";
    }

    movePracticeSettingsButton();
  }

  function loadPracticeSettings() {
    if (typeof practiceSettings === "undefined" || !practiceSettings) return;

    let loaded = false;

    try {
      const saved = JSON.parse(localStorage.getItem(PRACTICE_SETTINGS_STORAGE_KEY) || "null");
      if (saved && typeof saved === "object") {
        Object.keys(practiceSettings).forEach((key) => {
          if (typeof saved[key] === "boolean") {
            practiceSettings[key] = saved[key];
          }
        });
        loaded = true;
      }
    } catch (err) {}

    // First-time default: stationary dummy OFF.
    if (!loaded) {
      practiceSettings.stationaryDummy = false;
    }
  }

  function savePracticeSettings() {
    if (typeof practiceSettings === "undefined" || !practiceSettings) return;

    try {
      localStorage.setItem(PRACTICE_SETTINGS_STORAGE_KEY, JSON.stringify(practiceSettings));
    } catch (err) {}
  }

  function refreshPracticeButtons() {
    if (typeof updatePracticeSettingsButtons === "function") {
      updatePracticeSettingsButtons();
    }

    if (typeof updatePracticeSettingsUi === "function") {
      updatePracticeSettingsUi();
    }

    // Backup UI sync if your game uses data-practice-setting buttons.
    document.querySelectorAll(".practice-setting-button").forEach((button) => {
      const key = button.dataset.practiceSetting || button.dataset.setting;
      const value = button.dataset.value;

      if (!key || !(key in practiceSettings)) return;

      const pressed =
        (value === "on" && practiceSettings[key]) ||
        (value === "off" && !practiceSettings[key]);

      button.setAttribute("aria-pressed", pressed ? "true" : "false");
      button.classList.toggle("active", pressed);
    });
  }

  function installPracticeButtonStyle() {
    if (document.getElementById("practice-dummy-button-style")) return;

    const style = document.createElement("style");
    style.id = "practice-dummy-button-style";
    style.textContent = `
      #practiceSettingsButton.practice-under-dummy-hp {
        position: static !important;
        display: block !important;
        width: 100% !important;
        margin: 7px 0 6px 0 !important;
        padding: 6px 10px !important;
        border-radius: 10px !important;
        font-size: 0.82rem !important;
        font-weight: 900 !important;
        text-align: center !important;
        transform: none !important;
        z-index: auto !important;
      }
    `;
    document.head.appendChild(style);
  }

  function movePracticeSettingsButton() {
    if (!practiceSettingsButton || !enemyHealthEl) return;

    const active = isPracticeActive();

    practiceSettingsButton.classList.toggle("practice-under-dummy-hp", active);

    if (!active) return;

    // Put the button directly under the dummy HP bar.
    if (enemyHealthEl.nextElementSibling !== practiceSettingsButton) {
      enemyHealthEl.insertAdjacentElement("afterend", practiceSettingsButton);
    }
  }

  function setupPracticeSettingSaving() {
    document.addEventListener(
      "click",
      (event) => {
        const button = event.target.closest(".practice-setting-button");
        if (!button) return;

        const key = button.dataset.practiceSetting || button.dataset.setting;
        const value = button.dataset.value;

        if (!key || typeof practiceSettings === "undefined" || !(key in practiceSettings)) {
          return;
        }

        // Run after the game's normal click code, then force the intended on/off value.
        setTimeout(() => {
          if (value === "on") practiceSettings[key] = true;
          if (value === "off") practiceSettings[key] = false;

          savePracticeSettings();
          refreshPracticeButtons();
          applyDummyHud();
        }, 0);
      },
      true
    );
  }

  function patchUpdateHud() {
    if (typeof updateHud !== "function" || updateHud.practiceDummyPatchApplied) return;

    const oldUpdateHud = updateHud;

    updateHud = function patchedUpdateHud() {
      oldUpdateHud();
      applyDummyHud();
    };

    updateHud.practiceDummyPatchApplied = true;
  }

  function startPatch() {
    loadPracticeSettings();
    installPracticeButtonStyle();
    setupPracticeSettingSaving();
    refreshPracticeButtons();
    patchUpdateHud();
    applyDummyHud();

    setInterval(() => {
      applyDummyHud();
      refreshPracticeButtons();
    }, 300);
  }

  if (document.readyState === "loading") {
    window.addEventListener("DOMContentLoaded", startPatch);
  } else {
    startPatch();
  }
})();
// CLEAN PAUSE BUTTON FIX
(function () {
  const pauseBtn = document.getElementById("pauseButton");
  const resumeBtn = document.getElementById("resumeButton");
  const pauseScreenEl = document.getElementById("pauseScreen");

  function openPause() {
    if (typeof paused !== "undefined") paused = true;
    if (pauseScreenEl) pauseScreenEl.classList.remove("hidden");
  }

  function closePause() {
    if (typeof paused !== "undefined") paused = false;
    if (pauseScreenEl) pauseScreenEl.classList.add("hidden");
  }

  if (pauseBtn) {
    pauseBtn.onclick = function (event) {
      event.preventDefault();
      event.stopPropagation();
      openPause();
    };
  }

  if (resumeBtn) {
    resumeBtn.onclick = function (event) {
      event.preventDefault();
      event.stopPropagation();
      closePause();
    };
  }

  document.addEventListener("keydown", function (event) {
    if (event.code !== "Escape") return;
    if (!pauseScreenEl) return;

    const isOpen = !pauseScreenEl.classList.contains("hidden");
    if (isOpen) closePause();
    else openPause();
  });
})();

// ==========================================================================
// MOBILE_PATCH: touch controls. Detects touch devices, swaps in an on-screen
// gamepad, and (if detection is uncertain) asks the player PC vs Mobile. All
// buttons drive the exact same input paths as the keyboard/mouse, so every
// character works identically on a phone.
// ==========================================================================
(function setupMobileControls() {
  const STORE_KEY = "brawlControlMode"; // "auto" | "pc" | "mobile"
  let controlMode = localStorage.getItem(STORE_KEY) || "auto";

  function hasTouch() {
    return ("ontouchstart" in window) || (navigator.maxTouchPoints || 0) > 0;
  }
  function looksMobile() {
    const ua = /Android|iPhone|iPad|iPod|Mobile|Silk|Kindle|Opera Mini|IEMobile/i.test(navigator.userAgent || "");
    const smallish = Math.min(window.innerWidth, window.innerHeight) <= 820;
    return hasTouch() && (ua || smallish);
  }
  function mobileActive() {
    if (controlMode === "mobile") return true;
    if (controlMode === "pc") return false;
    return looksMobile();
  }

  // ---- input helpers (reuse the real keyboard/mouse paths) ----------------
  function synthKey(type, key, code) {
    try {
      window.dispatchEvent(new KeyboardEvent(type, { key, code, bubbles: true }));
    } catch (e) {
      const ev = document.createEvent("Event");
      ev.initEvent(type, true, true);
      ev.key = key; ev.code = code;
      window.dispatchEvent(ev);
    }
  }
  function mobileFighter() {
    return (typeof gameMode !== "undefined" && gameMode === "online" && onlineRole === "p2") ? enemy : player;
  }
  function aimTowardOpponent() {
    const f = mobileFighter();
    if (!f) return mouseAimWorld;
    const opp = f === player ? enemy : player;
    if (opp && !opp.ko) { const c = getFighterCenter(opp); return { x: c.x, y: c.y }; }
    const c = getFighterCenter(f);
    return { x: c.x + (f.dir || 1) * 220, y: c.y };
  }
  function inPlay() {
    return !homeOpen && !paused && gameState === "playing";
  }
  function touchTechnique(slot, down) {
    if (!inPlay()) return;
    const aim = aimTowardOpponent();
    mouseAimWorld = aim;
    const online = gameMode === "online" && onlineRole === "p2";
    const target = online ? enemy : player;
    if (down) {
      useTechniqueInput(target, slot, aim);
      if (online) sendOnlineInput(slot === 1 ? "ct1" : "ct2", aim);
    } else {
      releaseTechniqueInput(target, slot, aim);
      if (online) sendOnlineInput(slot === 1 ? "ct1-release" : "ct2-release", aim);
    }
  }

  // MOBILE_ABILITIES_PATCH: per-character labels + extra tap-abilities so
  // every kit is fully playable on touch. Labels ride the `sp1`, `sp2`, `ult`
  // buttons for the mouse specials + ultimate, and up to 3 utility buttons
  // (`u1`, `u2`, `u3`) get bound to that character's other named abilities.
  // Abbreviations keep everything ≤ 8 chars so the button caps stay legible.
  function abbr(s) {
    if (!s) return "";
    const map = {
      "DISMANTLE": "DSMTL", "PSI FLURRY": "FLURRY", "SOCCER STRIKE": "SOCCER",
      "SPIRIT BLAST": "SPIRIT", "GORILLA ARMS": "GORILLA",
      "PROJECTILE LAUNCHER": "LNCHR", "GROUND BREAK": "GRND BRK",
      "WEB BARRAGE": "WEB BR.", "WEB SHOT": "WEB", "WEB SWING": "SWING",
      "SPIDER RUSH": "RUSH", "BERSERKER": "BRSRKR", "DIABLE JAMBE": "DIABLE",
      "MUTTON SHOT": "MUTTON", "SKY WALK": "SKY", "SPATIAL RUP.": "SPATIAL",
      "SPATIAL RUPTURE": "SPATIAL", "SANDEVISTAN": "SANDE",
      "INVESTIGATE": "INVEST", "COLD BEER": "BEER",
      "SHARK SUIT": "SHARK", "TRANSFORM": "SWAP", "UPSIDE-DOWN SLIP": "SLIP"
    };
    if (map[s]) return map[s];
    return s.length <= 8 ? s : s.slice(0, 7).trim() + ".";
  }
  // Extra utility abilities: {label, act} where act is a fn called on tap.
  // Kept small: each character exposes at most 3 utility taps.
  function extraAbilitiesFor(tech) {
    const f = mobileFighter();
    const util = [];
    if (tech === "shrine" || tech === "limitless" || tech === "deathnote") return util; // covered by R/F/T defaults
    if (tech === "brawler") util.push({ label: "FLIGHT", act: () => startFlyingDash(f) });
    if (tech === "blackleg") {
      util.push({ label: "SKY", act: () => startSkyWalk(f) });
      util.push({ label: "COOK", act: () => startSanjiCook(f) });
      util.push({ label: "SWAP", act: () => switchSanjiUtensil(f) });
    }
    if (tech === "hivemind") util.push({ label: "SLIP", act: () => startUpsideDownSlip(f) });
    if (tech === "zealot") util.push({ label: "WHIRL", act: () => startZealotWhirlwind(f) });
    if (tech === "spider") { util.push({ label: "SWING", act: () => startWebSwing(f) }); util.push({ label: "RUSH", act: () => startSpiderRush(f) }); }
    if (tech === "beast") {
      util.push({ label: "CRAZY", act: () => startBeastCrazy(f) });
      util.push({ label: "SPATIAL", act: () => startBeastSpatial(f) });
      util.push({ label: "WHIRL", act: () => startBeastWhirl(f) });
    }
    if (tech === "jiji") util.push({ label: "SWAP", act: () => startJijiTransform(f) });
    if (tech === "david") util.push({ label: "SANDE", act: () => startSandevistan(f) });
    if (tech === "akira") {
      util.push({ label: "WORK", act: () => startOvertime(f) });
      util.push({ label: "BEER", act: () => drinkBeer(f) });
      util.push({ label: "SHARK", act: () => startSharkSuit(f) });
    }
    return util;
  }

  function ultLabelFor(tech) {
    const map = {
      limitless: "HOLLOW", shrine: "SLASH", deathnote: "NOTE",
      brawler: "STOMP", blackleg: "IFRIT", hivemind: "UPSIDE",
      zealot: "WARP", spider: "FRIEND", beast: "BEAST",
      jiji: "ACCEPT", david: "SKELE", akira: "BUCKET"
    };
    return map[tech] || "ULT";
  }

  function currentTech() {
    const f = mobileFighter();
    return f?.technique || selectedTechnique || "limitless";
  }

  // Refresh labels on the ability buttons based on the current character.
  function relabelAbilityButtons() {
    if (!root) return;
    const tech = currentTech();
    const f = mobileFighter();
    // ①  → LC / mouse slot 1 label
    const sp1Name = f ? getTechniqueDisplayName(getTechniqueMoveKey(f, 1)) : "①";
    const sp2Name = f ? getTechniqueDisplayName(getTechniqueMoveKey(f, 2)) : "②";
    root._sp1.textContent = abbr(sp1Name);
    root._sp2.textContent = abbr(sp2Name);
    root._ult.textContent = ultLabelFor(tech);
    // Utility buttons u1/u2/u3
    const extras = extraAbilitiesFor(tech);
    [root._u1, root._u2, root._u3].forEach((el, i) => {
      if (!el) return;
      const spec = extras[i];
      el.style.display = spec ? "flex" : "none";
      if (spec) { el.textContent = spec.label; el._act = spec.act; }
    });
    layout();
  }

  // Button spec: [id, label, {key,code} | special, mode] mode: "hold"|"tap"
  const KEYMAP = {
    left:  { key: "a", code: "KeyA", hold: true },
    right: { key: "d", code: "KeyD", hold: true },
    jump:  { key: " ", code: "Space", hold: true },
    block: { key: "q", code: "KeyQ", hold: true },
    aimS:  { key: "s", code: "KeyS", hold: true },
    ult:   { key: "c", code: "KeyC", hold: true },
    light: { key: "w", code: "KeyW", hold: false },
    heavy: { key: "e", code: "KeyE", hold: false },
    dodge: { key: "Shift", code: "ShiftLeft", hold: false },
    throw: { key: "Tab", code: "Tab", hold: false },
    rkey:  { key: "r", code: "KeyR", hold: false },
    fkey:  { key: "f", code: "KeyF", hold: false },
    tkey:  { key: "t", code: "KeyT", hold: false }
  };

  function pressKeyBtn(name) {
    const m = KEYMAP[name];
    if (!m) return;
    if (name === "aimS" || name === "ult") mouseAimWorld = aimTowardOpponent();
    synthKey("keydown", m.key, m.code);
  }
  function releaseKeyBtn(name) {
    const m = KEYMAP[name];
    if (!m) return;
    synthKey("keyup", m.key, m.code);
  }

  // ---- DOM / CSS ----------------------------------------------------------
  function injectStyle() {
    if (document.getElementById("mobileControlsStyle")) return;
    const s = document.createElement("style");
    s.id = "mobileControlsStyle";
    s.textContent = `
      #mobileControls { position: fixed; inset: 0; z-index: 60; pointer-events: none;
        display: none; touch-action: none; -webkit-user-select: none; user-select: none; }
      body.mobile-controls-on #mobileControls.playing { display: block; }
      .mc-btn { position: absolute; pointer-events: auto; touch-action: none;
        display: flex; align-items: center; justify-content: center; text-align: center;
        border-radius: 999px; border: 2px solid rgba(255,255,255,0.5);
        background: radial-gradient(circle at 35% 30%, rgba(255,255,255,0.22), rgba(15,23,42,0.62));
        color: #f4f7fb; font: 800 13px/1.05 system-ui, sans-serif; letter-spacing: .3px;
        box-shadow: 0 3px 10px rgba(0,0,0,0.35); -webkit-tap-highlight-color: transparent;
        text-shadow: 0 1px 2px rgba(0,0,0,0.6); backdrop-filter: blur(1px); }
      .mc-btn:active, .mc-btn.mc-active { background: radial-gradient(circle at 35% 30%, rgba(255,255,255,0.42), rgba(56,120,220,0.7));
        transform: scale(0.94); border-color: #cfe4ff; }
      .mc-btn.mc-lg { width: 74px; height: 74px; font-size: 22px; }
      .mc-btn.mc-md { width: 62px; height: 62px; font-size: 15px; }
      .mc-btn.mc-sm { width: 48px; height: 48px; font-size: 12px; }
      .mc-btn.mc-sp1 { border-color: #93c5fd; } .mc-btn.mc-sp2 { border-color: #fca5a5; }
      .mc-btn.mc-ult { border-color: #fde68a; background: radial-gradient(circle at 35% 30%, rgba(255,240,180,0.3), rgba(120,80,10,0.6)); }
      #mcModeToggle { position: fixed; top: 8px; right: 8px; z-index: 62; pointer-events: auto;
        width: 40px; height: 40px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.4);
        background: rgba(15,23,42,0.7); color:#fff; font-size:18px; display:flex; align-items:center;
        justify-content:center; cursor:pointer; -webkit-tap-highlight-color: transparent; }
      #mcPrompt { position: fixed; inset: 0; z-index: 80; display: none;
        align-items: center; justify-content: center; background: rgba(2,6,20,0.8); }
      #mcPrompt.show { display: flex; }
      #mcPrompt .mc-card { background: #0f172a; border: 2px solid #38507a; border-radius: 16px;
        padding: 24px 22px; text-align: center; max-width: 88vw; }
      #mcPrompt h2 { color: #f4f7fb; font: 800 20px system-ui; margin: 0 0 6px; }
      #mcPrompt p { color: #9fb2cc; font: 500 13px system-ui; margin: 0 0 18px; }
      #mcPrompt .mc-row { display: flex; gap: 14px; justify-content: center; }
      #mcPrompt button { flex: 1; min-width: 110px; padding: 16px 10px; border-radius: 12px;
        border: 2px solid #4b6ea8; background: #17233b; color: #fff; font: 800 15px system-ui; cursor: pointer; }
      #mcPrompt button:active { background: #24406e; }
      @media (max-width: 820px), (pointer: coarse) {
        body.mobile-controls-on .shell { touch-action: none; }
      }
      #mcRotate { position: fixed; inset: 0; z-index: 90; display: none;
        flex-direction: column; align-items: center; justify-content: center;
        gap: 14px; text-align: center; padding: 28px;
        background: radial-gradient(circle at 50% 40%, #16233d, #070b16 75%);
        color: #eaf1ff; font: 700 17px system-ui, sans-serif; }
      body.mobile-controls-on #mcRotate.show { display: flex; }
      #mcRotate .mc-rot-icon { font-size: 66px; line-height: 1;
        animation: mcRotSpin 1.8s ease-in-out infinite; }
      #mcRotate small { font-weight: 500; font-size: 13px; color: #9fb2cc; max-width: 280px; }
      @keyframes mcRotSpin { 0%, 100% { transform: rotate(0deg); } 45%, 55% { transform: rotate(-90deg); } }
    `;
    document.head.appendChild(s);
  }

  let root = null;
  function bindHold(el, onDown, onUp) {
    let active = false;
    const down = (e) => { e.preventDefault(); if (active) return; active = true; el.classList.add("mc-active"); onDown(); };
    const up = (e) => { if (e) e.preventDefault(); if (!active) return; active = false; el.classList.remove("mc-active"); onUp(); };
    el.addEventListener("touchstart", down, { passive: false });
    el.addEventListener("touchend", up, { passive: false });
    el.addEventListener("touchcancel", up, { passive: false });
    el.addEventListener("mousedown", down);
    el.addEventListener("mouseup", up);
    el.addEventListener("mouseleave", up);
  }
  function bindTap(el, onTap) {
    const fire = (e) => { e.preventDefault(); el.classList.add("mc-active"); onTap(); setTimeout(() => el.classList.remove("mc-active"), 90); };
    el.addEventListener("touchstart", fire, { passive: false });
    el.addEventListener("mousedown", fire);
  }

  function makeBtn(cls, label) {
    const b = document.createElement("div");
    b.className = "mc-btn " + cls;
    b.textContent = label;
    root.appendChild(b);
    return b;
  }

  function layout() {
    if (!root) return;
    const W = window.innerWidth, H = window.innerHeight;
    const BM = 18; // bottom margin to clear phone chrome / safe area
    const B = H - BM;
    const pos = (el, x, y) => { el.style.left = Math.round(x) + "px"; el.style.top = Math.round(y) + "px"; };

    // ---- left thumb: movement (bottom) + block/dodge (above) ----
    pos(root._left,  16, B - 78);    // ◀ lg 74
    pos(root._right, 98, B - 78);    // ▶ lg 74
    pos(root._block, 16, B - 136);   // BLK sm 48
    pos(root._dodge, 74, B - 136);   // DDG sm 48

    // ---- right thumb: attacks, specials, JUMP, ult (spread so none overlap) ----
    pos(root._jump,  W - 90,  B - 78);   // JUMP lg 74 (bottom-right corner)
    pos(root._heavy, W - 166, B - 50);   // HEAVY md 62
    pos(root._sp1,   W - 96,  B - 164);  // ① lg 74
    pos(root._sp2,   W - 166, B - 134);  // ② md 62
    pos(root._light, W - 244, B - 78);   // LIGHT md 62 (swapped with JUMP)
    pos(root._ult,   W - 244, B - 160);  // ULT md 62
    pos(root._aimS,  W - 312, B - 118);  // S sm 48

    // ---- utility strip: a centred bottom row, clear of the HUD + thumbs ----
    const uw = 48, ug = 8;
    const strip = [root._throw, root._rkey, root._fkey, root._tkey, root._u1, root._u2, root._u3].filter((el) => el && el.style.display !== "none");
    const total = strip.length * uw + (strip.length - 1) * ug;
    let ux = (W - total) / 2;
    strip.forEach((el) => { pos(el, ux, B - 54); ux += uw + ug; });
  }

  function build() {
    injectStyle();
    if (root) return;
    root = document.createElement("div");
    root.id = "mobileControls";
    document.body.appendChild(root);

    const holdKey = (el, name) => bindHold(el, () => pressKeyBtn(name), () => releaseKeyBtn(name));
    const tapKey = (el, name) => bindTap(el, () => { pressKeyBtn(name); setTimeout(() => releaseKeyBtn(name), 60); });

    root._left = makeBtn("mc-lg", "◀");   holdKey(root._left, "left");
    root._right = makeBtn("mc-lg", "▶");  holdKey(root._right, "right");
    root._jump = makeBtn("mc-lg", "JUMP"); holdKey(root._jump, "jump");
    root._block = makeBtn("mc-sm", "BLK"); holdKey(root._block, "block");
    root._dodge = makeBtn("mc-sm", "DDG"); tapKey(root._dodge, "dodge");

    root._sp1 = makeBtn("mc-lg mc-sp1", "①"); bindHold(root._sp1, () => touchTechnique(1, true), () => touchTechnique(1, false));
    root._sp2 = makeBtn("mc-md mc-sp2", "②"); bindHold(root._sp2, () => touchTechnique(2, true), () => touchTechnique(2, false));
    root._light = makeBtn("mc-md", "LIGHT"); tapKey(root._light, "light");
    root._heavy = makeBtn("mc-md", "HEAVY"); tapKey(root._heavy, "heavy");
    root._ult = makeBtn("mc-md mc-ult", "ULT"); bindHold(root._ult, () => pressKeyBtn("ult"), () => releaseKeyBtn("ult"));
    root._aimS = makeBtn("mc-sm", "S");  bindHold(root._aimS, () => pressKeyBtn("aimS"), () => releaseKeyBtn("aimS"));

    root._throw = makeBtn("mc-sm", "THR"); tapKey(root._throw, "throw");
    root._rkey = makeBtn("mc-sm", "RCT"); tapKey(root._rkey, "rkey");
    root._fkey = makeBtn("mc-sm", "INF"); tapKey(root._fkey, "fkey");
    root._tkey = makeBtn("mc-sm", "BLUE"); tapKey(root._tkey, "tkey");
    // MOBILE_ABILITIES_PATCH: three utility slots for the character's extra
    // named abilities (relabelled dynamically in relabelAbilityButtons).
    root._u1 = makeBtn("mc-sm", ""); bindTap(root._u1, () => { if (root._u1._act) root._u1._act(); });
    root._u2 = makeBtn("mc-sm", ""); bindTap(root._u2, () => { if (root._u2._act) root._u2._act(); });
    root._u3 = makeBtn("mc-sm", ""); bindTap(root._u3, () => { if (root._u3._act) root._u3._act(); });

    relabelAbilityButtons();
    layout();
    window.addEventListener("resize", layout);
    window.addEventListener("orientationchange", () => setTimeout(layout, 300));
    // relabel when the character or form changes (poll each second - cheap)
    setInterval(() => {
      const key = (currentTech() || "") + "|" + (mobileFighter()?.jijiForm || "");
      if (root._lastRelabelKey !== key) { root._lastRelabelKey = key; relabelAbilityButtons(); }
    }, 500);
  }

  // ---- mode toggle + first-run prompt -------------------------------------
  function applyMode() {
    const on = mobileActive();
    document.body.classList.toggle("mobile-controls-on", on);
    if (on) build();
    const tgl = document.getElementById("mcModeToggle");
    if (tgl) tgl.textContent = on ? "📱" : "🖥️";
  }
  function setMode(mode) {
    controlMode = mode;
    localStorage.setItem(STORE_KEY, mode);
    applyMode();
    if (mobileActive()) { tryLockLandscape(); updateRotate(); }
  }
  function buildToggle() {
    if (document.getElementById("mcModeToggle")) return;
    if (!hasTouch() && !looksMobile()) return; // desktop without touch: no toggle needed
    const b = document.createElement("button");
    b.id = "mcModeToggle";
    b.title = "Toggle PC / Mobile controls";
    b.addEventListener("click", () => setMode(mobileActive() ? "pc" : "mobile"));
    document.body.appendChild(b);
  }
  function maybePrompt() {
    if (localStorage.getItem(STORE_KEY)) return;       // already chosen
    if (!hasTouch()) return;                            // clearly desktop
    const wrap = document.createElement("div");
    wrap.id = "mcPrompt";
    wrap.innerHTML = `
      <div class="mc-card">
        <h2>How are you playing?</h2>
        <p>Pick your controls — you can switch anytime with the button in the corner.</p>
        <div class="mc-row">
          <button data-mode="pc">🖥️ PC<br><span style="font-weight:500;font-size:11px;opacity:.8">keyboard &amp; mouse</span></button>
          <button data-mode="mobile">📱 Mobile<br><span style="font-weight:500;font-size:11px;opacity:.8">touch controls</span></button>
        </div>
      </div>`;
    document.body.appendChild(wrap);
    requestAnimationFrame(() => wrap.classList.add("show"));
    wrap.querySelectorAll("button").forEach((btn) => btn.addEventListener("click", () => {
      setMode(btn.getAttribute("data-mode"));
      wrap.remove();
    }));
  }

  // ---- landscape enforcement ----------------------------------------------
  function isPortrait() {
    return window.innerHeight > window.innerWidth;
  }
  function tryLockLandscape() {
    try {
      const so = screen.orientation;
      if (so && so.lock) so.lock("landscape").catch(() => {});
    } catch (e) { /* not supported - the rotate overlay covers it */ }
  }
  let rotateEl = null;
  function buildRotate() {
    if (rotateEl) return;
    rotateEl = document.createElement("div");
    rotateEl.id = "mcRotate";
    rotateEl.innerHTML = `
      <div class="mc-rot-icon">🔄</div>
      <div>Rotate your device</div>
      <small>Universal Brawl plays best in landscape. Turn your phone sideways to keep going.</small>`;
    document.body.appendChild(rotateEl);
    // tapping it is a user gesture - a good moment to (re)try the lock.
    rotateEl.addEventListener("touchstart", tryLockLandscape, { passive: true });
  }
  function updateRotate() {
    if (!rotateEl) return;
    const need = mobileActive() && isPortrait();
    rotateEl.classList.toggle("show", need);
  }

  // Show the pad only during actual gameplay (and never over the rotate gate).
  function visibilityTick() {
    updateRotate();
    if (root) root.classList.toggle("playing", mobileActive() && !isPortrait() && typeof gameState !== "undefined" && gameState === "playing" && !homeOpen && !paused);
  }

  function init() {
    injectStyle();
    buildToggle();
    buildRotate();
    applyMode();
    maybePrompt();
    updateRotate();
    window.addEventListener("resize", updateRotate);
    window.addEventListener("orientationchange", () => setTimeout(() => { updateRotate(); layout(); }, 200));
    // Best-effort: lock to landscape on the first touch gesture.
    window.addEventListener("touchstart", function once() {
      if (mobileActive()) tryLockLandscape();
      window.removeEventListener("touchstart", once);
    }, { passive: true, once: true });
    setInterval(visibilityTick, 150);
  }
  if (document.readyState === "loading") window.addEventListener("DOMContentLoaded", init);
  else init();
})();

// ==========================================================================
// SKINS_PATCH: the Skins gallery. A button on the home + character-select
// screens opens a modal where you pick a cosmetic outfit per character. The
// choice is saved and applied to that character in every fight.
// ==========================================================================
(function setupSkinsGallery() {
  function injectStyle() {
    if (document.getElementById("skinsGalleryStyle")) return;
    const s = document.createElement("style");
    s.id = "skinsGalleryStyle";
    s.textContent = `
      #skinsScreen { position: fixed; inset: 0; z-index: 40; display: none;
        align-items: center; justify-content: center; padding: 16px;
        background: rgba(8, 11, 18, 0.9); }
      #skinsScreen.show { display: flex; }
      #skinsScreen .skins-panel { width: min(860px, calc(100vw - 20px));
        max-height: calc(100dvh - 24px); overflow-y: auto; background: #111725;
        border: 3px solid #edf2ff; border-radius: 10px; padding: 18px 20px 22px;
        box-shadow: 0 22px 70px rgba(0,0,0,0.55); }
      #skinsScreen .skins-head { display: flex; align-items: center; justify-content: space-between; margin-bottom: 14px; }
      #skinsScreen h2 { margin: 0; color: #ffe071; text-transform: uppercase; font-size: 24px; }
      #skinsScreen .skins-close { min-width: 44px; background: #c4b5fd; box-shadow: 0 4px 0 #5b21b6; }
      #skinsScreen .skin-char { margin-bottom: 16px; }
      #skinsScreen .skin-char > strong { display: block; color: #cfe0ff; text-transform: uppercase;
        font-size: 14px; letter-spacing: .5px; margin-bottom: 6px; }
      #skinsScreen .skin-row { display: grid; grid-template-columns: repeat(auto-fill, minmax(112px, 1fr)); gap: 10px; }
      #skinsScreen .skin-card { cursor: pointer; border: 3px solid rgba(120,140,180,0.5);
        border-radius: 8px; background: #dbeafe; padding: 6px; display: flex; flex-direction: column;
        align-items: center; gap: 4px; -webkit-tap-highlight-color: transparent; }
      #skinsScreen .skin-card.selected { border-color: #ffe071; box-shadow: 0 0 0 2px #ffe071, 0 4px 0 #b8860b; }
      #skinsScreen .skin-card canvas { width: 100%; max-width: 100px; height: 84px; border-radius: 6px;
        border: 2px solid rgba(2,6,23,0.72); background: linear-gradient(180deg,#172033,#090d17); }
      #skinsScreen .skin-card span { font: 800 12px system-ui; text-transform: uppercase; color: #0b1220; }
      #openSkinsHome, #openSkinsSelect { background: #a7f3d0; box-shadow: 0 4px 0 #047857; }
    `;
    document.head.appendChild(s);
  }

  let screen = null;
  function build() {
    injectStyle();
    if (screen) return;
    screen = document.createElement("div");
    screen.id = "skinsScreen";
    const panel = document.createElement("div");
    panel.className = "skins-panel";
    const head = document.createElement("div");
    head.className = "skins-head";
    const h2 = document.createElement("h2");
    h2.textContent = "Skins";
    const close = document.createElement("button");
    close.className = "skins-close";
    close.type = "button";
    close.textContent = "Done";
    close.addEventListener("click", closeGallery);
    head.appendChild(h2); head.appendChild(close);
    panel.appendChild(head);

    const nameOf = (t) => getTechniqueCharacterName(t);
    Object.keys(CHARACTER_SKINS).forEach((tech) => {
      const block = document.createElement("div");
      block.className = "skin-char";
      const title = document.createElement("strong");
      title.textContent = nameOf(tech);
      block.appendChild(title);
      const row = document.createElement("div");
      row.className = "skin-row";
      CHARACTER_SKINS[tech].forEach((sk) => {
        const card = document.createElement("div");
        card.className = "skin-card";
        card.dataset.tech = tech;
        card.dataset.skin = sk.id;
        const cv = document.createElement("canvas");
        cv.width = 180; cv.height = 160;
        const label = document.createElement("span");
        label.textContent = sk.name;
        card.appendChild(cv); card.appendChild(label);
        card.addEventListener("click", () => {
          setSelectedSkin(tech, sk.id);
          refreshSelected();
          if (typeof renderTechniquePreviews === "function") renderTechniquePreviews();
        });
        row.appendChild(card);
      });
      block.appendChild(row);
      panel.appendChild(block);
    });
    screen.appendChild(panel);
    document.body.appendChild(screen);
    screen.addEventListener("click", (e) => { if (e.target === screen) closeGallery(); });
  }

  function refreshSelected() {
    if (!screen) return;
    screen.querySelectorAll(".skin-card").forEach((card) => {
      card.classList.toggle("selected", getSelectedSkin(card.dataset.tech) === card.dataset.skin);
    });
  }
  function renderGalleryPreviews() {
    if (!screen) return;
    screen.querySelectorAll(".skin-card").forEach((card) => {
      const cv = card.querySelector("canvas");
      if (cv) drawTechniquePreview(cv, card.dataset.tech, card.dataset.skin);
    });
  }
  function openGallery() {
    build();
    screen.classList.add("show");
    refreshSelected();
    // render after layout so the canvases have size
    requestAnimationFrame(renderGalleryPreviews);
    setTimeout(renderGalleryPreviews, 60);
  }
  function closeGallery() {
    if (screen) screen.classList.remove("show");
  }

  function addButtons() {
    // Home screen: put a Skins button in the start actions row.
    const startActions = document.querySelector(".start-actions");
    if (startActions && !document.getElementById("openSkinsHome")) {
      const b = document.createElement("button");
      b.id = "openSkinsHome";
      b.type = "button";
      b.textContent = "Skins";
      b.addEventListener("click", openGallery);
      startActions.appendChild(b);
    }
    // Character select: put a Skins button under the heading.
    const panel = document.querySelector("#techniqueScreen .technique-panel");
    if (panel && !document.getElementById("openSkinsSelect")) {
      const b = document.createElement("button");
      b.id = "openSkinsSelect";
      b.type = "button";
      b.textContent = "Skins";
      b.style.cssText = "justify-self:center;margin-bottom:6px;";
      b.addEventListener("click", openGallery);
      const h2 = panel.querySelector("h2");
      if (h2 && h2.nextSibling) panel.insertBefore(b, h2.nextSibling);
      else panel.appendChild(b);
    }
  }

  function init() {
    injectStyle();
    addButtons();
    // re-add in case the character-select panel is built later
    setTimeout(addButtons, 400);
    setTimeout(addButtons, 1200);
  }
  if (document.readyState === "loading") window.addEventListener("DOMContentLoaded", init);
  else init();
})();

// STAGE_SELECT_PATCH: a stage strip + hazards toggle injected into the
// character-select panel. Picking a stage sets currentStageId; picking a
// character then starts the match on it. Online: the pick rides along on the
// technique message and the host (p1) is authoritative.
(function setupStageSelect() {
  const SWATCH = {
    city: "#7e5060", zen: "#e7a976", protoss: "#10323a", village: "#3f3b63",
    rooftops: "#864f5e", sunny: "#5db4e0", upsideDown: "#161022", space: "#0a0820"
  };
  function injectStyle() {
    if (document.getElementById("stageSelectStyle")) return;
    const s = document.createElement("style");
    s.id = "stageSelectStyle";
    s.textContent = `
      .stage-strip { display: flex; flex-wrap: wrap; gap: 6px; justify-content: center;
        margin: 2px auto 8px; max-width: 640px; }
      .stage-chip { display: flex; align-items: center; gap: 6px; padding: 4px 9px;
        border-radius: 999px; border: 2px solid rgba(255,255,255,0.16);
        background: rgba(15,20,30,0.7); color: #e7ecf3; font-size: 12px; font-weight: 700;
        cursor: pointer; transition: all .12s; }
      .stage-chip:hover { border-color: rgba(120,200,255,0.5); }
      .stage-chip.active { border-color: #45d3c0; box-shadow: 0 0 10px rgba(69,211,192,0.4);
        background: rgba(20,60,60,0.75); }
      .stage-chip .sw { width: 14px; height: 14px; border-radius: 4px; border: 1px solid rgba(0,0,0,0.5); }
      .stage-hazard-row { display: flex; align-items: center; justify-content: center; gap: 8px;
        margin: 0 auto 8px; font-size: 12px; font-weight: 700; color: #cdd6e2; }
      .stage-hazard-row label { display: flex; align-items: center; gap: 6px; cursor: pointer; }
      .stage-title { text-align: center; font-size: 12px; letter-spacing: .06em;
        text-transform: uppercase; color: #9fb2c8; margin: 4px 0 2px; }
    `;
    document.head.appendChild(s);
  }
  function refresh() {
    document.querySelectorAll(".stage-chip").forEach((c) => {
      c.classList.toggle("active", c.dataset.stage === currentStageId);
    });
    const cb = document.getElementById("stageHazardToggle");
    if (cb) cb.checked = stageHazardsEnabled;
  }
  function syncOnline() {
    if (gameMode === "online" && typeof sendOnlineTechniqueChoice === "function" && onlineSocket && onlineSocket.readyState === 1) {
      try { onlineSocket.send(JSON.stringify({ type: "stage", role: onlineRole, stage: currentStageId, hazards: stageHazardsEnabled })); } catch (e) {}
    }
  }
  function build() {
    const panel = document.querySelector("#techniqueScreen .technique-panel");
    if (!panel || document.getElementById("stageStrip")) return;
    const title = document.createElement("div");
    title.className = "stage-title";
    title.textContent = "Stage";
    const strip = document.createElement("div");
    strip.className = "stage-strip";
    strip.id = "stageStrip";
    STAGE_ORDER.forEach((id) => {
      const chip = document.createElement("button");
      chip.type = "button";
      chip.className = "stage-chip";
      chip.dataset.stage = id;
      chip.innerHTML = `<span class="sw" style="background:${SWATCH[id] || "#333"}"></span>${STAGES[id].name}`;
      chip.addEventListener("click", () => { currentStageId = id; refresh(); syncOnline(); });
      strip.appendChild(chip);
    });
    const hazardRow = document.createElement("div");
    hazardRow.className = "stage-hazard-row";
    hazardRow.innerHTML = `<label><input type="checkbox" id="stageHazardToggle"> Stage Hazards</label>`;
    // insert just above the character grid (after any Skins button / heading)
    const grid = panel.querySelector(".technique-actions");
    if (grid) {
      panel.insertBefore(title, grid);
      panel.insertBefore(strip, grid);
      panel.insertBefore(hazardRow, grid);
    } else {
      panel.appendChild(title); panel.appendChild(strip); panel.appendChild(hazardRow);
    }
    hazardRow.querySelector("#stageHazardToggle").addEventListener("change", (e) => {
      stageHazardsEnabled = e.target.checked; syncOnline();
    });
    refresh();
  }
  function init() {
    injectStyle();
    build();
    setTimeout(build, 400);
    setTimeout(build, 1200);
  }
  if (document.readyState === "loading") window.addEventListener("DOMContentLoaded", init);
  else init();
})();
